# Configure the AWS Provider
# Note: Route 53 query logging requires the CloudWatch Log Group to be in us-east-1
provider "aws" {
  region = "us-east-1"
}

# 1. Define the Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# 2. Define the CloudWatch Log Group
# The name must start with /aws/route53/ for some automated permission handling, 
# but we will use the specific name requested.
resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/example.com"
  retention_in_days = 30
}

# 3. Define the IAM Policy Document to allow Route 53 to post logs
data "aws_iam_policy_document" "route53_query_logging_policy_doc" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

# 4. Create the CloudWatch Log Resource Policy
resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53_query_logging_policy_doc.json
  policy_name     = "route53-query-logging-policy"
}

# 5. Configure the Route 53 Query Log
# This resource links the Hosted Zone to the Log Group.
resource "aws_route53_query_log" "example_query_log" {
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id

  # The policy must be in place before Route 53 can successfully verify the log group
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]
}

