response:
To configure a Route 53 Private Hosted Zone association, we need to follow these steps:

1.  **Define the Provider**: Set up the AWS provider.
2.  **Create VPCs**: Private Route 53 zones must be associated with at least one VPC. We will create two VPCs to demonstrate the association resource specifically.
3.  **Enable DNS Support**: Ensure the VPCs have `enable_dns_support` and `enable_dns_hostnames` set to `true`, which is a requirement for Private Hosted Zones.
4.  **Create the Private Zone**: Define the `aws_route53_zone` and associate it with the first VPC initially.
5.  **Create the Association**: Use the `aws_route53_zone_association` resource to link the second VPC to the private zone.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Primary VPC
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "primary-vpc"
  }
}

# 2. Create a Secondary VPC to associate with the zone later
resource "aws_vpc" "secondary" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "secondary-vpc"
  }
}

# 3. Create the Private Route 53 Zone
# A private zone must be associated with at least one VPC at creation time
resource "aws_route53_zone" "private" {
  name = "example.internal"

  vpc {
    vpc_id = aws_vpc.primary.id
  }

  comment = "Private zone for internal infrastructure"
}

# 4. Associate the Secondary VPC with the Private Zone
# This resource is used to add additional VPCs to an existing private zone
resource "aws_route53_zone_association" "secondary_association" {
  zone_id = aws_route53_zone.private.zone_id
  vpc_id  = aws_vpc.secondary.id
}
```

