response:
To configure a Route 53 record pointing to an Elastic Load Balancer (ELB), we need to define the AWS provider, create the ELB resource, establish the Route 53 hosted zone, and finally create an alias record that maps the domain name to the load balancer's DNS name and Hosted Zone ID.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create an Elastic Load Balancer (Classic)
resource "aws_elb" "main" {
  name               = "main-elb"
  availability_zones = ["us-east-1a", "us-east-1b"]

  listener {
    instance_port     = 80
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }

  health_check {
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 3
    target              = "HTTP:80/"
    interval            = 30
  }

  tags = {
    Name = "main-elb"
  }
}

# Create a Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# Create a Route 53 Record (Alias) pointing to the ELB
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com"
  type    = "A"

  alias {
    name                   = aws_elb.main.dns_name
    zone_id                = aws_elb.main.zone_id
    evaluate_target_health = true
  }
}
```

