# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Subnet Group named "main"
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Security Group for DB Access
resource "aws_security_group" "db_sg" {
  name        = "database-sg"
  description = "Allow DB traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Database Instances ---

# Internal RDS Instance
resource "aws_db_instance" "internal" {
  identifier           = "internal"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  db_name              = "internaldb"
  username             = "admin"
  password             = "Password123!" # In production, use Secrets Manager
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible  = false
  skip_final_snapshot  = true
}

# Public RDS Instance
resource "aws_db_instance" "public" {
  identifier           = "public"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  db_name              = "publicdb"
  username             = "admin"
  password             = "Password123!" # In production, use Secrets Manager
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible  = true
  skip_final_snapshot  = true
}

# --- Route 53 Split-Horizon DNS ---

# Public Hosted Zone
resource "aws_route53_zone" "public" {
  name = "example.com"
  comment = "public"
}

# Private Hosted Zone (associated with VPC)
resource "aws_route53_zone" "private" {
  name = "example.com"
  comment = "private"

  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# DNS Record for External Users (points to Public RDS)
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

# DNS Record for Internal Users (points to Internal RDS)
resource "aws_route53_record" "private_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
