}

# 4. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my_application"
  description = "Application shared by multiple environments"
}

# 5. First Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "env_one" {
  name                = "my-env-one"
