  bucket  = aws_s3_bucket.sampleapril26426.id
  key     = "examplebucket_object"
  content = "placeholder for application code" # In a real scenario, use 'source' for a zip file
}

# 4. IAM Role for EC2 instances in the Elastic Beanstalk environment
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary managed policies for Worker environments
