To create an AWS Elastic Beanstalk environment with the specified components, we need to set up the IAM infrastructure for the EC2 instances, create an S3 bucket and object to hold the application source code, and then define the Elastic Beanstalk application, its version, and the environment itself.

Here is the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard WebTier policy to the role
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# 2. IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 3. S3 Bucket for application source code
resource "aws_s3_bucket" "sampleapril26426" {
  bucket = "sampleapril26426"
}

# 4. S3 Object (Source Bundle)
resource "aws_s3_object" "examplebucket_object" {
  bucket  = aws_s3_bucket.sampleapril26426.id
  key     = "app-v1.zip"
  content = "dummy-source-code-content" # In production, use the 'source' attribute to upload a real zip
}

# 5. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "myapp"
  description = "Elastic Beanstalk Application created via Terraform"
}

# 6. Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.myapp.name
  bucket      = aws_s3_bucket.sampleapril26426.id
  key         = aws_s3_object.examplebucket_object.key
}

# 7. Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "tf_env" {
  name                = "myapp-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.9"
  version_label       = aws_elastic_beanstalk_application_version.version.name

  # Setting the IAM Instance Profile so the EC2 instances can communicate with Beanstalk
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = "aws-elasticbeanstalk-service-role"
  }
}
