}

# 1. S3 Bucket for Elastic Beanstalk Source Bundle
resource "aws_s3_bucket" "eb_bucket" {
  bucket_prefix = "eb-app-bucket-" # Ensuring uniqueness
  force_destroy = true
}

# 2. Upload Application Object
resource "aws_s3_object" "examplebucket_object" {
  bucket = aws_s3_bucket.eb_bucket.id
  key    = "examplebucket_object"
  source = "app.zip" # Assumes a local app.zip exists or provides the structure
}

# 3. IAM Role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

# Attach mandatory policies for Elastic Beanstalk
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_multicontainer" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

# 4. IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 5. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "myapp"
  description = "My Elastic Beanstalk Application"
}

# 6. Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.myapp.name
  description = "application version created by terraform"
  bucket      = aws_s3_bucket.eb_bucket.id
  key         = aws_s3_object.examplebucket_object.id
}

# 7. Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eb-env" {
  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
}

# 8. Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your actual domain name
}

# 9. Route 53 Record pointing to Beanstalk Environment
resource "aws_route53_record" "eb_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "eb-env.example.com"
  type    = "A"

  alias {
    # Elastic Beanstalk environments provide a CNAME. 
    # To use an Alias, we point to the underlying LB or the regional EB DNS.
    # Note: Zone ID varies by region. 
    # For us-east-1, the EB Zone ID is Z117K0FE2G6A7X
    name                   = aws_elastic_beanstalk_environment.eb-env.cname
    zone_id                = "Z117K0FE2G6A7X" 
    evaluate_target_health = true
  }
}

