response:
To configure an AWS Elastic Beanstalk environment linked to an RDS database instance using Terraform, we need to set up several components:
1.  **IAM Role and Instance Profile**: To allow the EC2 instances within the Beanstalk environment to interact with AWS services.
2.  **Relational Database Service (RDS)**: The database instance itself.
3.  **Elastic Beanstalk Application**: The logical container for your environment.
4.  **Elastic Beanstalk Environment**: The actual running infrastructure, where we inject the database connection details as environment properties.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

# Attach standard Beanstalk policies to the role
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_multicontainer_docker" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

# 2. Instance Profile as requested: "eb_ec2_profile"
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_role.name
}

# 3. RDS Database Instance called "default" as requested
resource "aws_db_instance" "default" {
  allocated_storage      = 20
  identifier             = "eb-database-instance"
  engine                 = "postgres"
  engine_version         = "15.3"
  instance_class         = "db.t3.micro"
  db_name                = "ebdb"
  username               = "dbadmin"
  password               = "SecurePassword123!" # Note: Use sensitive variables or Secrets Manager in production
  skip_final_snapshot    = true
  publicly_accessible    = false
}

# 4. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-eb-application"
  description = "Application linked to an RDS instance"
}

# 5. Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "my-eb-env"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.9"

  # Setting the Instance Profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Link Database via Environment Variables (The standard decoupled approach)
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.default.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PORT"
    value     = aws_db_instance.default.port
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.default.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.default.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.default.password
  }

  # Ensure the RDS instance is created before the Environment
  depends_on = [aws_db_instance.default]
}
```

