response:
To configure production and staging environments with Elastic Beanstalk and RDS, we need to perform the following steps:

1.  **IAM Configuration**: Create an IAM Role and the requested Instance Profile `eb_ec2_profile` so that the EC2 instances in the Beanstalk environment have the necessary permissions to function.
2.  **RDS Databases**: Provision two RDS instances. One for production named `prod_db` and one for staging named `staging_db`.
3.  **Elastic Beanstalk Application**: Define a logical container for the environments.
4.  **Elastic Beanstalk Environments**: Create two environments (Production and Staging). We will pass the RDS connection details (endpoint, username, password) into the Beanstalk environments using `setting` blocks so the application code can access the database.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role and Instance Profile for Elastic Beanstalk
resource "aws_iam_role" "eb_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

# Attach managed policies required for Elastic Beanstalk
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_role.name
}

# 2. RDS Instances
resource "aws_db_instance" "prod_db" {
  allocated_storage    = 20
  identifier           = "production-db-instance"
  db_name              = "prod_db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "SecurePassword123!" # In production, use sensitive variables or Secrets Manager
  skip_final_snapshot  = true
  publicly_accessible  = false
}

resource "aws_db_instance" "staging_db" {
  allocated_storage    = 10
  identifier           = "staging-db-instance"
  db_name              = "staging_db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "StagingPass123!"
  skip_final_snapshot  = true
  publicly_accessible  = false
}

# 3. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-application"
  description = "Application with Production and Staging environments"
}

# 4. Elastic Beanstalk Environments
# Production Environment
resource "aws_elastic_beanstalk_environment" "prod_env" {
  name                = "production-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.prod_db.endpoint
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.prod_db.db_name
  }
}

# Staging Environment
resource "aws_elastic_beanstalk_environment" "staging_env" {
  name                = "staging-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

