terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}
# RDS Database Configuration
resource "aws_db_instance" "my_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "mydbuser"
  password             = "mypassword"
  parameter_group_name = "default.mysql5.7"
  multi_az             = true
  skip_final_snapshot  = true
  backup_retention_period = 7  # Enable backups with 7-day retention
  apply_immediately       = true
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-app"
  description = "My Application"
}

# Original Elastic Beanstalk Environment (Blue)
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "my-app-blue-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASS"
    value     = aws_db_instance.my_db.password
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# New Elastic Beanstalk Environment (Green), for the new version
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "my-app-green-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASS"
    value     = aws_db_instance.my_db.password
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
    }
}

# Taking a snapshot before deployment
resource "aws_db_snapshot" "my_db_snapshot" {
  db_instance_identifier = aws_db_instance.my_db.identifier
  db_snapshot_identifier = "my-db-snapshot-${formatdate("YYYYMMDDHHmmss", timestamp())}"
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}

# Weighted DNS records for Blue and Green environments
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 120
  }
  set_identifier = "BlueEnvironment"
  records = [
    aws_elastic_beanstalk_environment.blue_env.cname
  ]
}

resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 60
  }
  set_identifier = "GreenEnvironment"
  records = [
    aws_elastic_beanstalk_environment.green_env.cname
  ]
}

response:
To implement a Blue/Green deployment strategy for AWS Elastic Beanstalk with an external RDS database in Terraform, we need to decouple the database from the Beanstalk environment lifecycle. This ensures that when we swap environments (Blue to Green), the data persists.

Here is the step-by-step logic:
1.  **IAM Role & Profile**: Create the `ec2_eb_profile1` instance profile required for the EC2 instances within the Beanstalk environments.
2.  **RDS Instance**: Create the `my_db` RDS instance. We set `skip_final_snapshot = false` and provide a `final_snapshot_identifier` to ensure a snapshot is taken before the database is ever destroyed or modified significantly.
3.  **Elastic Beanstalk Application**: Define the logical application container.
4.  **Elastic Beanstalk Environments**: Define two environments ("blue" and "green"). Both are configured to point to the same RDS instance via environment variables.
5.  **Blue/Green Swap**: In a real-world scenario, you would use the `aws_elastic_beanstalk_environment` CNAME swap or a Route53 weighted record to switch traffic.

```hcl
# Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Instance Profile for Elastic Beanstalk
resource "aws_iam_role" "eb_role" {
  name = "eb_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "worker_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_instance_profile" "eb_profile" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_role.name
}

# 2. RDS Database Configuration
resource "aws_db_instance" "database" {
  identifier           = "my-db"             # Resource ID
  db_name              = "my_db"             # Actual Database Name
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "14"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "SecurePassword123" # Use secrets management in production
  parameter_group_name = "default.postgres14"

  # Snapshot requirements
  skip_final_snapshot       = false
  final_snapshot_identifier = "my-db-final-snapshot-${timestamp()}"
  backup_retention_period   = 7
  copy_tags_to_snapshot     = true

  lifecycle {
    ignore_changes = [final_snapshot_identifier]
  }
}

# 3. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application for blue/green deployment"
}

# 4. Common Settings for both Environments
locals {
  common_settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_profile.name
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_HOST"
      value     = aws_db_instance.database.address
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_NAME"
      value     = aws_db_instance.database.db_name
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_USER"
      value     = aws_db_instance.database.username
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_PASSWORD"
      value     = aws_db_instance.database.password
    }
  ]
}

# Blue Environment
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 16"

  dynamic "setting" {
    for_each = local.common_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# Green Environment
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 16"

  dynamic "setting" {
    for_each = local.common_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# Output the CNAMEs for verification
output "blue_cname" {
  value = aws_elastic_beanstalk_environment.blue_env.cname
}

output "green_cname" {
  value = aws_elastic_beanstalk_environment.green_env.cname
}
```

