# Variable definitions for easy customization
variable "domain_name" {
  description = "The root domain name"
  type        = string
  default     = "example.com"
}

variable "subdomain" {
  description = "The subdomain to map to IPv6"
  type        = string
  default     = "ipv6-test"
}

