  default     = "2001:0db8:85a3:0000:0000:8a2e:0370:7334"
}

# 1. Create or reference a Route 53 Hosted Zone
# If you already have a zone, you could use a data source instead
resource "aws_route53_zone" "primary" {
  name = var.domain_name
}

# 2. Create the AAAA Record
# Type "AAAA" is used specifically for mapping hostnames to IPv6 addresses
resource "aws_route53_record" "ipv6_mapping" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "${var.subdomain}.${var.domain_name}"
  type    = "AAAA"
  ttl     = 300
  records = [var.ipv6_address]
}

# Output the FQDN for verification
output "record_fqdn" {
  value = aws_route53_record.ipv6_mapping.fqdn
}

