# Terraform Configuration for Multi-Region Elastic Beanstalk with RDS and Route 53

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# --- Providers ---

provider "aws" {
  alias  = "us-east-1"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-west-1"
  region = "eu-west-1"
}

# --- Variables ---

variable "domain_name" {
  description = "The domain name for the Route 53 hosted zone"
  type        = string
  default     = "example.com"
}

variable "db_password" {
  description = "Password for the RDS databases"
  type        = string
  sensitive   = true
  default     = "SecurePassword123!"
}

# --- IAM Resources (Global but used by EB) ---

resource "aws_iam_role" "eb_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

