  provider             = aws.us-east-1
  identifier           = "main-db-us-east"
  db_name              = "main_db_us_east"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "adminuser"
  password             = var.db_password
  skip_final_snapshot  = true
