}

# --- Security Groups ---
resource "aws_security_group" "rds_sg" {
  name   = "rds_shared_sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

# --- IAM Instance Profile ---
resource "aws_iam_role" "eb_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_role.name
}

# --- Shared RDS Database ---
resource "aws_db_instance" "shared_db" {
  identifier           = "myapp-db"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t3.micro"
  db_name              = "myapp_db"
  username             = "dbadmin"
  password             = "SecurePassword123" # Should be handled via secrets manager in production
  db_subnet_group_name = aws_db_subnet_group.db_subnets.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot  = true
}

# --- Elastic Beanstalk Application ---
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application with Blue/Green deployment"
}

# Environment Configuration Template
locals {
  eb_settings = [
    { namespace = "aws:autoscaling:launchconfiguration", name = "IamInstanceProfile", value = aws_iam_instance_profile.eb_profile.name },
    { namespace = "aws:ec2:vpc", name = "VPCId", value = aws_vpc.main.id },
    { namespace = "aws:ec2:vpc", name = "Subnets", value = aws_subnet.subnet_1.id },
    { namespace = "aws:elasticbeanstalk:application:environment", name = "DB_HOST", value = aws_db_instance.shared_db.address }
  ]
}

# Blue Environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# Green Environment
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# --- Route 53 Configuration ---
resource "aws_route53_zone" "primary" {
  name = "myapp.example.com"
}

# Health Checks
resource "aws_route53_health_check" "blue_health" {
  fqdn              = aws_elastic_beanstalk_environment.blue.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"
}

resource "aws_route53_health_check" "green_health" {
  fqdn              = aws_elastic_beanstalk_environment.green.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"
}

# Failover Routing Records
resource "aws_route53_record" "primary_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "CNAME"
  ttl     = "60"

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier  = "blue-env"
  records         = [aws_elastic_beanstalk_environment.blue.cname]
  health_check_id = aws_route53_health_check.blue_health.id
}

resource "aws_route53_record" "secondary_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "CNAME"
  ttl     = "60"

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier  = "green-env"
  records         = [aws_elastic_beanstalk_environment.green.cname]
  health_check_id = aws_route53_health_check.green_health.id
}
```

