# Elastic Beanstalk requires an IAM instance profile to run the EC2 instances

resource "aws_iam_role" "eb_instance_role" {
  name = "${var.app_name}-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach standard Elastic Beanstalk policies to the role
resource "aws_iam_role_policy_attachment" "web_tier" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "worker_tier" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "multicontainer_docker" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "${var.app_name}-instance-profile"
  role = aws_iam_role.eb_instance_role.name
}

# --- Elastic Beanstalk Resources ---

# 1. Define the Application
resource "aws_elastic_beanstalk_application" "tfc_app" {
  name        = var.app_name
  description = "Terraform managed Elastic Beanstalk Application"

  appversion_lifecycle {
    service_role          = aws_iam_role.eb_instance_role.arn
    max_count             = 128
    delete_source_from_s3 = true
  }
}

# 2. Define the Environment
resource "aws_elastic_beanstalk_environment" "tfc_env" {
  name                = var.env_name
  application         = aws_elastic_beanstalk_application.tfc_app.name
  solution_stack_name = var.solution_stack

  # Setting up the instance profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  # Setting the instance type
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = var.instance_type
  }

  # Environment Type (SingleInstance for dev, LoadBalanced for prod)
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "SingleInstance"
  }

  # Enable logging
  setting {
    namespace = "aws:elasticbeanstalk:hostmanager"
    name      = "LogPublicationControl"
    value     = "true"
  }

  tags = {
    Environment = "Template"
    ManagedBy   = "Terraform"
  }
}

# --- Outputs ---
output "eb_url" {
  description = "The URL of the Elastic Beanstalk environment"
  value       = aws_elastic_beanstalk_environment.tfc_env.cname
}

