  name                = "go-webapp-env"
  application         = aws_elastic_beanstalk_application.go_app.name

  # Specify the Solution Stack for Go. 
  # Note: Version strings are updated frequently by AWS. 
  # This targets Go 1 on Amazon Linux 2023.
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.2 running Go 1"

  # 5. Environment Settings

  # Associate the IAM Instance Profile created above
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
