# Terraform configuration to deploy and scale a web application using AWS App Runner

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the Auto Scaling Configuration
# This resource manages how the application scales up or down based on concurrent requests.
resource "aws_apprunner_auto_scaling_configuration_version" "web_app_scaling" {
  auto_scaling_configuration_name = "web-app-auto-scaling"

  # Max number of concurrent requests per instance before scaling
  max_concurrency = 100
  # Maximum number of instances to scale out to
  max_size        = 10
  # Minimum number of instances to keep running
  min_size        = 1

  tags = {
    Name = "web-app-scaling-config"
  }
}

# 2. Define the App Runner Service
# This resource deploys the web application and connects it to the scaling configuration.
resource "aws_apprunner_service" "web_app" {
  service_name = "sample-web-app-service"

  # Link the auto-scaling configuration defined above
  auto_scaling_configuration_arn = aws_apprunner_auto_scaling_configuration_version.web_app_scaling.arn

  # Source configuration: Using a public container image for demonstration.
  # App Runner also supports direct deployment from GitHub repositories for 
  # languages like Python, Node.js, Java, Go, etc.
  source_configuration {
    image_repository {
      image_identifier      = "public.ecr.aws/aws-containers/hello-app-runner:latest"
      image_repository_type = "ECR_PUBLIC"
      port                  = "8000"
    }
    auto_deployments_enabled = false
  }

  # Instance configuration: Define CPU and Memory for the application instances
  instance_configuration {
    cpu    = "1024" # 1 vCPU
    memory = "2048" # 2 GB
  }

  network_configuration {
    egress_configuration {
      egress_type = "DEFAULT"
    }
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# 3. Output the Service URL
# This provides the publicly accessible URL for the deployed web application.
output "web_app_url" {
  description = "The URL to access the web application."
  value       = "https://${aws_apprunner_service.web_app.service_url}"
}

