# AWS CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example project with secondary artifacts"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Secondary Artifact Definition 1
  secondary_artifacts {
    artifact_identifier = "BinaryOutput"
    type                = "S3"
    location            = aws_s3_bucket.artifacts_bucket.bucket
    path                = "binaries/"
    packaging           = "ZIP"
    name                = "app-binary.zip"
  }

  # Secondary Artifact Definition 2
  secondary_artifacts {
    artifact_identifier = "DocsOutput"
    type                = "S3"
    location            = aws_s3_bucket.artifacts_bucket.bucket
    path                = "documentation/"
    packaging           = "NONE"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TYPE"
      value = "example"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/aws-samples/aws-codebuild-samples.git"
    git_clone_depth = 1

    buildspec = <<-END_BUILDSPEC
      version: 0.2
      phases:
        build:
          commands:
            - echo "Building..."
            - mkdir output_bin output_docs
            - touch output_bin/app.exe
            - touch output_docs/readme.txt
      artifacts:
        secondary-artifacts:
          BinaryOutput:
            files:
              - '**/*'
            base-directory: 'output_bin'
          DocsOutput:
            files:
              - '**/*'
            base-directory: 'output_docs'
    END_BUILDSPEC
  }

  source_version = "master"

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    Terraform   = "true"
  }
}

