response:
To create an AWS CodeBuild project with the specified requirements, we need to define the following components:
1.  **IAM Role**: A service role that grants CodeBuild permission to interact with AWS services (Logs, S3, etc.).
2.  **IAM Policy**: Attached to the role to allow logging and S3 access for artifacts.
3.  **CodeBuild Project**: The main resource which includes:
    *   **Environment Variables**: Configuration for the build environment.
    *   **Secondary Sources**: Additional repositories or source locations.
    *   **Secondary Artifacts**: Multiple output locations for build results.

Here is the complete Terraform configuration:

```hcl
# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild (Logs and S3 permissions)
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "example-codebuild-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketLocation",
          "s3:PutObject"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "An example CodeBuild project with secondary sources and artifacts"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  # Primary Source
  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
