  }

  # Secondary Sources
  secondary_sources {
    source_identifier = "secondary_repo_1"
    type              = "GITHUB"
    location          = "https://github.com/example/secondary-repo.git"
    git_clone_depth   = 1
  }

  # Primary Artifacts (Required block)
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Secondary Artifacts
  secondary_artifacts {
    artifact_identifier = "binary_output"
    type                = "S3"
    location            = "example-build-artifacts-bucket" # Ensure this bucket exists
    path                = "binaries/"
    packaging           = "ZIP"
    name                = "app-binary.zip"
  }

  secondary_artifacts {
    artifact_identifier = "docs_output"
    type                = "S3"
    location            = "example-build-artifacts-bucket"
    path                = "documentation/"
    packaging           = "NONE"
  }

  # Environment Configuration
  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # Environment Variables
    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
      type  = "PLAINTEXT"
    }

    environment_variable {
