# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-v2-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard Lex execution policy to the role
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# 2. Create the Lex V2 Bot
resource "aws_lexv2models_bot" "example_bot" {
  name                        = "OrderFlowersBot"
  description                 = "A bot to order flowers"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300

  tags = {
    Environment = "dev"
  }
}

# 3. Create a Locale for the Bot (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.example_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.70
}

# 4. Create an Intent (Welcome Intent)
resource "aws_lexv2models_intent" "welcome_intent" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "WelcomeIntent"

  sample_utterance {
    utterance = "hello"
  }
  sample_utterance {
    utterance = "hi"
  }
  sample_utterance {
    utterance = "I want to order flowers"
  }

  initial_response_setting {
    code_hook {
      active = false
    }
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Hello! I can help you order flowers. What type would you like?"
          }
        }
      }
    }
  }
}

# 5. Create a Bot Version
# Note: In a real scenario, you would build the bot before creating a version.
resource "aws_lexv2models_bot_version" "example_version" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.welcome_intent
  ]
}

# Output the Bot ID
output "lex_bot_id" {
  value = aws_lexv2models_bot.example_bot.id
}

