terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lex_intent" "order_flowers" {
  name = "OrderFlowers"
  description = "Intent to order a bouquet of flowers for pick up"

  sample_utterances = [
    "I would like to pick up flowers",
    "I would like to order some flowers",
  ]

  slot {
    name                     = "FlowerType"
    description              = "Type of flower to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1

    sample_utterances = ["I would like to get {FlowerType} flower."]

    value_elicitation_prompt {
      message {
        content             = "What type of flower would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PickupDate"
    description              = "Date of flower pickup"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.DATE"
    priority                 = 2

    value_elicitation_prompt {
      message {
        content             = "When would you like to pickup your flower?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, your {FlowerType} will be ready for pickup on {PickupDate}.  Does this sound okay?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  rejection_statement {
    message {
      content      = "Okay, I will not place your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "order_flowers" {
  name     = "OrderFlowers"
  description = "Bot to order flowers on the behalf of a user"
  locale   = "en-US"
  process_behavior = "BUILD"
  voice_id = "Salli"
  child_directed = false
  create_version = false
  detect_sentiment            = false
  idle_session_ttl_in_seconds = 600

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_flowers.name
    intent_version = aws_lex_intent.order_flowers.version
  }
}

response:
To create an AWS Lex V2 Bot using Terraform, we need to define the IAM role for the bot, the bot itself, a locale (language), and at least one intent. AWS Lex V2 is the current standard, and the following configuration sets up a basic "OrderFlowers" bot structure.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-v2-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard Lex execution policy to the role
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# 2. Create the Lex V2 Bot
resource "aws_lexv2models_bot" "example_bot" {
  name                        = "OrderFlowersBot"
  description                 = "A bot to order flowers"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300

  tags = {
    Environment = "dev"
  }
}

# 3. Create a Locale for the Bot (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.example_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.70
}

# 4. Create an Intent (Welcome Intent)
resource "aws_lexv2models_intent" "welcome_intent" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "WelcomeIntent"

  sample_utterance {
    utterance = "hello"
  }
  sample_utterance {
    utterance = "hi"
  }
  sample_utterance {
    utterance = "I want to order flowers"
  }

  initial_response_setting {
    code_hook {
      active = false
    }
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Hello! I can help you order flowers. What type would you like?"
          }
        }
      }
    }
  }
}

# 5. Create a Bot Version
# Note: In a real scenario, you would build the bot before creating a version.
resource "aws_lexv2models_bot_version" "example_version" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.welcome_intent
  ]
}

# Output the Bot ID
output "lex_bot_id" {
  value = aws_lexv2models_bot.example_bot.id
}
```

