  name = "lex-v2-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Define the Lex V2 Bot
resource "aws_lexv2_models_bot" "order_bot" {
  name                        = "OrderPizzaBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
}

# 3. Create a Locale for the Bot (English US)
resource "aws_lexv2_models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2_models_bot.order_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.70
