}

# 4. Custom Slot Type for Pizza Size
resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  name        = "PizzaSize"

  slot_type_values {
    sample_value { value = "Small" }
  }
  slot_type_values {
    sample_value { value = "Medium" }
  }
  slot_type_values {
    sample_value { value = "Large" }
  }
}

# 5. Order Pizza Intent
resource "aws_lexv2models_intent" "order_pizza_intent" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I get a {size} pizza" }
  sample_utterance { utterance = "Order pizza" }

  # Confirmation Setting (The "Confirm Order" question)
  confirmation_setting {
    active = true
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "Okay, I have a {size} pizza. Should I go ahead and place the order?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "No problem. Your order has been cancelled."
          }
        }
      }
    }
  }

  # Closing Response (The Follow-up question)
  closing_setting {
    active = true
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great! Your pizza is being prepared. Would you like to add a side or a drink to your order?"
          }
        }
      }
    }
  }
}

# 6. Slot for the Intent
resource "aws_lexv2models_slot" "size_slot" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza_intent.intent_id
  name        = "size"

  slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? Small, Medium, or Large?"
          }
        }
      }
    }
  }
}

