terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_lex_bot" "pizza_order_bot" {
  name = "PizzaOrderBot"
  description = "Pizza order bot"
  idle_session_ttl_in_seconds = 600
  create_version = false
  child_directed = false

  abort_statement {
    message {
      content = "Sorry, I am not able to assist."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content = "I'm sorry, I didn't understand that. Can you try again?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name = aws_lex_intent.OrderPizzaIntent.name
    intent_version = aws_lex_intent.OrderPizzaIntent.version
  }
}

resource "aws_lex_intent" "OrderPizzaIntent" {
  name = "OrderPizzaIntent"
  create_version = true

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name = "PizzaType"
    description = "Type of pizza to order"
    priority = 1  # must be in [1, 100]
    slot_type = aws_lex_slot_type.PizzaType.name
    slot_type_version = aws_lex_slot_type.PizzaType.version
    slot_constraint = "Required"

    sample_utterances = ["I want a {PizzaType} pizza.", "A {PizzaType} pizza please."]

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content = "What type of pizza would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content = "So, you would like to order a pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
        content = "Sorry, I don't know how to help then"
        content_type = "PlainText"
      }
    }

  follow_up_prompt {
    prompt {
      max_attempts = 2
      message {
        content = "Would you like anything else with your order?"
        content_type = "PlainText"
      }
    }
    rejection_statement {
      message {
        content = "OK, Your pizza is on its way."
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_slot_type" "PizzaType" {
  create_version = true
  description = "Types of pizza available to order"
  name = "PizzaTypes"
  enumeration_value {
    value = "Margherita"
  }
  enumeration_value {
    value = "Pepperoni"
  }
}

response:
To create an AWS Lex (V2) bot for ordering pizza with a follow-up question, we need to define the Bot, the Locale, the Intent, and the Slots. We also need an IAM role that allows Lex to run.

The following configuration includes:
1.  **IAM Role**: Permissions for the Lex bot.
2.  **Lex Bot**: The main container for the bot.
3.  **Locale**: English (US) setup.
4.  **Slot Type**: A custom "PizzaSize" type.
5.  **Intent**: "OrderPizza" with sample utterances.
6.  **Slots**: Capturing the pizza size.
7.  **Confirmation & Follow-up**: A confirmation prompt to verify the order and a closing response that acts as a follow-up question ("Would you like to add a drink?").

```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "PizzaBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# 2. The Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
}

# 3. Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "pizza_bot_en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold  = 0.4
}

# 4. Custom Slot Type for Pizza Size
resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  name        = "PizzaSize"

  slot_type_values {
    sample_value { value = "Small" }
  }
  slot_type_values {
    sample_value { value = "Medium" }
  }
  slot_type_values {
    sample_value { value = "Large" }
  }
}

# 5. Order Pizza Intent
resource "aws_lexv2models_intent" "order_pizza_intent" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I get a {size} pizza" }
  sample_utterance { utterance = "Order pizza" }

  # Confirmation Setting (The "Confirm Order" question)
  confirmation_setting {
    active = true
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "Okay, I have a {size} pizza. Should I go ahead and place the order?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "No problem. Your order has been cancelled."
          }
        }
      }
    }
  }

  # Closing Response (The Follow-up question)
  closing_setting {
    active = true
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great! Your pizza is being prepared. Would you like to add a side or a drink to your order?"
          }
        }
      }
    }
  }
}

# 6. Slot for the Intent
resource "aws_lexv2models_slot" "size_slot" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza_intent.intent_id
  name        = "size"

  slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? Small, Medium, or Large?"
          }
        }
      }
    }
  }
}
```

