To create an AWS Lex (V1) Bot for ordering pizzas using Terraform, we need to define three main components:
1.  **IAM Role**: To allow the Lex service to function and log.
2.  **Lex Intent**: To define the "OrderPizza" logic, including the slots (size, crust type) and the requested **conclusion statement**.
3.  **Lex Bot**: To wrap the intent into a functional conversational interface.

Here is the complete Terraform configuration.

```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Lex Intent for Ordering Pizza
resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizzaIntent"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Can I get a pizza",
    "Order a {PizzaSize} pizza"
  ]

  # Slot for Pizza Size
  slot {
    name             = "PizzaSize"
    description      = "The size of the pizza (Small, Medium, Large)"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.AlphaNumeric" # Or a custom slot type if preferred
    slot_type_version = "$LATEST"
    priority         = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? (Small, Medium, or Large)"
        content_type = "PlainText"
      }
    }
  }

  # Slot for Pizza Type/Topping
  slot {
    name             = "PizzaType"
    description      = "The type of pizza (e.g., Pepperoni, Margherita)"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.AlphaNumeric"
    slot_type_version = "$LATEST"
    priority         = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What kind of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  # Conclusion Statement as requested
  conclusion_statement {
    message {
      content      = "Great! I have placed your order for a {PizzaSize} {PizzaType} pizza. It will be ready in 20 minutes."
      content_type = "PlainText"
    }
    response_card = "{"version":1,"contentType":"application/vnd.amazonaws.card.generic","genericAttachments":[]}"
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# 3. Lex Bot Configuration
resource "aws_lex_bot" "pizza_bot" {
  name             = "PizzaOrderingBot"
  description      = "A bot for ordering pizzas"
  locale           = "en-US"
  child_directed   = false
  process_behavior = "BUILD"

  intent {
    intent_name    = aws_lex_intent.order_pizza_intent.name
    intent_version = "$LATEST"
  }

  clarification_prompt {
    max_attempts = 2
    message {
