  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Intent: BookHotel
resource "aws_lex_intent" "book_hotel" {
  name        = "BookHotel"
  description = "Intent to book a hotel"

  sample_utterances = [
    "I would like to book a hotel",
    "Book a hotel in {Location}",
    "I want to make a hotel reservation"
  ]

  slot {
    name             = "Location"
    description      = "The city the hotel is located in"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.US_CITY"
    priority         = 1
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What city will you be staying in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name             = "CheckInDate"
    description      = "The date of check in"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.DATE"
    priority         = 2
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day do you want to check in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name             = "Nights"
    description      = "Number of nights to stay"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.NUMBER"
    priority         = 3
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many nights are you staying?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I have you down for a stay in {Location} starting {CheckInDate}. Shall I book it?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnParameters"
  }
}

# 3. Intent: BookCar
resource "aws_lex_intent" "book_car" {
  name        = "BookCar"
  description = "Intent to book a rental car"

  sample_utterances = [
    "Book a car",
    "Reserve a car in {PickUpCity}",
    "I need a rental car"
  ]

  slot {
    name             = "PickUpCity"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.US_CITY"
    priority         = 1
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "In what city do you need the car?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name             = "PickUpDate"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.DATE"
    priority         = 2
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day do you want to pick up the car?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name             = "CarType"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.AlphaNumeric" # Or a custom slot type for Economy, Luxury, etc.
    priority         = 3
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of car would you like (Economy, Standard, or Luxury)?"
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnParameters"
  }
}

# 4. Lex Bot: BookTrip
resource "aws_lex_bot" "book_trip_bot" {
  name                         = "BookTripBot"
  description                  = "Bot to assist with hotel and car bookings"
  process_behavior             = "BUILD"
  child_directed               = false
  locale                       = "en-US"
  idle_session_ttl_in_seconds  = 300
  voice_id                     = "Salli"

  # Clarification prompt if the bot doesn't understand
  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I'm sorry, I didn't hear that. Can you repeat? You can say 'Book a hotel' or 'Book a car'."
      content_type = "PlainText"
    }
  }

  # Message if the bot fails multiple times
  abort_statement {
    message {
      content      = "I am sorry, I am unable to assist you with that at this time. Goodbye."
      content_type = "PlainText"
    }
  }

  # Link the intents to the bot
  intent {
    intent_name    = aws_lex_intent.book_hotel.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.book_car.name
    intent_version = "$LATEST"
  }

  # Depend on the intents being created first
  depends_on = [
    aws_lex_intent.book_hotel,
    aws_lex_intent.book_car
  ]
}

