# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for the Lex Bot
resource "aws_iam_role" "lex_pizza_bot_role" {
  name = "PizzaKidBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to the role
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_pizza_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# 1. Define the Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_kid_bot" {
  name                        = "PizzaKidBot"
  description                 = "A fun pizza ordering bot for kids"
  role_arn                    = aws_iam_role.lex_pizza_bot_role.arn
  idle_session_ttl_in_seconds = 300

  data_privacy {
    child_directed = true # Mandatory for kid-focused bots (COPPA compliance)
  }
}

# 2. Define the English Locale
resource "aws_lexv2models_bot_locale" "pizza_locale_en" {
  bot_id                           = aws_lexv2models_bot.pizza_kid_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.70
}

# 3. Custom Slot Type: Pizza Sizes (Kid-friendly names)
resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_kid_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale_en.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale_en.locale_id
  name        = "PizzaSizeSlotType"
  description = "Sizes for kids"

  slot_type_values {
    sample_value { value = "Mini-Mouse" }
  }
  slot_type_values {
    sample_value { value = "Small-Snack" }
  }
  slot_type_values {
    sample_value { value = "Super-Size" }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# 4. Custom Slot Type: Toppings
resource "aws_lexv2models_slot_type" "pizza_topping" {
  bot_id      = aws_lexv2models_bot.pizza_kid_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale_en.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale_en.locale_id
  name        = "PizzaToppingSlotType"

  slot_type_values { sample_value { value = "Extra Cheese" } }
  slot_type_values { sample_value { value = "Pepperoni" } }
  slot_type_values { sample_value { value = "Rainbow Veggies" } }
  slot_type_values { sample_value { value = "Tiny Tomatoes" } }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# 5. The Main Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza_intent" {
  bot_id      = aws_lexv2models_bot.pizza_kid_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale_en.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale_en.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want a yummy pizza!" }
  sample_utterance { utterance = "Can I have a pizza please?" }
  sample_utterance { utterance = "I'm hungry for pizza." }
  sample_utterance { utterance = "Order pizza" }

  # Slot: Pizza Size
  slot {
    name        = "PizzaSize"
    description = "The size of the pizza"
    slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id

    value_elicitation_setting {
      prompt_specification {
        max_retries = 3
        message_group {
          message {
            plain_text_message {
              content = "Hi little chef! What size pizza do you want? We have Mini-Mouse, Small-Snack, or Super-Size!"
            }
          }
        }
      }
    }
  }

  # Slot: Pizza Topping
  slot {
    name        = "PizzaTopping"
    description = "The topping for the pizza"
    slot_type_id = aws_lexv2models_slot_type.pizza_topping.slot_type_id

    value_elicitation_setting {
      prompt_specification {
        max_retries = 3
        message_group {
          message {
            plain_text_message {
              content = "Yum! What yummy topping should we put on your pizza?"
            }
          }
        }
      }
    }
  }

  # Confirmation Setting
  confirmation_setting {
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            content = "Okay! So that's a {PizzaSize} pizza with {PizzaTopping}. Ready to order?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            content = "No problem! We can start over. What would you like instead?"
          }
        }
      }
    }
  }

  # Final Fulfillment Message
  fulfillment_code_hook {
    enabled = false # Set to true if linking to a Lambda
  }

  closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            content = "Yay! Your pizza is being cooked by our magic ovens. It will be ready soon!"
          }
        }
      }
    }
  }
}

# 6. Fallback Intent (Handles misunderstood input)
resource "aws_lexv2models_intent" "fallback_intent" {
  bot_id      = aws_lexv2models_bot.pizza_kid_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale_en.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale_en.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}

# 7. Create a Bot Version
resource "aws_lexv2models_bot_version" "pizza_bot_v1" {
  bot_id      = aws_lexv2models_bot.pizza_kid_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.pizza_locale_en.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.order_pizza_intent,
    aws_lexv2models_intent.fallback_intent
  ]
}

