}

response:
To create an Amazon Lex (V2) bot for ordering pizzas with an integrated Lambda function, we need to define the IAM roles, the Lambda function logic, the Lex bot structure, and the necessary permissions for Lex to invoke Lambda.

The following Terraform configuration sets up:
1.  **IAM Roles**: For both Lambda execution and Lex bot operations.
2.  **Lambda Function**: A simple Python-based fulfillment function.
3.  **Lex V2 Bot**: Including a locale (en_US), an intent (OrderPizza), and slots (PizzaSize, PizzaType).
4.  **Lex Bot Alias & Version**: To make the bot functional and link it to the Lambda.

```hcl
# --- Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- IAM Role for Lambda ---
resource "aws_iam_role" "lambda_exec_role" {
  name = "pizza_bot_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# --- Lambda Function for Fulfillment ---
resource "aws_lambda_function" "pizza_bot_fulfillment" {
  filename      = "lambda_function_payload.zip" # This expects a local zip or dummy content
  function_name = "pizza_bot_fulfillment"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.9"

  # Create a dummy zip file inline for demonstration purposes
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"
  source {
    content  = <<-EOF
def lambda_handler(event, context):
    intent_name = event['sessionState']['intent']['name']
    slots = event['sessionState']['intent']['slots']

    pizza_type = slots['PizzaType']['value']['interpretedValue']
    pizza_size = slots['PizzaSize']['value']['interpretedValue']

    response = {
        "sessionState": {
            "dialogAction": {
                "type": "Close"
            },
            "intent": {
                "name": intent_name,
                "slots": slots,
                "state": "Fulfilled"
            }
        },
        "messages": [
            {
                "contentType": "PlainText",
                "content": f"Thanks! I have placed your order for a {pizza_size} {pizza_type} pizza."
            }
        ]
    }
    return response
EOF
    filename = "index.py"
  }
}

# --- IAM Role for Lex Bot ---
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_bot_lex_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lexv2.amazonaws.com"
      }
    }]
  })
}

# --- Lex V2 Bot Definition ---
resource "aws_lexv2_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  description                 = "Bot for ordering pizzas"
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_bot_role.arn
}

resource "aws_lexv2_bot_locale" "en_us" {
  bot_id                           = aws_lexv2_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# --- Lex Intent: OrderPizza ---
resource "aws_lexv2_bot_intent" "order_pizza" {
  bot_id      = aws_lexv2_bot.pizza_bot.id
  bot_version = aws_lexv2_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I get a pizza?" }
  sample_utterance { utterance = "Order a {PizzaSize} {PizzaType} pizza" }

  fulfillment_code_hook {
    enabled = true
  }
}

# --- Slots for Intent ---
resource "aws_lexv2_bot_slot" "pizza_type" {
  bot_id      = aws_lexv2_bot.pizza_bot.id
  bot_version = aws_lexv2_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2_bot_intent.order_pizza.intent_id
  name        = "PizzaType"

  slot_type_id = "AMAZON.AlphaNumeric" # Using built-in type for simplicity

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            content = "What kind of pizza would you like (e.g., Pepperoni, Veggie)?"
          }
        }
      }
    }
  }
}

resource "aws_lexv2_bot_slot" "pizza_size" {
  bot_id      = aws_lexv2_bot.pizza_bot.id
  bot_version = aws_lexv2_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2_bot_intent.order_pizza.intent_id
  name        = "PizzaSize"

  slot_type_id = "AMAZON.AlphaNumeric"

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            content = "What size would you like (Small, Medium, Large)?"
          }
        }
      }
    }
  }
}

# --- Bot Version and Alias ---
resource "aws_lexv2_bot_version" "pizza_bot_v1" {
  bot_id      = aws_lexv2_bot.pizza_bot.id
  locale_specification = {
    (aws_lexv2_bot_locale.en_us.locale_id) = {
      source_bot_version = aws_lexv2_bot_locale.en_us.bot_version
    }
  }
}

resource "aws_lexv2_bot_alias" "pizza_bot_prod" {
  bot_id      = aws_lexv2_bot.pizza_bot.id
  name        = "Prod"
  bot_version = aws_lexv2_bot_version.pizza_bot_v1.bot_version

  bot_alias_locale_settings {
    locale_id = aws_lexv2_bot_locale.en_us.locale_id
    enabled   = true
    code_hook {
      lambda_code_hook {
        code_hook_interface_version = "1.0"
        lambda_arn                  = aws_lambda_function.pizza_bot_fulfillment.arn
      }
    }
  }
}

# --- Lambda Permission for Lex ---
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_bot_fulfillment.function_name
  principal     = "lexv2.amazonaws.com"
  source_arn    = "${aws_lexv2_bot.pizza_bot.arn}/*"
}
