  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# --- Lex V2 Bot ---
resource "aws_lexv2models_bot" "example_bot" {
  name                        = "OrderFlowersBot"
  description                 = "A bot to order flowers"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  idle_session_ttl_in_seconds = 300

  data_privacy {
    child_directed = false
  }

  tags = {
    Environment = "Development"
  }
}

# --- Lex V2 Bot Locale (English US) ---
resource "aws_lexv2models_bot_locale" "example_locale" {
  bot_id                           = aws_lexv2models_bot.example_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# --- Lex V2 Intent (Fallback Intent) ---
# Every Lex bot requires a Fallback intent
resource "aws_lexv2models_bot_intent" "fallback_intent" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.example_locale.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
