# 1. Create a Kinesis Data Stream to act as the source
resource "aws_kinesis_stream" "input_stream" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24

  tags = {
    Environment = "Development"
  }
}

# 2. Create an IAM Role for the Kinesis Analytics Application
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach a policy to the role to allow reading from the Kinesis Stream
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream",
          "kinesis:ListShards"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.input_stream.arn
      }
    ]
  })
}

# 4. Create the Kinesis Analytics v2 Application
resource "aws_kinesisanalyticsv2_application" "example_app" {
  name                   = "example-sql-application"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        # Define how the data is formatted (JSON in this example)
        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json_mapping_parameters {
                record_row_path = "$"
              }
            }
          }

          record_encoding = "UTF-8"

          # Define the columns expected in the JSON input
          record_column {
            name     = "sensor_id"
            sql_type = "VARCHAR(64)"
            mapping  = "$.sensor_id"
          }

          record_column {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temperature"
          }
        }

        # Link the Kinesis Stream as the input source
        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
        }
      }
    }
  }

  tags = {
    Application = "SensorAnalytics"
  }
}

# Output the Application ARN
output "kinesis_analytics_app_arn" {
  value       = aws_kinesisanalyticsv2_application.example_app.arn
  description = "The ARN of the Kinesis Analytics Application"
}

