# Terraform configuration for Amazon Managed Service for Apache Flink (formerly Kinesis Analytics V2)
# This includes the S3 bucket for code storage, IAM roles, logging, and the Flink application.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create an S3 bucket to store the Apache Flink application code (JAR or Zip)
resource "aws_s3_bucket" "flink_assets" {
  bucket = "flink-app-assets-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. Upload a placeholder for the application code
# In a real scenario, this would be your compiled Flink JAR file.
resource "aws_s3_object" "flink_jar" {
  bucket = aws_s3_bucket.flink_assets.id
  key    = "my-flink-app.jar"
  source = "my-flink-app.jar" # Path to your local JAR
  # Use etag to trigger updates when the file changes
  etag   = filemd5("my-flink-app.jar")
}

# 3. Create IAM Role for the Kinesis Analytics Application
resource "aws_iam_role" "flink_role" {
  name = "kinesis-analytics-flink-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach policies to the IAM Role to allow access to S3 and CloudWatch Logs
resource "aws_iam_role_policy" "flink_policy" {
  name = "kinesis-analytics-flink-policy"
  role = aws_iam_role.flink_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.flink_assets.arn,
          "${aws_s3_bucket.flink_assets.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents",
          "logs:DescribeLogGroups",
          "logs:DescribeLogStreams"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# 5. Create CloudWatch Log Group and Stream for application monitoring
resource "aws_cloudwatch_log_group" "flink_log_group" {
  name = "/aws/kinesis-analytics/my-flink-application"
}

resource "aws_cloudwatch_log_stream" "flink_log_stream" {
  name           = "flink-log-stream"
  log_group_name = aws_cloudwatch_log_group.flink_log_group.name
}

# 6. Define the Kinesis Analytics V2 (Flink) Application
resource "aws_kinesisanalyticsv2_application" "flink_application" {
  name                   = "my-flink-application"
  runtime_environment    = "FLINK-1_18" # Current Flink runtime
  service_execution_role = aws_iam_role.flink_role.arn

  application_configuration {
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.flink_assets.arn
          file_key   = aws_s3_object.flink_jar.key
        }
      }
      code_content_type = "ZIPFILE" # Use ZIPFILE for JARs/Zips
    }

    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 1
        parallelism_per_kpu  = 1
      }
    }

    # Configuration for CloudWatch logging within the app
    cloudwatch_logging_options {
      log_stream_arn = aws_cloudwatch_log_stream.flink_log_stream.arn
    }
  }

  tags = {
    Environment = "Dev"
    Application = "FlinkApp"
  }
}

# Output the Application ARN
output "flink_application_arn" {
  value = aws_kinesisanalyticsv2_application.flink_application.arn
}

