# Terraform configuration for Kinesis Firehose with Dynamic Partitioning

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Firehose destination
resource "aws_s3_bucket" "destination" {
  bucket        = "firehose-dynamic-partitioning-bucket-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose to access S3 and CloudWatch
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = "firehose_delivery_role"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.destination.arn,
          "${aws_s3_bucket.destination.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# 4. Kinesis Firehose Delivery Stream with Dynamic Partitioning
resource "aws_kinesis_firehose_delivery_stream" "dynamic_partitioning_stream" {
  name        = "dynamic-partitioning-s3-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.destination.arn

    # Buffer settings
    buffering_size     = 64
    buffering_interval = 60

    # Dynamic Partitioning Configuration
    dynamic_partitioning_configuration {
      enabled = "true"
    }

    # Use JQL (JSON Query Language) to define the partition key from the record
    # This example expects a JSON field named 'customer_id' and 'service'
    prefix              = "data/customer_id=!{partitionKeyFromQuery:customer_id}/service=!{partitionKeyFromQuery:service}/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_output_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/!{firehose:error-output-type}/"

    processing_configuration {
      enabled = "true"

      # Processor to extract metadata for Dynamic Partitioning
      processors {
        type = "MetadataExtraction"
        parameters {
          parameter_name  = "MetadataExtractionQuery"
          parameter_value = "{customer_id: .customer_id, service: .service}"
        }
        parameters {
          parameter_name  = "JsonParsingEngine"
          parameter_value = "JQ-1.6"
        }
      }

      # Append a newline to each record for better S3 readability
      processors {
        type = "AppendDelimiterToRawData"
        parameters {
          parameter_name  = "Delimiter"
          parameter_value = "\n"
        }
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/dynamic-partitioning-stream"
      log_stream_name = "S3Delivery"
    }
  }
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/dynamic-partitioning-stream"
  retention_in_days = 7
}

