response:
To generate a Kinesis Data Firehose delivery stream with an Amazon Redshift destination, we need to set up several interconnected components: a VPC for the Redshift cluster, an S3 bucket for intermediate data storage (required by Firehose for Redshift copies), IAM roles for permissions, and the Firehose stream itself.

### Step-by-Step Logic:
1.  **Networking**: Create a VPC, Subnet, and Security Group to host the Redshift cluster.
2.  **Redshift Cluster**: Provision the Redshift cluster which will serve as the final data destination.
3.  **S3 Storage**: Create an S3 bucket. Firehose first loads data into S3 and then issues a Redshift `COPY` command to move data from S3 to Redshift.
4.  **IAM Roles**: 
    *   Create a role for Firehose to allow it to access the S3 bucket and interact with the Redshift cluster.
5.  **Kinesis Firehose**: Configure the delivery stream with the `redshift_configuration` block, specifying the cluster JDBC URL, credentials, and the intermediate S3 configuration.

```hcl
# Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Networking Components
resource "aws_vpc" "firehose_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "redshift_subnet" {
  vpc_id            = aws_vpc.firehose_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_redshift_subnet_group" "main" {
  name       = "firehose-redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]
}

resource "aws_security_group" "redshift_sg" {
  name   = "redshift-sg"
  vpc_id = aws_vpc.firehose_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to Firehose IP ranges
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 2. Redshift Cluster
resource "aws_redshift_cluster" "destination" {
  cluster_identifier  = "firehose-redshift-cluster"
  database_name       = "dev"
  master_username     = "adminuser"
  master_password     = "MustBe8CharactersMin"
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  skip_final_snapshot       = true
  publicly_accessible       = true # Required for Firehose to reach Redshift if not using VPC endpoints
}

# 3. Intermediate S3 Bucket
resource "aws_s3_bucket" "firehose_intermediate" {
  bucket        = "firehose-redshift-intermediate-bucket-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 4. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_redshift_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name = "firehose_redshift_policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_intermediate.arn,
          "${aws_s3_bucket.firehose_intermediate.arn}/*"
        ]
      },
      {
        Action = [
          "kinesis:GetRecords",
          "kinesis:GetShardIterator",
          "kinesis:DescribeStream"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

# 5. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "kinesis-firehose-to-redshift"
  destination = "redshift"

  redshift_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    cluster_jdbcurl    = "jdbc:redshift://${aws_redshift_cluster.destination.endpoint}/${aws_redshift_cluster.destination.database_name}"
    username           = "adminuser"
    password           = "MustBe8CharactersMin"
    data_table_name    = "incoming_data" # Ensure this table exists in Redshift
    copy_options       = "csv"           # Example: data format

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_intermediate.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    # Optional: Backup mode for failed records
    s3_backup_mode = "Disabled"
  }
}

