# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an S3 Bucket for Firehose backups/failures
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-es-backup-bucket-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_elasticsearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose to access S3 and Elasticsearch
resource "aws_iam_role_policy" "firehose_policy" {
  name   = "firehose_delivery_policy"
  role   = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = [
          aws_elasticsearch_domain.example.arn,
          "${aws_elasticsearch_domain.example.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpGet"
        ]
        Resource = [
          aws_elasticsearch_domain.example.arn,
          "${aws_elasticsearch_domain.example.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# 4. Elasticsearch (OpenSearch) Domain
resource "aws_elasticsearch_domain" "example" {
  domain_name           = "tf-firehose-es"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type = "t3.small.elasticsearch"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "es:*"
        Principal = "*"
        Effect    = "Allow"
        Resource  = "arn:aws:es:us-east-1:*:domain/tf-firehose-es/*"
      }
    ]
  })
}

# 5. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_stream" {
  name        = "terraform-kinesis-firehose-es-stream"
  destination = "elasticsearch"

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "GZIP"
  }

  elasticsearch_configuration {
    domain_arn            = aws_elasticsearch_domain.example.arn
    role_arn              = aws_iam_role.firehose_role.arn
    index_name            = "logs"
    index_rotation_period = "OneDay"
    type_name             = "_doc"

    # CloudWatch logging for Firehose
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_stream.name
    }

    s3_backup_mode = "FailedDocumentsOnly"
  }
}

# CloudWatch Logging setup
resource "aws_cloudwatch_log_group" "firehose_logs" {
  name = "/aws/kinesisfirehose/terraform-kinesis-firehose-es-stream"
}

resource "aws_cloudwatch_log_stream" "firehose_stream" {
  name           = "ElasticsearchDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose_logs.name
}

