# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Variables for Splunk Configuration
variable "splunk_hec_url" {
  description = "The Splunk HTTP Event Collector (HEC) endpoint URL"
  type        = string
  default     = "https://http-inputs-mysplunk.splunkcloud.com:8088/v1/collector"
}

variable "splunk_hec_token" {
  description = "The Splunk HEC Token"
  type        = string
  sensitive   = true
}

# 1. S3 Bucket for Firehose Backups (Required for failed events)
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "splunk-firehose-backup-bucket-unique-id"
}

resource "aws_s3_bucket_ownership_controls" "firehose_backup_oc" {
  bucket = aws_s3_bucket.firehose_backup.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_backup_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_backup_oc]
  bucket     = aws_s3_bucket.firehose_backup.id
  acl        = "private"
}

# 2. IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_splunk_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose (Permissions for S3 and CloudWatch Logs)
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_splunk_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect = "Allow"
        Resource = [
          "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*"
        ]
      }
    ]
  })
}

# 4. CloudWatch Log Group for Firehose Error Logging
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name = "/aws/kinesisfirehose/splunk-stream"
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "SplunkDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# 5. Kinesis Firehose Delivery Stream with Splunk Destination
resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name        = "splunk-delivery-stream"
  destination = "splunk"

  splunk_configuration {
    hec_endpoint               = var.splunk_hec_url
    hec_token                  = var.splunk_hec_token
    hec_acknowledgment_timeout = 600
    hec_endpoint_type          = "Raw"
    s3_backup_mode             = "FailedEventsOnly"

    # Configuration for the S3 bucket where failed events are sent
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
        log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }
  }
}

