# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an S3 Bucket for Firehose backups (required for OpenSearch destination)
resource "aws_s3_bucket" "firehose_backup" {
  bucket_prefix = "firehose-oss-backup-"
  force_destroy = true
}

# 2. OpenSearch Serverless: Encryption Policy
resource "aws_opensearchserverless_security_policy" "encryption_policy" {
  name = "firehose-encryption-policy"
  type = "encryption"
  policy = jsonencode({
    Rules = [
      {
        Resource = ["collection/firehose-collection"]
        ResourceType = "collection"
      }
    ],
    AWSOwnedKey = true
  })
}

# 3. OpenSearch Serverless: Network Policy (Public access for this example)
resource "aws_opensearchserverless_security_policy" "network_policy" {
  name = "firehose-network-policy"
  type = "network"
  policy = jsonencode([
    {
      Rules = [
        {
          Resource = ["collection/firehose-collection"]
          ResourceType = "collection"
        },
        {
          Resource = ["collection/firehose-collection"]
          ResourceType = "dashboard"
        }
      ],
      AllowFromPublic = true
    }
  ])
}

# 4. OpenSearch Serverless: Collection
resource "aws_opensearchserverless_collection" "firehose_collection" {
  name             = "firehose-collection"
  type             = "TIMESERIES"
  description      = "Collection for Firehose ingestion"
  depends_on       = [aws_opensearchserverless_security_policy.encryption_policy]
}

# 5. IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_oss_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 6. OpenSearch Serverless: Data Access Policy 
# Grants the Firehose Role permission to write to the collection
resource "aws_opensearchserverless_access_policy" "data_access_policy" {
  name = "firehose-access-policy"
  type = "data"
  policy = jsonencode([
    {
      Rules = [
        {
          Resource = ["collection/firehose-collection"]
          Permission = [
            "aoss:CreateCollectionItems",
            "aoss:DescribeCollectionItems",
            "aoss:UpdateCollectionItems"
          ]
          ResourceType = "collection"
        },
        {
          Resource = ["index/firehose-collection/*"]
          Permission = [
            "aoss:CreateIndex",
            "aoss:DescribeIndex",
            "aoss:ReadDocument",
            "aoss:WriteDocument",
            "aoss:UpdateIndex"
          ]
          ResourceType = "index"
        }
      ],
      Principal = [aws_iam_role.firehose_role.arn]
    }
  ])
}

# 7. IAM Policy for Firehose to access S3 and OSS
resource "aws_iam_role_policy" "firehose_permissions" {
  name = "firehose_oss_permissions"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Action = [
          "aoss:APIAccessAll"
        ]
        Effect   = "Allow"
        Resource = [aws_opensearchserverless_collection.firehose_collection.arn]
      }
    ]
  })
}

# 8. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "oss_delivery_stream" {
  name        = "firehose-to-oss-serverless"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_endpoint = aws_opensearchserverless_collection.firehose_collection.collection_endpoint
    index_name          = "logs"
    role_arn            = aws_iam_role.firehose_role.arn

    # Required: Configuration for data that fails to index
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    # Optional: CloudWatch logging
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/oss-delivery"
      log_stream_name = "S3Delivery"
    }
  }

  depends_on = [
    aws_opensearchserverless_access_policy.data_access_policy,
    aws_iam_role_policy.firehose_permissions
  ]
}

# Outputs
output "firehose_arn" {
  value = aws_kinesis_firehose_delivery_stream.oss_delivery_stream.arn
}

output "oss_collection_endpoint" {
  value = aws_opensearchserverless_collection.firehose_collection.collection_endpoint
}

