# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# --- Variables ---
variable "new_relic_license_key" {
  description = "New Relic License Key or Insights Insert Key"
  type        = string
  sensitive   = true
}

variable "new_relic_endpoint_url" {
  description = "New Relic HTTP Endpoint (US: https://aws-api.newrelic.com/firehose/v1, EU: https://aws-api.eu.newrelic.com/firehose/v1)"
  type        = string
  default     = "https://aws-api.newrelic.com/firehose/v1"
}

# --- S3 Bucket for Backup ---
# Firehose requires an S3 bucket to store records that failed to deliver to the HTTP endpoint
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-http-backup-bucket-${data.aws_caller_identity.current.account_id}"
}

data "aws_caller_identity" "current" {}

# --- CloudWatch Logging ---
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name = "/aws/kinesisfirehose/http-delivery-stream"
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "HttpDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# --- IAM Role for Firehose ---
resource "aws_iam_role" "firehose_role" {
  name = "firehose_http_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_http_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = [
          "${aws_cloudwatch_log_group.firehose_log_group.arn}:*"
        ]
      }
    ]
  })
}

# --- Kinesis Firehose Delivery Stream ---
resource "aws_kinesis_firehose_delivery_stream" "http_delivery_stream" {
  name        = "new-relic-delivery-stream"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url                = var.new_relic_endpoint_url
    name               = "New Relic"
    access_key         = var.new_relic_license_key
    buffering_size     = 5  # MiB
    buffering_interval = 60 # Seconds
    role_arn           = aws_iam_role.firehose_role.arn
    s3_backup_mode     = "FailedDataOnly"

    request_configuration {
      content_encoding = "GZIP"
    }

    # Logging configuration for the HTTP destination
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }
  }

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffering_size     = 5
    buffering_interval = 300
    compression_format = "GZIP"

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }
  }
}

# --- Outputs ---
output "firehose_arn" {
  value = aws_kinesis_firehose_delivery_stream.http_delivery_stream.arn
}

