resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = { Name = "opensearch-subnet" }
}

resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-sg"
  description = "Security group for OpenSearch and Firehose"
  vpc_id      = aws_vpc.main.id

  # Allow Firehose to communicate with OpenSearch on 443
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 2. OpenSearch Domain
resource "aws_opensearch_domain" "dest" {
  domain_name    = "tf-firehose-os-domain"
  engine_version = "OpenSearch_2.11"

  cluster_config {
    instance_type = "t3.small.search"
  }

  vpc_options {
    subnet_ids         = [aws_subnet.private.id]
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "es:*"
        Principal = { AWS = "*" }
        Effect    = "Allow"
        Resource  = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/tf-firehose-os-domain/*"
      }
    ]
  })
}

# 3. S3 Bucket for Failed Deliveries
resource "aws_s3_bucket" "firehose_backup" {
  bucket_prefix = "firehose-os-backup-"
}

# 4. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_opensearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name   = "firehose_delivery_policy"
  role   = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeDomain",
          "es:DescribeDomains",
          "es:DescribeDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = [
          aws_opensearch_domain.dest.arn,
          "${aws_opensearch_domain.dest.arn}/*"
        ]
      },
      {
        # Firehose needs these to manage ENIs in the VPC
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

# 5. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "os_stream" {
  name        = "kinesis-firehose-to-opensearch"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn     = aws_opensearch_domain.dest.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "logs"
    type_name      = "_doc"
    buffering_size = 5

    vpc_config {
      subnet_ids         = [aws_subnet.private.id]
      security_group_ids = [aws_security_group.opensearch_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled = false
    }
  }

  # Ensure OpenSearch is ready before creating Firehose
  depends_on = [aws_opensearch_domain.dest]
}

# Data sources for account details
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

