resource "aws_kinesis_stream" "output_stream" {
  name             = "kinesis-analytics-output-stream"
  shard_count      = 1
  retention_period = 24
}

# 3. IAM Role for Kinesis Analytics
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-application-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 4. IAM Policy to allow reading from Input and writing to Output
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-permissions"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.input_stream.arn
      },
      {
        Action = [
          "kinesis:DescribeStream",
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.output_stream.arn
      }
    ]
  })
}

# 5. Kinesis Data Analytics V2 Application (SQL)
resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "basic-sql-analytics-app"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_row_path = "$"
              }
            }
          }

          # Define the columns expected in the JSON input
          record_column {
            name     = "sensor_id"
            sql_type = "VARCHAR(16)"
            mapping  = "$.sensor_id"
          }
          record_column {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temp"
          }
        }

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
        }
      }
    }
  }

  tags = {
    Environment = "Development"
    Application = "SensorDataAnalytics"
  }
}

