}

# 5. IAM Policy for the Role to access Streams and CloudWatch
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream",
          "kinesis:ListShards"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.input_stream.arn
      },
      {
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.output_stream.arn
      },
      {
        Action = [
          "logs:PutLogEvents",
          "logs:DescribeLogGroups",
          "logs:DescribeLogStreams"
        ]
        Effect   = "Allow"
        Resource = "${aws_cloudwatch_log_group.analytics_logs.arn}:*"
      }
    ]
  })
}

# 6. Kinesis Data Analytics V2 SQL Application
resource "aws_kinesisanalyticsv2_application" "sql_application" {
  name                   = "example-sql-app"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    # SQL Application Specific Configuration
    sql_application_configuration {

      # Input Configuration
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_row_path = "$"
              }
            }
          }

          record_encoding = "UTF-8"

          # Define the columns expected from the JSON input
          record_column {
            name     = "sensor_id"
            sql_type = "VARCHAR(16)"
            mapping  = "$.sensor_id"
          }
          record_column {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temperature"
          }
        }

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
        }
      }

      # Output Configuration
      output {
        name = "DESTINATION_SQL_STREAM"

        destination_schema {
          record_format_type = "JSON"
        }

        kinesis_streams_output {
          resource_arn = aws_kinesis_stream.output_stream.arn
        }
      }
    }

    # The SQL Code
    application_code_configuration {
      code_content {
        text_content = <<EOF
          CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
            sensor_id   VARCHAR(16),
            temperature DOUBLE
          );

          CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
          INSERT INTO "DESTINATION_SQL_STREAM"
          SELECT STREAM "sensor_id", "temperature"
          FROM "SOURCE_SQL_STREAM_001"
          WHERE "temperature" > 25.0;
        EOF
      }
      code_content_type = "PLAINTEXT"
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.analytics_log_stream.arn
  }

  tags = {
    Environment = "Development"
    Application = "Analytics"
  }
}

