          "${aws_cloudwatch_log_group.analytics_log_group.arn}:*"
        ]
      }
    ]
  })
}

# 4. Kinesis Data Analytics v2 Application
resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "my-analytics-application"
  runtime_environment    = "SQL-1_0" # Using SQL for a basic example
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"
        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json_mapping_parameters {
                record_row_path = "$"
              }
            }
          }
          record_column {
            name     = "sensor_id"
            sql_type = "VARCHAR(64)"
            mapping  = "$.sensor_id"
          }
          record_column {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temperature"
          }
        }

        # In a real scenario, you would reference a Kinesis Stream ARN here
        # For this basic example, we define the structure without an active source
        kinesis_streams_input {
          resource_arn = "arn:aws:kinesis:us-east-1:123456789012:stream/placeholder-stream"
        }
      }
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.analytics_log_stream.arn
  }

  tags = {
    Environment = "Dev"
    Project     = "TerraformAI-Example"
  }
}

output "application_arn" {
