# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Kendra
resource "aws_iam_role" "kendra_role" {
  name = "kendra-web-crawler-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# 2. IAM Policy for Kendra Index and Secrets Access
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-web-crawler-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["kendra:BatchPutDocument", "kendra:BatchDeleteDocument"]
        Resource = aws_kendra_index.example.arn
      },
      {
        Effect   = "Allow"
        Action   = ["secretsmanager:GetSecretValue"]
        Resource = aws_secretsmanager_secret.proxy_auth.arn
      }
    ]
  })
}

# 3. Kendra Index
resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"
}

# 4. Secrets Manager Secret for Proxy Credentials
resource "aws_secretsmanager_secret" "proxy_auth" {
  name        = "kendra-proxy-credentials"
  description = "Credentials for Kendra Web Crawler Proxy"
}

resource "aws_secretsmanager_secret_version" "proxy_auth_val" {
  secret_id     = aws_secretsmanager_secret.proxy_auth.id
  secret_string = jsonencode({
    username = "proxy_user"
    password = "secure_password123"
  })
}

# 5. Kendra Data Source with Proxy Configuration
resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler-with-proxy"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = ["https://aws.amazon.com"]
          web_crawler_mode = "EVERYTHING"
        }
      }

      # Proxy Configuration block
      proxy_configuration {
        host                   = "proxy.example.com"
        port                   = 8080
        credentials_secret_arn = aws_secretsmanager_secret.proxy_auth.arn
      }
    }
  }

  description = "A web crawler data source that routes traffic through a corporate proxy"
}

