}

provider "aws" {
  region = "us-east-1"
}

# 1. Kendra Index (Developer Edition for cost efficiency in testing)
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  description = "Example index for web crawling"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role_kendra_index.arn
}

# 2. IAM Role for Kendra Index
resource "aws_iam_role" "kendra_index" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Role for Kendra Data Source (Web Crawler)
resource "aws_iam_role" "kendra_ds_role" {
  name = "kendra-webcrawler-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Basic CloudWatch Logs permissions for the data source
resource "aws_iam_role_policy" "kendra_ds_policy" {
  name = "kendra-webcrawler-policy"
  role = aws_iam_role_kendra_ds_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "logs:PutLogEvents"
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "logs:CreateLogStream"
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "logs:CreateLogGroup"
        Resource = "*"
      }
    ]
  })
}

# 4. Kendra Data Source with URL Inclusion and Exclusion Patterns
resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role_kendra_ds_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_urls = ["https://aws.amazon.com/"]
      }

      # Use Regular Expressions to define patterns
      # Inclusion: Only index pages under the 'kendra' path
      url_inclusion_patterns = [
        "https://aws.amazon.com/kendra/.*"
      ]

      # Exclusion: Do not index the pricing page or sub-pages of pricing
      url_exclusion_patterns = [
        "https://aws.amazon.com/kendra/pricing/.*",
        ".*\.pdf$" # Exclude all PDF files
      ]

      crawl_depth = 2
    }
  }

  tags = {
    Environment = "Production"
  }
}

output "kendra_index_id" {
  value = aws_kendra_index.example.id
}

output "kendra_data_source_id" {
  value = aws_kendra_data_source.web_crawler.data_source_id
}

