response:
To create an AWS Kendra Index with Document Metadata Configuration Updates, we need to set up the following:
1.  **IAM Role**: Kendra requires an IAM role with a trust policy allowing `kendra.amazonaws.com` to assume it.
2.  **IAM Policy**: A policy allowing Kendra to output logs to CloudWatch (standard for index health monitoring).
3.  **Kendra Index**: The core resource where we define the edition and the `document_metadata_configuration_updates` block to manage how specific metadata fields are indexed and searched.

Here is the complete Terraform configuration:

```hcl
# AWS Provider configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kendra to assume
resource "aws_iam_role" "kendra_role" {
  name = "example-kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy to allow Kendra to write logs to CloudWatch
resource "aws_iam_role_policy" "kendra_logging_policy" {
  name = "example-kendra-logging-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Kendra Index Resource
resource "aws_kendra_index" "example" {
  name        = "example-index"
  description = "A basic Kendra index with metadata configuration"
  role_arn    = aws_iam_role.kendra_role.arn
  edition     = "DEVELOPER_EDITION"

  # Default Document Metadata Configuration Updates
  # Example: Configuring the '_document_title' system attribute
  document_metadata_configuration_updates {
    name = "_document_title"
    type = "STRING_VALUE"

    relevance {
      importance = 5
      freshness  = false
    }

    search {
      displayable = true
      facetable   = false
      searchable  = true
      sortable    = false
    }
  }

  # Example: Configuring the '_source_uri' system attribute
  document_metadata_configuration_updates {
    name = "_source_uri"
    type = "STRING_VALUE"

    search {
      displayable = true
      facetable   = false
      searchable  = false
      sortable    = false
    }
  }

  tags = {
    Environment = "Development"
  }

  depends_on = [aws_iam_role_policy.kendra_logging_policy]
}

# Output the Index ID
output "kendra_index_id" {
  value       = aws_kendra_index.example.id
  description = "The ID of the Kendra Index"
}
```

