Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the VPC required for the private hosted zone
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Create the Private Route 53 Zone linked to the VPC
resource "aws_route53_zone" "private_zone" {
  name = "internal.example53.com"

  vpc {
    vpc_id = aws_vpc.main.id
  }

  comment = "Private zone for internal traffic"
}

# Create a non-alias Route 53 record within the private zone
resource "aws_route53_record" "example_record" {
  zone_id = aws_route53_zone.private_zone.zone_id
  name    = "web.internal.example53.com"
  type    = "A"
  ttl     = 300
  records = ["10.0.0.10"]
}
```

