response:
To configure an Active-Active (or more commonly, Active-Passive Failover) setup in Route 53 using Terraform, we need to define the hosted zone, health checks for both endpoints, and the DNS records with the specific failover routing policy.

In Route 53, a **Failover** policy specifically uses a `PRIMARY` and `SECONDARY` designation. If you require "Active-Active" in the sense that both are healthy and serving traffic, you would typically use Weighted or Multivalue routing. However, since the request specifically asks for "Failover policies," the following configuration implements the standard Route 53 Failover Routing Policy.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# Health Check for the Primary Endpoint
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "primary-endpoint.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "primary_health_check"
  }
}

# Health Check for the Secondary Endpoint
resource "aws_route53_health_check" "secondary_health_check" {
  fqdn              = "secondary-endpoint.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "secondary_health_check"
  }
}

# Primary DNS Record with Failover Policy
resource "aws_route53_record" "primary_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "service.example.com"
  type    = "A"
  ttl     = "60"

  # The IP address of your primary resource
  records = ["1.1.1.1"]

  set_identifier = "primary-resource"

  failover_routing_policy {
    type = "PRIMARY"
  }

  health_check_id = aws_route53_health_check.primary_health_check.id
}

# Secondary DNS Record with Failover Policy
resource "aws_route53_record" "secondary_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "service.example.com"
  type    = "A"
  ttl     = "60"

  # The IP address of your secondary resource
  records = ["2.2.2.2"]

  set_identifier = "secondary-resource"

  failover_routing_policy {
    type = "SECONDARY"
  }

  health_check_id = aws_route53_health_check.secondary_health_check.id
}
```

