# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Route 53 Hosted Zone (if not already existing)
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# 2. Define the Route 53 Traffic Policy
# This policy routes traffic based on weights between two endpoints.
resource "aws_route53_traffic_policy" "weighted_policy" {
  name     = "weighted-traffic-policy"
  comment  = "Weighted routing policy for high availability"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-11-01"
    RecordType             = "A"
    Endpoints = {
      PrimaryRegion = {
        Type  = "value"
        Value = "1.2.3.4"
      }
      SecondaryRegion = {
        Type  = "value"
        Value = "5.6.7.8"
      }
    }
    Rules = {
      WeightedRule = {
        RuleType = "weighted"
        Items = [
          {
            EndpointReference = "PrimaryRegion"
            Weight            = "80"
          },
          {
            EndpointReference = "SecondaryRegion"
            Weight            = "20"
          }
        ]
      }
    }
    StartRule = "WeightedRule"
  })
}

# 3. Create the Traffic Policy Instance
# This actually creates the DNS record and applies the policy logic.
resource "aws_route53_traffic_policy_instance" "main_instance" {
  name                   = "app" # This results in app.example.com
  traffic_policy_id      = aws_route53_traffic_policy.weighted_policy.id
  traffic_policy_version = aws_route53_traffic_policy.weighted_policy.version
  hosted_zone_id         = aws_route53_zone.main.id
  ttl                    = 300
}

# Output the DNS name of the traffic policy instance
output "dns_name" {
  value = "${aws_route53_traffic_policy_instance.main_instance.name}.${aws_route53_zone.main.name}"
}

