# Variable definition for the EKS Cluster Name
variable "cluster_name" {
  description = "The name of the EKS cluster to be created"
  type        = string
  default     = "terraform-managed-eks"
}

# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# Data sources to retrieve current AWS environment details
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# Data source to fetch default VPC and Subnets for networking
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# IAM Role for the EKS Cluster
resource "aws_iam_role" "eks_cluster_role" {
  name = "${var.cluster_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      },
    ]
  })
}

# Policy Attachment: AmazonEKSClusterPolicy
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# Policy Attachment: AmazonEKSServicePolicy
resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# EKS Cluster Resource
resource "aws_eks_cluster" "main" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster_role.arn

  vpc_config {
    # Utilizing subnet IDs fetched from the data source
    subnet_ids = data.aws_subnets.default.ids
  }

  # Ensure IAM Role permissions are created before and deleted after the EKS Cluster
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # local-exec provisioner to update kubeconfig after cluster creation
  provisioner "local-exec" {
    command = "aws eks update-kubeconfig --name ${self.name} --region ${data.aws_region.current.name}"
  }

  # local-exec provisioner to clean up kubeconfig context upon destruction
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config delete-context arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/${self.name} || true"
  }
}

# Output the EKS Cluster Endpoint
output "cluster_endpoint" {
  value = aws_eks_cluster.main.endpoint
}

# Output the EKS Cluster Status
output "cluster_status" {
  value = aws_eks_cluster.main.status
}

