# --- Variables ---
variable "region" {
  description = "The AWS region to deploy resources into"
  type        = string
  default     = "us-east-1"
}

variable "ecr_repository_name" {
  description = "The name of the ECR repository to fetch the stable image from"
  type        = string
  default     = "my-app-repo"
}

# --- Providers ---
provider "aws" {
  region = var.region
}

# --- Data Sources ---
# Retrieve the current AWS caller identity
data "aws_caller_identity" "current" {}

# Fetch the latest stable ECR image tagged as 'stable'
data "aws_ecr_image" "stable" {
  repository_name = var.ecr_repository_name
  image_tag       = "stable"
}

# Get authentication token for the EKS cluster to configure K8s/Helm providers
data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_name
}

# Supporting data for VPC/Networking (Assumption: using default or existing VPC for EKS)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "public" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# --- Locals ---
locals {
  image_tag      = data.aws_ecr_image.stable.image_tag
  workspace_name = terraform.workspace
  aws_tags = {
    Environment = local.workspace_name
    ManagedBy   = "Terraform"
    Owner       = data.aws_caller_identity.current.arn
  }
}

# --- EKS Module ---
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 20.0"

  cluster_name    = "${local.workspace_name}-cluster"
  cluster_version = "1.30"

  # Networking
  vpc_id     = data.aws_vpc.default.id
  subnet_ids = data.aws_subnets.public.ids

  # Enables public access for simplicity in this example
  cluster_endpoint_public_access = true

  # Node Group Configuration
  eks_managed_node_groups = {
    main = {
      instance_types = ["t3.medium"]
      min_size     = 1
      max_size     = 3
      desired_size = 2

      # Additional IAM policies can be attached here
      iam_role_additional_policies = {
        AmazonSSMManagedInstanceCore = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
      }
    }
  }

  tags = local.aws_tags
}

# --- Kubernetes & Helm Provider Configuration ---
# Configured using the EKS module outputs for seamless communication
provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  cluster_ca_certificate = base64decode(module.eks.cluster_certificate_authority_data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

provider "helm" {
  kubernetes {
    host                   = module.eks.cluster_endpoint
    cluster_ca_certificate = base64decode(module.eks.cluster_certificate_authority_data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}

# --- Outputs ---
output "cluster_endpoint" {
  value = module.eks.cluster_endpoint
}

output "caller_arn" {
  value = data.aws_caller_identity.current.arn
}

output "stable_image_digest" {
  value = data.aws_ecr_image.stable.image_digest
}

