      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks-fargate-profile" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.eks-fargate-profile.name
}

resource "aws_eks_fargate_profile" "kube-system" {
  cluster_name           = aws_eks_cluster.cluster.name
  fargate_profile_name   = "kube-system"
  pod_execution_role_arn = aws_iam_role.eks-fargate-profile.arn

  subnet_ids = [
    aws_subnet.test_eks_1.id,
    aws_subnet.test_eks_2.id
  ]

  selector {
    namespace = "kube-system"
  }

  depends_on = [ aws_iam_role_policy_attachment.eks-fargate-profile ]
}

data "aws_eks_cluster_auth" "eks" {
  name = aws_eks_cluster.cluster.id
}

resource "null_resource" "k8s_patcher" {
  depends_on = [aws_eks_fargate_profile.kube-system]

  triggers = {
    endpoint = aws_eks_cluster.cluster.endpoint
    ca_crt   = base64decode(aws_eks_cluster.cluster.certificate_authority[0].data)
    token    = data.aws_eks_cluster_auth.eks.token
  }

  provisioner "local-exec" {
    command = <<EOH
      cat >/tmp/ca.crt <<EOF
      ${base64decode(aws_eks_cluster.cluster.certificate_authority[0].data)}
      EOF
      kubectl \n        --server="${aws_eks_cluster.cluster.endpoint}" \n        --certificate_authority=/tmp/ca.crt \n        --token="${data.aws_eks_cluster_auth.eks.token}" \n        patch deployment coredns \n        -n kube-system --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]'
      EOH
  }

  lifecycle {
    ignore_changes = [triggers]
  }
}

response:
To create an EKS Fargate profile and manage the transition of `kube-system` workloads (like CoreDNS) to Fargate, we need to configure IAM roles, tagging for network resources, the Fargate profile itself, and a post-provisioning patch step.

### Step-by-Step Approach:
1.  **IAM Role**: Create a role with the trust relationship allowing `eks-fargate-pods.amazonaws.com` to assume it.
2.  **Policy Attachment**: Attach the managed policy `AmazonEKSFargatePodExecutionRolePolicy` to the role.
3.  **Subnet Tagging**: Use `aws_ec2_tag` to ensure the subnets are correctly associated with the EKS cluster (required for Fargate scheduling).
4.  **Fargate Profile**: Define the profile specifically for the `kube-system` namespace.
5.  **CoreDNS Patching**: Use a `null_resource` with a `local-exec` provisioner. CoreDNS on EKS initially has an annotation (`eks.amazonaws.com/compute-type: ec2`) that prevents it from running on Fargate. We will use the cluster's endpoint and auth token to remove this annotation.

```hcl
# Provider and Data Requirements
provider "aws" {
  region = var.region
}

data "aws_eks_cluster" "this" {
  name = var.cluster_name
}

data "aws_eks_cluster_auth" "this" {
  name = var.cluster_name
}

variable "cluster_name" {
  type        = string
  description = "The name of the existing EKS cluster"
}

variable "region" {
  type        = string
  description = "AWS Region"
}

variable "subnet_ids" {
  type        = list(string)
  description = "List of private subnet IDs for the Fargate profile"
}

# 1. IAM Role for EKS Fargate Pod Execution
resource "aws_iam_role" "fargate_pod_execution_role" {
  name = "${var.cluster_name}-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks-fargate-pods.amazonaws.com"
      }
    }]
  })
}

# 2. Attach the AmazonEKSFargatePodExecutionRolePolicy
resource "aws_iam_role_policy_attachment" "fargate_pod_execution_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# 3. Ensure Subnets have the required cluster association tags
resource "aws_ec2_tag" "subnet_cluster_tag" {
  for_each    = toset(var.subnet_ids)
  resource_id = each.value
  key         = "kubernetes.io/cluster/${var.cluster_name}"
  value       = "shared"
}

# 4. EKS Fargate Profile for 'kube-system' namespace
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = var.cluster_name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = var.subnet_ids

  selector {
    namespace = "kube-system"
  }

  depends_on = [
    aws_iam_role_policy_attachment.fargate_pod_execution_policy,
    aws_ec2_tag.subnet_cluster_tag
  ]
}

# 5. Patch CoreDNS to allow it to run on Fargate
# This removes the 'compute-type: ec2' annotation that exists by default
resource "null_resource" "patch_coredns" {
  depends_on = [aws_eks_fargate_profile.kube_system]

  triggers = {
    endpoint = data.aws_eks_cluster.this.endpoint
    ca_cert  = data.aws_eks_cluster.this.certificate_authority[0].data
    token    = data.aws_eks_cluster_auth.this.token
  }

  provisioner "local-exec" {
    command = <<-EOT
      # Create a temporary CA file for kubectl
      echo "${self.triggers.ca_cert}" | base64 -d > cluster_ca.crt

      # Execute the patch using the cluster endpoint and token directly
      kubectl patch deployment coredns \n        -n kube-system \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n        --server=${self.triggers.endpoint} \n        --token=${self.triggers.token} \n        --certificate-authority=cluster_ca.crt

      # Clean up
      rm cluster_ca.crt
    EOT
  }
}
```

