To associate an access policy with an AWS EKS cluster using the EKS Access Management API, we use the `aws_eks_access_policy_association` resource. This requires an existing `aws_eks_access_entry` for the principal. 

The following configuration defines the provider, creates the access entry for the principal, and then associates a specific EKS access policy (e.g., `AmazonEKSViewPolicy`) scoped to a specific namespace.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Define variables for reusability
variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
  default     = "example-cluster"
}

variable "principal_arn" {
  description = "The IAM ARN of the user or role to grant access to"
  type        = string
  default     = "arn:aws:iam::123456789012:role/example-iam-role"
}

variable "target_namespace" {
  description = "The specific namespace to limit access to"
  type        = string
  default     = "example-namespace"
}

# An Access Entry must exist for the principal before associating a policy
resource "aws_eks_access_entry" "example" {
  cluster_name      = var.cluster_name
  principal_arn     = var.principal_arn
  type              = "STANDARD"
}

# Associate the EKS Access Policy with the cluster
resource "aws_eks_access_policy_association" "example" {
  cluster_name  = var.cluster_name
  policy_arn    = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSViewPolicy"
  principal_arn = var.principal_arn

  # Define the scope of the policy
  access_scope {
    type       = "namespace"
    namespaces = [var.target_namespace]
  }

  # Ensure the access entry is created before the association
  depends_on = [aws_eks_access_entry.example]
}
