response:
To set up an Amazon EKS cluster with the required IAM roles and networking infrastructure, we will proceed with the following steps:

1.  **Networking**: Create a VPC and at least two subnets in different Availability Zones (a strict requirement for EKS).
2.  **IAM Role**: Define the `demo_eks` IAM role with a trust policy allowing the EKS service to assume it.
3.  **Policy Attachments**: Attach the `AmazonEKSClusterPolicy` and `AmazonEKSVPCResourceController` managed policies to the role.
4.  **EKS Cluster**: Define the `aws_eks_cluster` resource, ensuring it depends on the IAM policy attachments to prevent authorization errors during creation or deletion.

```hcl
# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for EKS Cluster
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach Required Managed Policies to the IAM Role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo_eks.name
}

resource "aws_iam_role_policy_attachment" "eks_vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.demo_eks.name
}

# 3. Networking Infrastructure (VPC and Subnets)
resource "aws_vpc" "demo_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "demo-eks-vpc"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_subnet" "demo_subnet_1" {
  vpc_id            = aws_vpc.demo_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "demo-eks-subnet-1"
  }
}

resource "aws_subnet" "demo_subnet_2" {
  vpc_id            = aws_vpc.demo_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "demo-eks-subnet-2"
  }
}

# 4. Amazon EKS Cluster
resource "aws_eks_cluster" "demo_eks" {
  name     = "demo_eks"
  role_arn = aws_iam_role.demo_eks.arn

  vpc_config {
    subnet_ids = [
      aws_subnet.demo_subnet_1.id,
      aws_subnet.demo_subnet_2.id
    ]
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete managed EC2 infrastructure (like ENIs).
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_vpc_resource_controller,
  ]
}

# Outputs
output "endpoint" {
  value = aws_eks_cluster.demo_eks.endpoint
}

output "kubeconfig-certificate-authority-data" {
