response:
To provision the requested AWS infrastructure, we need to define the networking components (VPC and Subnets), the IAM Role with the necessary trust relationships and policy attachments, and finally the EKS cluster itself with specific dependency management.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the EKS Cluster
resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "example-vpc"
  }
}

# 2. Create at least two subnets in different Availability Zones (EKS requirement)
data "aws_availability_zones" "available" {}

resource "aws_subnet" "example_1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "example-subnet-1"
  }
}

resource "aws_subnet" "example_2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "example-subnet-2"
  }
}

# 3. Create the IAM Role for the EKS Cluster
resource "aws_iam_role" "example" {
  name = "example"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "eks.amazonaws.com"
        }
      },
    ]
  })
}

# 4. Attach the AmazonEKSClusterPolicy to the IAM Role
resource "aws_iam_role_policy_attachment" "example_AmazonEKSClusterPolicy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example.name
}

# 5. Provision the Amazon EKS Cluster
resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.example.arn

  vpc_config {
    subnet_ids              = [aws_subnet.example_1.id, aws_subnet.example_2.id]
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete the cluster-managed EC2 infrastructure (Security Groups, etc).
  depends_on = [
    aws_iam_role_policy_attachment.example_AmazonEKSClusterPolicy
  ]
}

# Output the EKS Cluster Endpoint
output "endpoint" {
  value = aws_eks_cluster.example.endpoint
}

# Output the kubeconfig certificate-authority-data
output "kubeconfig-certificate-authority-data" {
  value = aws_eks_cluster.example.certificate_authority[0].data
}
```

