To create the requested infrastructure, we need to define the AWS provider and configure the S3 bucket along with its associated security and lifecycle resources. 

Following the modern Terraform AWS provider pattern (v4.0+), S3 features like ACLs, encryption, and public access blocks are managed via separate resources linked to the main bucket. We also include a lifecycle block within the bucket resource to prevent accidental destruction.

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Main S3 Bucket Resource
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"

  # Preventive destruction measure
  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name        = "test-bucket"
    Environment = "Dev"
  }
}

# 2. Ownership Controls (Required for setting ACLs in modern AWS accounts)
resource "aws_s3_bucket_ownership_controls" "test_bucket_ownership" {
  bucket = aws_s3_bucket.test_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Private ACL Configuration
resource "aws_s3_bucket_acl" "test_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.test_bucket_ownership]

  bucket = aws_s3_bucket.test_bucket.id
  acl    = "private"
}

# 4. Server-Side Encryption (AES256)
resource "aws_s3_bucket_server_side_encryption_configuration" "test_bucket_encryption" {
  bucket = aws_s3_bucket.test_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 5. Public Access Block (Restricting all public access)
resource "aws_s3_bucket_public_access_block" "test_bucket_public_access" {
  bucket = aws_s3_bucket.test_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}
```

