provider "aws" {
  region = "us-east-1"
}

# 1. Define the S3 Bucket with prevent_destroy lifecycle protection
resource "aws_s3_bucket" "infra_bucket" {
  bucket = "wellcomecollection-platform-infra"

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name        = "wellcomecollection-platform-infra"
    Environment = "Production"
  }
}

# 2. Configure Ownership Controls (Required for setting ACLs on modern S3 buckets)
resource "aws_s3_bucket_ownership_controls" "infra_bucket_ownership" {
  bucket = aws_s3_bucket.infra_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Set the bucket ACL to private
resource "aws_s3_bucket_acl" "infra_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.infra_bucket_ownership]

  bucket = aws_s3_bucket.infra_bucket.id
  acl    = "private"
}

# 4. Enable Versioning
resource "aws_s3_bucket_versioning" "infra_bucket_versioning" {
  bucket = aws_s3_bucket.infra_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 5. Configure Lifecycle Rules
resource "aws_s3_bucket_lifecycle_configuration" "infra_bucket_lifecycle" {
  bucket = aws_s3_bucket.infra_bucket.id

  # Rule for automatic deletion of objects with 'tmp/' prefix after 30 days
  rule {
    id     = "delete-temporary-objects"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  # Rule for versioning: 
  # - Transition noncurrent versions to STANDARD_IA after 30 days
  # - Permanently delete noncurrent versions after 90 days
  rule {
    id     = "manage-versions"
    status = "Enabled"

    filter {} # Applies to all objects in the bucket

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

