  }
}

# Private ACL for CloudGoat bucket
resource "aws_s3_bucket_acl" "cloudgoat_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_ownership]
  bucket     = aws_s3_bucket.cloudgoat_storage.id
  acl        = "private"
}

# 2. Web Data Storage Bucket
