```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random suffix for the bucket name to ensure global uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket        = "my-unique-bucket-name-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

# 2. Configure Bucket Ownership Controls
# Required to enable ACLs on modern AWS accounts where S3 Object Ownership is 'Bucket owner enforced' by default
resource "aws_s3_bucket_ownership_controls" "ownership" {
  bucket = aws_s3_bucket.my_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Configure Public Access Block
# We must disable these settings to allow a bucket policy with a wildcard Principal ("*")
resource "aws_s3_bucket_public_access_block" "public_access" {
  bucket = aws_s3_bucket.my_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Define the Bucket ACL
resource "aws_s3_bucket_acl" "my_bucket_acl" {
  depends_on = [
    aws_s3_bucket_ownership_controls.ownership,
    aws_s3_bucket_public_access_block.public_access,
  ]

  bucket = aws_s3_bucket.my_bucket.id
  acl    = "private"
}

# 5. Create the Bucket Policy
# This policy allows s3:GetObject for all principals, provided the aws:Referer header matches
resource "aws_s3_bucket_policy" "allow_referer_access" {
  bucket = aws_s3_bucket.my_bucket.id

  # Explicitly wait for public access blocks to be removed before applying the policy
  depends_on = [aws_s3_bucket_public_access_block.public_access]

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowGetObjectWithRefererCondition"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.my_bucket.arn}/*"
