# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create the S3 Bucket
# Note: Bucket names must be globally unique. 
resource "aws_s3_bucket" "mybucket" {
  bucket              = "mybucket"
  object_lock_enabled = true # Must be true to use Object Lock configuration

  tags = {
    Name        = "My Compliance Bucket"
    Environment = "Production"
  }
}

# Enable Versioning
# Object Lock requires versioning to be enabled
resource "aws_s3_bucket_versioning" "mybucket_versioning" {
  bucket = aws_s3_bucket.mybucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Configure Object Lock Retention
# Compliance mode ensures that even the root user cannot delete objects until the period expires
resource "aws_s3_bucket_object_lock_configuration" "mybucket_lock" {
  bucket = aws_s3_bucket.mybucket.id

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 5
    }
  }

  # Ensure versioning is applied before or alongside the lock configuration
  depends_on = [aws_s3_bucket_versioning.mybucket_versioning]
}

# Output the Bucket ARN for reference
output "bucket_arn" {
  value       = aws_s3_bucket.mybucket.arn
  description = "The ARN of the created S3 bucket"
}

