  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_ownership_controls" "main_bucket_oc" {
  bucket = aws_s3_bucket.main_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 4. Set Access Control for the Log Bucket
# Must allow 'log-delivery-write' so the S3 service can write logs to it
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket_oc]

  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

