To set up the requested S3 architecture, we need to define two S3 buckets. The first bucket will be the primary data bucket (set to `private`), and the second will be the log destination bucket (configured with `log-delivery-write` permissions). 

Modern AWS S3 security best practices require explicit Ownership Controls to be defined before legacy ACLs like `log-delivery-write` can be applied. Therefore, the configuration includes `aws_s3_bucket_ownership_controls` for both buckets to allow ACL management.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the Log Bucket (Destination for logs)
resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-tf-app-logs-destination"

  # Force destroy for easier cleanup in dev environments
  force_destroy = true
}

# 2. Define the Main Bucket (Source that generates logs)
resource "aws_s3_bucket" "main_bucket" {
  bucket = "my-tf-app-data-storage"

  force_destroy = true
}

# 3. Ownership Controls (Required to enable ACLs on modern S3 buckets)
resource "aws_s3_bucket_ownership_controls" "log_bucket_oc" {
  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_ownership_controls" "main_bucket_oc" {
  bucket = aws_s3_bucket.main_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 4. Set Access Control for the Log Bucket
# Must allow 'log-delivery-write' so the S3 service can write logs to it
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket_oc]

  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# 5. Set Access Control for the Main Bucket
# Set to 'private' as per requirements
resource "aws_s3_bucket_acl" "main_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.main_bucket_oc]

  bucket = aws_s3_bucket.main_bucket.id
  acl    = "private"
}

# 6. Configure S3 Bucket Logging
# This links the main bucket to the log bucket with a specific prefix
resource "aws_s3_bucket_logging" "main_bucket_logging" {
  bucket = aws_s3_bucket.main_bucket.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "s3-access-logs/"
}

# Output the bucket names for verification
output "main_bucket_name" {
  value = aws_s3_bucket.main_bucket.id
}

output "log_bucket_name" {
  value = aws_s3_bucket.log_bucket.id
}
