extracted_code:
# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Networking Resources
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-fleet-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

# Public Subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "public-subnet"
  }
}

# Private Subnet
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet"
  }
}

# NAT Gateway for Private Subnet Internet Access
resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id
}

# Route Tables
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# 2. Security Group for Instances
resource "aws_security_group" "instance_sg" {
  name        = "fleet-instance-sg"
  description = "Security group for EC2 Fleet"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Fetch Newest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 4. Launch Template
resource "aws_launch_template" "fleet_template" {
  name_prefix   = "fleet-template-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.instance_sg.id]
    subnet_id                   = aws_subnet.private.id
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "FleetInstance"
    }
  }
}

# 5. EC2 Fleet configuration
# This defines 9 total instances: 5 On-Demand and 4 Spot
resource "aws_ec2_fleet" "app_fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.fleet_template.id
      version            = aws_launch_template.fleet_template.latest_version
    }

    # Override can be used to provide multiple instance types for Spot stability
    override {
      instance_type     = "t3.micro"
      availability_zone = "us-east-1a"
    }
    override {
      instance_type     = "t3.small"
      availability_zone = "us-east-1a"
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "spot"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  spot_options {
    allocation_strategy = "capacity-optimized"
  }

  on_demand_options {
    allocation_strategy = "lowest-price"
  }

  # Fleet needs to be able to terminate instances on deletion
  terminate_instances            = true
  terminate_instances_with_expiration = true
}

