resource "aws_elasticache_subnet_group" "memcached_subnet_group" {
  name       = "memcached-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]
}

# 3. Security Group (Port 11211 is default for Memcached)
resource "aws_security_group" "memcached_sg" {
  name        = "memcached-sg"
  description = "Allow Memcached traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 11211
    to_port     = 11211
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restrict to VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Memcached Parameter Group
resource "aws_elasticache_parameter_group" "memcached_params" {
  name   = "memcached-params"
  family = "memcached1.6"

  parameter {
    name  = "max_item_size"
    value = "1048576" # 1MB
  }
}

# 5. ElastiCache Memcached Cluster
resource "aws_elasticache_cluster" "memcached_cluster" {
  cluster_id           = "my-memcached-cluster"
  engine               = "memcached"
  node_type            = "cache.t3.micro" # Economical instance type
  num_cache_nodes      = 2                # Defines the cluster size
  parameter_group_name = aws_elasticache_parameter_group.memcached_params.name
  port                 = 11211
  subnet_group_name    = aws_elasticache_subnet_group.memcached_subnet_group.name
  security_group_ids   = [aws_security_group.memcached_sg.id]
