output "configuration_endpoint" {
  description = "The DNS endpoint of the Memcached cluster"
  value       = aws_elasticache_cluster.memcached_cluster.configuration_endpoint
}

output "cluster_nodes" {
  description = "Individual node details"
  value       = aws_elasticache_cluster.memcached_cluster.cache_nodes
}

