# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the Redis instance
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "redis-vpc"
  }
}

# 2. Create a Subnet
resource "aws_subnet" "redis_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redis-subnet"
  }
}

# 3. Create a Subnet Group for ElastiCache
resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  name       = "my-redis-subnet-group"
  subnet_ids = [aws_subnet.redis_subnet.id]
}

# 4. Create a Security Group to allow Redis traffic
resource "aws_security_group" "redis_sg" {
  name        = "redis-sg"
  description = "Allow inbound Redis traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Create the Redis Replication Group (Instance)
resource "aws_elasticache_replication_group" "redis_instance" {
  replication_group_id          = "my-redis-instance"
  replication_group_description = "Managed Redis instance"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  port                          = 6379
  parameter_group_name          = "default.redis7"

  # Network and Security
  subnet_group_name          = aws_elasticache_subnet_group.redis_subnet_group.name
  security_group_ids         = [aws_security_group.redis_sg.id]

  # Security Settings
  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  # Maintenance/Settings
  apply_immediately          = true
  auto_minor_version_upgrade = true

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Output the Primary Endpoint for the Redis Instance
output "redis_endpoint" {
  value       = aws_elasticache_replication_group.redis_instance.primary_endpoint_address
  description = "The endpoint of the Redis instance"
}

response:
To provide a Redis instance on AWS using Terraform, we need to follow these steps:

1.  **Provider Configuration**: Define the AWS provider and region.
2.  **Networking**: Create a VPC and a Subnet where the Redis instance will reside.
3.  **Security Group**: Create a security group to allow traffic on the default Redis port (6379).
4.  **Subnet Group**: Create an ElastiCache Subnet Group to associate the Redis instance with our specific VPC subnets.
5.  **Redis Instance**: Deploy an `aws_elasticache_replication_group`. While `aws_elasticache_cluster` can be used, `replication_group` is the modern standard for Redis on AWS, supporting features like encryption and multi-AZ failover even for single-node setups.

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the Redis instance
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "redis-vpc"
  }
}

# 2. Create a Subnet
resource "aws_subnet" "redis_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redis-subnet"
  }
}

# 3. Create a Subnet Group for ElastiCache
resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  name       = "my-redis-subnet-group"
  subnet_ids = [aws_subnet.redis_subnet.id]
}

# 4. Create a Security Group to allow Redis traffic
resource "aws_security_group" "redis_sg" {
  name        = "redis-sg"
  description = "Allow inbound Redis traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Create the Redis Replication Group (Instance)
resource "aws_elasticache_replication_group" "redis_instance" {
  replication_group_id          = "my-redis-instance"
  replication_group_description = "Managed Redis instance"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  port                          = 6379
  parameter_group_name          = "default.redis7"

  # Network and Security
  subnet_group_name          = aws_elasticache_subnet_group.redis_subnet_group.name
  security_group_ids         = [aws_security_group.redis_sg.id]

  # Security Settings
  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  # Maintenance/Settings
  apply_immediately          = true
  auto_minor_version_upgrade = true

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Output the Primary Endpoint for the Redis Instance
output "redis_endpoint" {
  value       = aws_elasticache_replication_group.redis_instance.primary_endpoint_address
  description = "The endpoint of the Redis instance"
}
```

