provider "aws" {
  region = "us-east-1"
}

# 1. Create the ElastiCache User with IAM Authentication
# Note: User IDs must be unique and User Names are used for the actual protocol login
resource "aws_elasticache_user" "iam_auth_user" {
  user_id       = "iam-authenticated-user"
  user_name     = "iam_user"
  engine        = "REDIS" # Applicable to Redis 7.0+ or Valkey
  access_string = "on ~* +@all" # Provides full access to keys and commands; restrict as needed for production

  authentication_mode {
    type = "iam"
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# 2. Create an ElastiCache User Group
# ElastiCache requires a user group to be associated with a replication group.
# User groups must always include the "default" user.
resource "aws_elasticache_user_group" "app_user_group" {
  engine        = "REDIS"
  user_group_id = "iam-enabled-group"
  user_ids      = ["default", aws_elasticache_user.iam_auth_user.user_id]

  lifecycle {
    # It's often safer to ignore changes to user_ids if other processes manage group membership
    ignore_changes = []
  }
}

# 3. Define an IAM Policy for the Client
# This policy allows an IAM role/user to authenticate as the ElastiCache user created above.
resource "aws_iam_policy" "elasticache_iam_connection" {
  name        = "ElastiCacheConnectPolicy"
  description = "Allows the holder to connect to ElastiCache using IAM authentication"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "elasticache:Connect"
        Resource = aws_elasticache_user.iam_auth_user.arn
      }
    ]
  })
}

# Example Output: The ARN of the user which is needed for the IAM Resource field
output "elasticache_user_arn" {
  value       = aws_elasticache_user.iam_auth_user.arn
  description = "The ARN of the ElastiCache user to be used in IAM Policies."
}

# Example Output: The User Group ID to be used in the aws_elasticache_replication_group resource
output "user_group_id" {
  value = aws_elasticache_user_group.app_user_group.user_group_id
}

