  skip_final_snapshot = true
}

# 2. Create the Redshift Endpoint Authorization
# This allows the specified AWS account to create an interface VPC endpoint to this cluster
resource "aws_redshift_endpoint_authorization" "example_auth" {
  account            = "012345678910"
  cluster_identifier = aws_redshift_cluster.example_cluster.id

  # Optional: Grant access to specific VPCs if needed, otherwise it's account-wide for the cluster
  # vpc_ids          = ["vpc-xxxxxxxx"]
}

# Output the Cluster Identifier
output "redshift_cluster_id" {
  value = aws_redshift_cluster.example_cluster.id
}
