# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Networking Infrastructure
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-ha-vpc"
  }
}

resource "aws_subnet" "subnet_1a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1a"
  }
}

resource "aws_subnet" "subnet_1b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-1b"
  }
}

# 2. Redshift Subnet Group (Required for VPC deployment)
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-ha-subnet-group"
  subnet_ids = [aws_subnet.subnet_1a.id, aws_subnet.subnet_1b.id]

  tags = {
    Name = "Redshift HA Subnet Group"
  }
}

# 3. Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound access to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to your specific client CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Multi-AZ Redshift Cluster
# Multi-AZ requires RA3 node types and at least 2 nodes.
resource "aws_redshift_cluster" "ha_cluster" {
  cluster_identifier = "ha-redshift-cluster"
  database_name      = "devdb"
  master_username    = "adminuser"
  master_password    = "SecurePassword123!" # In production, use a secret manager or sensitive variable
  node_type          = "ra3.xlplus"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Enable High Availability across Availability Zones
  multi_az = true

  cluster_subnet_group_name    = aws_redshift_subnet_group.main.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]

  # Recommended for production HA
  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sat:07:00-sat:07:30"
  publicly_accessible                 = false
  encrypted                           = true

  tags = {
    Environment = "Production"
    HA          = "True"
  }
}

# Output the cluster endpoint
output "redshift_endpoint" {
  value       = aws_redshift_cluster.ha_cluster.endpoint
  description = "The connection endpoint for the Redshift cluster"
}

