response:
To set up a 2-node Amazon Redshift cluster in `us-east-1` with replication (Cross-Region Snapshot Copy) to `us-east-2`, we need to:
1. Define providers for both the primary (`us-east-1`) and secondary (`us-east-2`) regions.
2. Create a Redshift Snapshot Copy Grant in the destination region (required if the cluster is encrypted, which is a best practice).
3. Configure the primary Redshift cluster with the `snapshot_copy` block to enable automatic transmission of snapshots to the secondary region.

```hcl
# --- Provider Configuration ---

provider "aws" {
  region = "us-east-1"
}

provider "aws" {
  alias  = "secondary"
  region = "us-east-2"
}

# --- IAM Role for Redshift ---

resource "aws_iam_role" "redshift_role" {
  name = "redshift-serverless-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_s3_read" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
  role       = aws_iam_role.redshift_role.name
}

# --- Networking (Optional: Using Default VPC for brevity) ---

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

resource "aws_redshift_subnet_group" "primary" {
  name       = "redshift-subnet-group"
  subnet_ids = [data.aws_subnets.default.ids[0], data.aws_subnets.default.ids[1]]
}

# --- Destination Region Configuration (us-east-2) ---

# A snapshot copy grant is required in the destination region to receive 
# encrypted snapshots from the primary region.
resource "aws_redshift_snapshot_copy_grant" "secondary" {
  provider                 = aws.secondary
  snapshot_copy_grant_name = "replication-grant"
}

# --- Primary Redshift Cluster (us-east-1) ---

resource "aws_redshift_cluster" "primary" {
  cluster_identifier = "redshift-primary-cluster"
  database_name      = "dev"
  master_username    = "adminuser"
  master_password    = "Password123!" # In production, use a secret manager
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  iam_roles          = [aws_iam_role.redshift_role.arn]
  cluster_subnet_group_name = aws_redshift_subnet_group.primary.name

  # Configuration for Replication to us-east-2
  snapshot_copy {
    destination_region = "us-east-2"
    grant_name         = aws_redshift_snapshot_copy_grant.secondary.snapshot_copy_grant_name
    retention_period   = 7 # Retain snapshots in the secondary region for 7 days
  }

  encrypted           = true
  skip_final_snapshot = true

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# --- Output the Cluster Endpoint ---

output "redshift_endpoint" {
  value       = aws_redshift_cluster.primary.endpoint
  description = "The connection endpoint for the Redshift cluster"
}

output "snapshot_copy_destination" {
  value       = aws_redshift_cluster.primary.snapshot_copy[0].destination_region
  description = "The region where snapshots are being replicated"
}
```

