response:
To create a Redshift cluster associated with an IAM role, we follow these steps:
1.  **Define the Provider**: Set up the AWS provider.
2.  **Create the IAM Role**: Define an IAM role with a trust policy that allows the Redshift service (`redshift.amazonaws.com`) to assume the role.
3.  **Attach Policies to the Role**: Attach a managed policy (like `AmazonS3ReadOnlyAccess`) so Redshift can interact with other services.
4.  **Create the Redshift Cluster**: Define the cluster properties (node type, database name, credentials) and link the IAM role using the `iam_roles` attribute.

```hcl
# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Create the IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach a policy to the IAM role (e.g., S3 Read Only access for COPY/UNLOAD)
resource "aws_iam_role_policy_attachment" "redshift_s3_role_attach" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# 3. Create the Redshift Cluster
resource "aws_redshift_cluster" "example_redshift_cluster" {
  cluster_identifier = "terraform-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8Characters1!" # Use a secret manager in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # 4. Associate the IAM Role with the cluster
  iam_roles = [aws_iam_role.redshift_role.arn]

  # Optional settings
  skip_final_snapshot = true
  publicly_accessible = true
}

# Outputs
output "redshift_endpoint" {
  value = aws_redshift_cluster.example_redshift_cluster.endpoint
}

output "iam_role_arn" {
  value = aws_iam_role.redshift_role.arn
}
```

