  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Skip snapshot for demo purposes
  skip_final_snapshot = true
}

# Define the Resource Policy
# Resource policies are commonly used for Redshift Data Sharing or cross-account access.
resource "aws_redshift_resource_policy" "example_policy" {
  resource_arn = aws_redshift_cluster.example_cluster.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "CrossAccountDataSharing"
        Effect = "Allow"
        Principal = {
          AWS = "*" # In a real-world scenario, replace with specific AWS Account ARNs
        }
        Action = [
