# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the Redshift Cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create Subnets
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Create a Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "Redshift subnet group"
  }
}

# Create a Security Group for the Cluster
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust for production security
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create the Redshift Cluster (2 Nodes)
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8CharactersMin!" # Use a secret manager in production
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name    = aws_redshift_subnet_group.main.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  skip_final_snapshot          = true
}

# Create Redshift Endpoint Access
# This allows access to the cluster from a different VPC or specific subnet via a private endpoint
resource "aws_redshift_endpoint_access" "example" {
  endpoint_name      = "example-endpoint"
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
  subnet_group_name  = aws_redshift_subnet_group.main.name

  # The security groups associated with the endpoint
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

# Output the connection details
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "managed_vpc_endpoint" {
  value = aws_redshift_endpoint_access.example.address
}

