# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define the IAM Policy Document for the Lambda Trust Policy
data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

# Create the IAM Role for the Lambda Function
resource "aws_iam_role" "lambda_exec_role" {
  name               = "lambda_execution_role"
  assume_role_policy = data.aws_iam_policy_document.assume_role_policy.json
}

# Attach the basic execution policy to allow logging to CloudWatch
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Generate an archive file (zip) from the source code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# Create the AWS Lambda Function
resource "aws_lambda_function" "nodejs_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "my_nodejs_lambda_function"
  role          = aws_iam_role.lambda_exec_role.arn

  # The handler is defined as "filename.exportedFunction"
  # Since the file is lambda.js, we assume the export is named "handler"
  handler = "lambda.handler"

  # Use the zip file's hash to trigger updates when the code changes
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "nodejs18.x"

  environment {
    variables = {
      NODE_ENV = "production"
    }
  }

  depends_on = [
    aws_iam_role_policy_attachment.lambda_logs
  ]
}

# Output the Lambda Function ARN
output "lambda_function_arn" {
  value       = aws_lambda_function.nodejs_lambda.arn
  description = "The ARN of the generated Lambda function."
}

