To create a Lambda Function URL for an `aws_lambda_function` named "example_lambda", we need to define the AWS provider, an IAM role for the Lambda, the Lambda function itself, and finally the `aws_lambda_function_url` resource. We will also include an `aws_lambda_permission` resource to allow public access if `authorization_type` is set to `NONE`.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create IAM Role for the Lambda function
resource "aws_iam_role" "iam_for_lambda" {
  name = "iam_for_lambda"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# Create the Lambda function named "example_lambda"
# Note: This assumes you have a 'lambda_function_payload.zip' in your directory
resource "aws_lambda_function" "example_lambda" {
  filename      = "lambda_function_payload.zip"
  function_name = "example_lambda"
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      foo = "bar"
    }
  }
}

# Create the Lambda Function URL
resource "aws_lambda_function_url" "example_lambda_url" {
  function_name      = aws_lambda_function.example_lambda.function_name
  authorization_type = "NONE"

  cors {
    allow_credentials = true
    allow_origins     = ["*"]
    allow_methods     = ["*"]
    allow_headers     = ["date", "keep-alive"]
    expose_headers    = ["keep-alive", "date"]
    max_age           = 86400
  }
}

# Add permission to allow public access via the Function URL 
# (Required when authorization_type is NONE)
resource "aws_lambda_permission" "allow_public_url" {
  statement_id           = "AllowExecutionFromURL"
  action                 = "lambda:InvokeFunctionUrl"
  function_name          = aws_lambda_function.example_lambda.function_name
  principal              = "*"
  function_url_auth_type = "NONE"
}

# Output the generated Function URL
output "function_url" {
  description = "The HTTP URL endpoint for the Lambda function"
  value       = aws_lambda_function_url.example_lambda_url.function_url
}
```

