  value = aws_dynamodb_table.example_table.arn
  description = "The ARN of the DynamoDB table"
}

output "lambda_processing_arn" {
  value = aws_lambda_function.example_lambda.arn
  description = "The ARN of the Lambda function processing the DynamoDB stream"
}

response:
To create a Lambda event source mapping from a DynamoDB stream, we need to:
1.  Define a **DynamoDB Table** with streams enabled (`stream_enabled = true`).
2.  Create an **IAM Role** for the Lambda function with the necessary trust policy.
3.  Attach the **AWSLambdaDynamoDBExecutionRole** managed policy to the role so the Lambda can read from the stream.
4.  Define the **Lambda Function** itself.
5.  Create the **Event Source Mapping** resource to link the DynamoDB stream ARN to the Lambda function.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the DynamoDB Table with Streams enabled
resource "aws_dynamodb_table" "example_table" {
  name             = "ExampleTable"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "ID"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "ID"
    type = "S"
  }
}

# 2. Create IAM Role for the Lambda function
resource "aws_iam_role" "iam_for_lambda" {
  name = "dynamodb_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 3. Attach the policy allowing Lambda to read from DynamoDB Streams
resource "aws_iam_role_policy_attachment" "lambda_dynamodb_execution" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaDynamoDBExecutionRole"
}

# Generate a dummy zip file for the Lambda function source code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"
  source {
    content  = "exports.handler = async (event) => { console.log(JSON.stringify(event, null, 2)); };"
    filename = "index.js"
  }
}

# 4. Create the Lambda Function
resource "aws_lambda_function" "example_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "DynamoDBStreamHandler"
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# 5. Create the Event Source Mapping
resource "aws_lambda_event_source_mapping" "example_mapping" {
  event_source_arn  = aws_dynamodb_table.example_table.stream_arn
  function_name     = aws_lambda_function.example_lambda.arn
  starting_position = "LATEST"
  batch_size        = 100 # Adjust based on throughput needs

  # Optional: Filtering to only process certain events (e.g., only "INSERT")
  # filter_criteria {
  #   filter {
  #     pattern = jsonencode({
  #       eventName = ["INSERT"]
  #     })
  #   }
  # }
}

# Outputs
output "dynamodb_table_name" {
  value = aws_dynamodb_table.example_table.name
}

output "lambda_function_arn" {
  value = aws_lambda_function.example_lambda.arn
}

output "event_source_mapping_uuid" {
  value = aws_lambda_event_source_mapping.example_mapping.uuid
}
```

