response:
To create a Lambda function that is invoked every 15 minutes, we need to set up the Lambda function itself, an IAM role for execution, and an Amazon EventBridge (formerly CloudWatch Events) rule to handle the scheduling.

### Step-by-Step Approach:
1.  **IAM Role**: Create an IAM role that allows the Lambda service to assume it and grants basic execution permissions (like writing logs to CloudWatch).
2.  **Lambda Function**: Define the function. For this example, we will generate a small inline Python script and package it using the `archive_file` data source.
3.  **EventBridge Rule**: Create a rule with a `schedule_expression` set to `rate(15 minutes)`.
4.  **EventBridge Target**: Link the EventBridge rule to the Lambda function.
5.  **Lambda Permission**: Explicitly allow EventBridge to invoke the Lambda function, as AWS resources are secure by default and require explicit resource-based policies for cross-service invocation.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lambda
resource "aws_iam_role" "lambda_exec_role" {
  name = "scheduled_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Sid    = ""
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# Attach basic execution policy for CloudWatch Logs
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Package the Lambda Code (Inline Python example)
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"
  source {
    content  = "def lambda_handler(event, context):
    print('Lambda invoked every 15 minutes!')
    return {'status': 'success'}"
    filename = "index.py"
  }
}

# 3. Create the Lambda Function
resource "aws_lambda_function" "scheduled_lambda" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "fifteen_minute_timer_function"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "python3.9"
}

# 4. EventBridge Rule (The Schedule)
resource "aws_cloudwatch_event_rule" "every_fifteen_minutes" {
  name                = "every-fifteen-minutes"
  description         = "Fires every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# 5. EventBridge Target (Linking Rule to Lambda)
resource "aws_cloudwatch_event_target" "invoke_lambda_on_schedule" {
  rule      = aws_cloudwatch_event_rule.every_fifteen_minutes.name
  target_id = "SendToLambda"
  arn       = aws_lambda_function.scheduled_lambda.arn
}

# 6. Lambda Permission (Allow EventBridge to call Lambda)
resource "aws_lambda_permission" "allow_cloudwatch_to_call_lambda" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_fifteen_minutes.arn
}

# Output the Lambda ARN
output "lambda_arn" {
  value       = aws_lambda_function.scheduled_lambda.arn
  description = "The ARN of the scheduled Lambda function"
}
```

