To trigger an AWS Lambda function when an EC2 image (AMI) is created, we use **Amazon EventBridge** (formerly CloudWatch Events). EventBridge monitors the "EC2 Image State Change" event and triggers the Lambda target when the state becomes `available`.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for the Lambda Function
resource "aws_iam_role" "lambda_exec_role" {
  name = "test_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Basic execution policy for Lambda logging
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. The Lambda Function
# Note: This assumes you have a 'lambda_function_payload.zip' in the root directory.
resource "aws_lambda_function" "test_lambda" {
  filename      = "lambda_function_payload.zip"
  function_name = "test_lambda"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      APP_NAME = "AMI-Trigger-Function"
    }
  }
}

# 3. EventBridge Rule
# This rule filters for EC2 AMI state changes where the state becomes 'available' (created successfully)
resource "aws_cloudwatch_event_rule" "ami_creation_rule" {
  name        = "trigger-on-ami-creation"
  description = "Triggers when a new EC2 Image (AMI) enters the available state"

  event_pattern = jsonencode({
    "source": ["aws.ec2"],
    "detail-type": ["EC2 Image State Change"],
    "detail": {
      "state": ["available"]
    }
  })
}

# 4. EventBridge Target
# Links the EventBridge rule to the Lambda function
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.ami_creation_rule.name
  target_id = "InvokeTestLambda"
  arn       = aws_lambda_function.test_lambda.arn
}

# 5. Lambda Permission
# This resource grants EventBridge the permission to invoke the Lambda function
resource "aws_lambda_permission" "allow_eventbridge_to_call_lambda" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.test_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.ami_creation_rule.arn
}
