To create an AWS Lambda function that runs a file named `lambda.js`, we need to define the IAM execution role, the necessary permissions for logging, an archive data source to package the code, and the Lambda function resource itself.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the IAM Role for Lambda execution
resource "aws_iam_role" "iam_for_lambda" {
  name = "my_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach basic execution policy to allow logging to CloudWatch
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create a ZIP archive of the lambda.js file
# This assumes lambda.js exists in the same directory as the Terraform files
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 4. Create the Lambda Function
resource "aws_lambda_function" "test_lambda" {
  filename      = "lambda_function_payload.zip"
  function_name = "my_javascript_lambda"
  role          = aws_iam_role.iam_for_lambda.arn

  # The handler is defined as "filename.export_name"
  # Assuming lambda.js has an 'exports.handler'
  handler       = "lambda.handler"

  # Use the hash of the zip file to trigger updates when the code changes
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "nodejs20.x"

  environment {
    variables = {
      NODE_ENV = "production"
    }
  }

  depends_on = [
    aws_iam_role_policy_attachment.lambda_logs
  ]
}

# Output the Lambda ARN
output "lambda_function_arn" {
  value = aws_lambda_function.test_lambda.arn
}
```

