# Terraform Configuration for AWS CloudWatch Composite Alarm

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. SNS Topic for Alarm Actions
resource "aws_sns_topic" "alarm_notifications" {
  name = "composite-alarm-notifications"
}

# 2. Child Metric Alarm 1: High CPU Utilization
resource "aws_cloudwatch_metric_alarm" "cpu_usage_high" {
  alarm_name          = "HighCPUUtilization"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "300"
  statistic           = "Average"
  threshold           = "80"
  alarm_description   = "This metric monitors ec2 cpu utilization"

  dimensions = {
    InstanceId = "i-0123456789abcdef0"
  }
}

# 3. Child Metric Alarm 2: Status Check Failed
resource "aws_cloudwatch_metric_alarm" "status_check_failed" {
  alarm_name          = "StatusCheckFailed"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "StatusCheckFailed"
  namespace           = "AWS/EC2"
  period              = "60"
  statistic           = "Maximum"
  threshold           = "0"
  alarm_description   = "This metric monitors ec2 status check failures"

  dimensions = {
    InstanceId = "i-0123456789abcdef0"
  }
}

# 4. The Composite Alarm
# This alarm triggers if BOTH the CPU is high AND the Status Check has failed.
resource "aws_cloudwatch_composite_alarm" "example_composite_alarm" {
  alarm_name        = "Composite-HighCPU-And-StatusFailure"
  alarm_description = "Composite alarm monitoring both CPU and system health"

  # The alarm_rule uses the ALARM() function referencing the names of child alarms
  alarm_rule = "ALARM(${aws_cloudwatch_metric_alarm.cpu_usage_high.alarm_name}) AND ALARM(${aws_cloudwatch_metric_alarm.status_check_failed.alarm_name})"

  # Actions to take when the composite alarm enters the ALARM state
  alarm_actions = [aws_sns_topic.alarm_notifications.arn]
  ok_actions    = [aws_sns_topic.alarm_notifications.arn]

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

response:
To create a CloudWatch Composite Alarm, we need to follow these steps:

1.  **Define the Provider**: Set up the AWS provider configuration.
2.  **Create Child Metric Alarms**: A composite alarm monitors the states of other alarms. Therefore, we must first define at least two standard `aws_cloudwatch_metric_alarm` resources (e.g., for High CPU and Status Check failures).
3.  **Define an SNS Topic**: Create an Amazon SNS topic to serve as the notification endpoint when the composite alarm triggers.
4.  **Create the Composite Alarm**: Use the `aws_cloudwatch_composite_alarm` resource. The critical attribute here is `alarm_rule`, which uses a logical expression (AND, OR, NOT) to determine the state of the composite alarm based on the child alarms.

```hcl
# Terraform Configuration for AWS CloudWatch Composite Alarm

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. SNS Topic for Alarm Actions
resource "aws_sns_topic" "alarm_notifications" {
  name = "composite-alarm-notifications"
}

# 2. Child Metric Alarm 1: High CPU Utilization
resource "aws_cloudwatch_metric_alarm" "cpu_usage_high" {
  alarm_name          = "HighCPUUtilization"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "300"
  statistic           = "Average"
  threshold           = "80"
  alarm_description   = "This metric monitors ec2 cpu utilization"

  dimensions = {
    InstanceId = "i-0123456789abcdef0"
  }
}

# 3. Child Metric Alarm 2: Status Check Failed
resource "aws_cloudwatch_metric_alarm" "status_check_failed" {
  alarm_name          = "StatusCheckFailed"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "StatusCheckFailed"
  namespace           = "AWS/EC2"
  period              = "60"
  statistic           = "Maximum"
  threshold           = "0"
  alarm_description   = "This metric monitors ec2 status check failures"

  dimensions = {
    InstanceId = "i-0123456789abcdef0"
  }
}

# 4. The Composite Alarm
# This alarm triggers if BOTH the CPU is high AND the Status Check has failed.
resource "aws_cloudwatch_composite_alarm" "example_composite_alarm" {
  alarm_name        = "Composite-HighCPU-And-StatusFailure"
  alarm_description = "Composite alarm monitoring both CPU and system health"

  # The alarm_rule uses the ALARM() function referencing the names of child alarms
  alarm_rule = "ALARM(${aws_cloudwatch_metric_alarm.cpu_usage_high.alarm_name}) AND ALARM(${aws_cloudwatch_metric_alarm.status_check_failed.alarm_name})"

  # Actions to take when the composite alarm enters the ALARM state
  alarm_actions = [aws_sns_topic.alarm_notifications.arn]
  ok_actions    = [aws_sns_topic.alarm_notifications.arn]

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}
```

