# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a DynamoDB Table
resource "aws_dynamodb_table" "example_table" {
  name           = "UserActivityLogs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PK"
  range_key      = "SK"

  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  attribute {
    name = "GSI1_PK"
    type = "S"
  }

  # Define a Global Secondary Index (GSI)
  global_secondary_index {
    name               = "GSI1"
    hash_key           = "GSI1_PK"
    projection_type    = "ALL"
  }

  tags = {
    Environment = "Production"
    Project     = "Analytics"
  }
}

# 2. Enable Contributor Insights for the base table
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.example_table.name
}

# 3. Enable Contributor Insights for the Global Secondary Index (GSI)
# This represents a "custom setting" where insights are tracked specifically for the index partition keys
resource "aws_dynamodb_contributor_insights" "gsi_insights" {
  table_name = aws_dynamodb_table.example_table.name
  index_name = "GSI1"

  # Ensure the insights resource is created after the table is fully provisioned
  depends_on = [aws_dynamodb_table.example_table]
}

# Output the Table ARN and Insight Statuses
output "dynamodb_table_arn" {
  value = aws_dynamodb_table.example_table.arn
}

output "contributor_insights_table_status" {
  value = aws_dynamodb_contributor_insights.table_insights.id
}

response:
To create a DynamoDB Contributor Insights resource, we first need a DynamoDB table. Contributor Insights can be enabled for the base table itself or for specific Global Secondary Indexes (GSIs). 

Here is the complete Terraform configuration to create a DynamoDB table with a GSI and enable Contributor Insights on both the table and the index.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a DynamoDB Table
resource "aws_dynamodb_table" "example_table" {
  name           = "UserActivityLogs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PK"
  range_key      = "SK"

  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  attribute {
    name = "GSI1_PK"
    type = "S"
  }

  # Define a Global Secondary Index (GSI)
  global_secondary_index {
    name               = "GSI1"
    hash_key           = "GSI1_PK"
    projection_type    = "ALL"
  }

  tags = {
    Environment = "Production"
    Project     = "Analytics"
  }
}

# 2. Enable Contributor Insights for the base table
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.example_table.name
}

# 3. Enable Contributor Insights for the Global Secondary Index (GSI)
# This represents a "custom setting" where insights are tracked specifically for the index partition keys
resource "aws_dynamodb_contributor_insights" "gsi_insights" {
  table_name = aws_dynamodb_table.example_table.name
  index_name = "GSI1"

  # Ensure the insights resource is created after the table is fully provisioned
  depends_on = [aws_dynamodb_table.example_table]
}

# Output the Table ARN and Insight Statuses
output "dynamodb_table_arn" {
  value = aws_dynamodb_table.example_table.arn
}

output "contributor_insights_table_status" {
  value = aws_dynamodb_contributor_insights.table_insights.id
}
```

