# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Kinesis Data Stream
# This will act as the destination for the DynamoDB change data records.
resource "aws_kinesis_stream" "example_dest_stream" {
  name             = "dynamodb-kinesis-replication-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes",
  ]

  tags = {
    Environment = "Production"
    Application = "DynamoDB-Streaming"
  }
}

# 2. Create the DynamoDB Table
# Note: Kinesis streaming captures changes (Inserts, Updates, Deletes) 
# to the table items.
resource "aws_dynamodb_table" "example_table" {
  name           = "UserActivityTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"
  range_key      = "Timestamp"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  tags = {
    Name        = "UserActivityTable"
    Environment = "Production"
  }
}

# 3. Enable Kinesis Streaming Destination
# This resource links the DynamoDB table to the Kinesis stream.
resource "aws_dynamodb_kinesis_streaming_destination" "example" {
  stream_arn = aws_kinesis_stream.example_dest_stream.arn
  table_name = aws_dynamodb_table.example_table.name
}

# Output the ARNs for reference
output "dynamodb_table_arn" {
  value       = aws_dynamodb_table.example_table.arn
  description = "The ARN of the DynamoDB table."
}

output "kinesis_stream_arn" {
  value       = aws_kinesis_stream.example_dest_stream.arn
  description = "The ARN of the Kinesis Data Stream destination."
}

