# Configure the AWS Providers
# The primary provider for the main table resource
provider "aws" {
  region = "us-east-1"
}

# The secondary provider for the replica region (required for certain cross-region operations)
provider "aws" {
  alias  = "replica"
  region = "us-west-2"
}

# DynamoDB Global Table Configuration
resource "aws_dynamodb_table" "global_table" {
  name             = "MyGlobalTable"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "pk"
  range_key        = "sk"

  # Stream must be enabled for Global Tables
  stream_enabled   "true"
  stream_view_type = "NEW_AND_OLD_IMAGES"

  # Attributes definitions
  attribute {
    name = "pk"
    type = "S"
  }

  attribute {
    name = "sk"
    type = "S"
  }

  # Define the replica region
  # This creates the table in the primary region and automatically 
  # replicates it to the specified region.
  replica {
    region_name = "us-west-2"
    # Optional: Enable point-in-time recovery for the replica
    point_in_time_recovery = true
    # Optional: Propagate tags to the replica
    propagate_tags         = true
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the ARN of the primary table
output "table_arn" {
  value       = aws_dynamodb_table.global_table.arn
  description = "The ARN of the DynamoDB Global Table"
}

# Output the Stream ARN (required for some integrations)
output "table_stream_arn" {
  value       = aws_dynamodb_table.global_table.stream_arn
  description = "The ARN of the Table Stream"
}

