response:
To create an AWS DAX (DynamoDB Accelerator) cluster with a node type of `dax.r4.large` and a replication factor of 1, we need to set up several supporting resources:
1.  **IAM Role**: DAX requires a service-linked role or a custom IAM role to interact with DynamoDB and EC2.
2.  **Subnet Group**: DAX clusters must run within a VPC and require a dedicated subnet group.
3.  **Security Group**: To allow traffic to the DAX cluster (typically on port 8111).
4.  **DAX Cluster**: The primary resource.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Data source to fetch existing VPC subnets for the subnet group
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 1. IAM Role for DAX
resource "aws_iam_role" "dax_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy to allow DAX to access DynamoDB
resource "aws_iam_role_policy" "dax_policy" {
  name = "dax-dynamodb-access"
  role = aws_iam_role.dax_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "dynamodb:*"
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

# 2. DAX Subnet Group
resource "aws_dax_subnet_group" "example" {
  name       = "example-dax-subnet-group"
  subnet_ids = data.aws_subnets.default.ids
}

# 3. Security Group for DAX
resource "aws_security_group" "dax_sg" {
  name        = "dax-cluster-sg"
  description = "Allow DAX traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. DAX Cluster Configuration
resource "aws_dax_cluster" "example" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
  replication_factor = 1

  subnet_group_name  = aws_dax_subnet_group.example.name
  security_group_ids = [aws_security_group.dax_sg.id]

  server_side_encryption {
    enabled = true
  }

  tags = {
    Environment = "Production"
    Name        = "DAX-Cluster"
  }
}

# Output the DAX Cluster endpoint
output "dax_endpoint" {
  value       = aws_dax_cluster.example.cluster_address
  description = "The DNS name of the DAX cluster endpoint"
}
```

