  name        = "custom-dax-parameters"
  description = "Custom parameter group for DAX to manage TTL settings"

  # Parameter to define how long a query result remains in the cache (in milliseconds)
  parameters {
    name  = "query-ttl-millis"
    value = "60000" # 1 minute
  }

  # Parameter to define how long a single item remains in the cache (in milliseconds)
  parameters {
    name  = "record-ttl-millis"
    value = "300000" # 5 minutes
  }
}

# Output the name of the parameter group for use in a DAX cluster resource
output "dax_parameter_group_name" {
  value       = aws_dax_parameter_group.example.name
  description = "The name of the DAX parameter group"
}
