  region = "us-east-1"
}

# Create a VPC for the DAX infrastructure
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-custom-vpc"
  }
}

# Create Subnet 1 in Availability Zone A
resource "aws_subnet" "dax_subnet_a" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet-1a"
  }
}

# Create Subnet 2 in Availability Zone B
resource "aws_subnet" "dax_subnet_b" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "dax-subnet-1b"
  }
}

# Create the Custom DAX Subnet Group
resource "aws_dax_subnet_group" "custom_dax_sg" {
  name        = "custom-dax-subnet-group"
  description = "DAX subnet group for high-performance DynamoDB caching"

  # Reference the IDs of the subnets created above
  subnet_ids = [
    aws_subnet.dax_subnet_a.id,
    aws_subnet.dax_subnet_b.id
  ]
}

# Output the Subnet Group Name for reference
