terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a DynamoDB table with On-Demand (Pay-Per-Request) capacity
resource "aws_dynamodb_table" "on_demand_table" {
  name         = "OnDemandUserTable"

  # PAY_PER_REQUEST enables On-Demand capacity mode. 
  # PROVISIONED (default) would require read_capacity and write_capacity.
  billing_mode = "PAY_PER_REQUEST"

  # Partition Key (Hash Key)
  hash_key     = "UserId"

  # Sort Key (Range Key) - Optional
  range_key    = "Timestamp"

  # Attributes must be defined for keys used in hash_key or range_key
  attribute {
    name = "UserId"
    type = "S" # S = String, N = Number, B = Binary
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  # Enable Point-in-time Recovery (Best practice)
  point_in_time_recovery {
    enabled = true
  }

  # Server-side encryption using an AWS managed key (default)
  server_side_encryption {
    enabled = true
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

