To create a SageMaker Domain, we need to set up several prerequisite resources. Here is the step-by-step approach:

1.  **VPC Infrastructure**: SageMaker Domains require a VPC and at least one subnet to operate.
2.  **IAM Execution Role**: The domain needs an IAM role that SageMaker assumes to perform actions on your behalf. This role requires a trust policy for the `sagemaker.amazonaws.com` service.
3.  **SageMaker Domain**: We define the domain itself, specifying the authentication mode (IAM or SSO), the VPC/Subnet configuration, and the default user settings (which includes the execution role created in the previous step).

```hcl
# --- Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Network Infrastructure ---
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "sagemaker_subnet" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "sagemaker-subnet"
  }
}

# --- IAM Role for SageMaker ---
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-domain-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "sagemaker.amazonaws.com"
      }
    }]
  })
}

# Attach the standard AmazonSageMakerFullAccess policy
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# --- SageMaker Domain ---
resource "aws_sagemaker_domain" "example" {
  domain_name = "my-sagemaker-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    # Configure default apps (JupyterServer, KernelGateway)
    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "system" # Default instance type
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  # Use PublicInternetOnly for easy access, or VpcOnly for restricted environments
  app_network_access_type = "PublicInternetOnly"

  tags = {
    Environment = "Development"
  }
}

# --- Outputs ---
output "sagemaker_domain_id" {
  value       = aws_sagemaker_domain.example.id
  description = "The ID of the SageMaker Domain"
}

output "sagemaker_domain_url" {
  value       = aws_sagemaker_domain.example.url
  description = "The URL for the SageMaker Domain"
}
