response:
To create a SageMaker User Profile, we need to ensure that a SageMaker Domain exists first, as user profiles are children of a domain. The process involves:
1.  **IAM Role Creation**: Defining an execution role that SageMaker assumes to perform actions on your behalf.
2.  **Networking**: Setting up a VPC and subnet (required for the Domain).
3.  **SageMaker Domain**: Creating the primary environment container.
4.  **SageMaker User Profile**: Defining the specific user profile linked to that domain.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for SageMaker execution
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-user-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach AmazonSageMakerFullAccess policy to the role
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 2. Networking components required for the SageMaker Domain
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "sagemaker_subnet" {
  vpc_id     = aws_vpc.sagemaker_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "sagemaker-subnet"
  }
}

# 3. Create the SageMaker Domain
# A User Profile must belong to a Domain.
resource "aws_sagemaker_domain" "example_domain" {
  domain_name = "ml-development-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "system"
      }
    }
  }
}

# 4. Create the SageMaker User Profile
resource "aws_sagemaker_user_profile" "example_user" {
  domain_id         = aws_sagemaker_domain.example_domain.id
  user_profile_name = "jdoe-data-scientist"

  user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    canvas_app_settings {
      identity_provider_oauth_settings {
        data_source_name = "Salesforce"
        status           = "DISABLED"
      }
    }

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type       = "system"
        sagemaker_image_arn = "arn:aws:sagemaker:us-east-1:081325390131:image/jupyter-server-3"
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  tags = {
    Environment = "Development"
    User        = "JohnDoe"
  }
}

# Output the User Profile ARN
output "sagemaker_user_profile_arn" {
  value       = aws_sagemaker_user_profile.example_user.arn
  description = "The ARN of the created SageMaker User Profile"
