response:
To create an AWS SageMaker Notebook Instance, we need to define the notebook resource itself and an IAM execution role that allows SageMaker to perform actions on your behalf.

Here is the step-by-step Terraform configuration:

1.  **IAM Role**: Create an IAM role with a trust policy that allows the `sagemaker.amazonaws.com` service to assume it.
2.  **IAM Policy Attachment**: Attach the managed policy `AmazonSageMakerFullAccess` to the role so the notebook has the necessary permissions.
3.  **SageMaker Notebook Instance**: Define the instance resource, specifying the `ml.t2.medium` instance type and the IAM role ARN.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the IAM Role for SageMaker
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker_notebook_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach the AmazonSageMakerFullAccess policy to the role
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. Create the SageMaker Notebook Instance
resource "aws_sagemaker_notebook_instance" "notebook" {
  name          = "my-sagemaker-notebook"
  role_arn      = aws_iam_role.sagemaker_execution_role.arn
  instance_type = "ml.t2.medium"

  tags = {
    Name = "SageMakerNotebookInstance"
    Environment = "Development"
  }
}

# Output the Notebook URL
output "notebook_url" {
  value       = "https://${aws_sagemaker_notebook_instance.notebook.name}.notebook.${data.aws_region.current.name}.sagemaker.aws/"
  description = "The URL of the SageMaker Notebook Instance"
}

data "aws_region" "current" {}
```

