# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for SageMaker Execution
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-endpoint-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach SageMaker Full Access Policy (Standard practice, though least-privilege is recommended for production)
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 2. SageMaker Model
# This defines the container image and the specific model data to be used
resource "aws_sagemaker_model" "example_model" {
  name               = "example-ml-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    # Example using a pre-built Scikit-learn image; replace with your ECR image URI
    image = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"

    # Optional: Link to model artifacts in S3
    # model_data_url = "s3://my-bucket/model-artifacts/model.tar.gz"
  }
}

# 3. SageMaker Endpoint Configuration
# This defines how the model should be served (instance types, counts, etc.)
resource "aws_sagemaker_endpoint_configuration" "example_endpoint_config" {
  name = "example-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = aws_sagemaker_model.example_model.name
    initial_instance_count = 1
    instance_type          = "ml.t2.medium" # Low-cost instance for demonstration
    initial_variant_weight = 1.0
  }

  tags = {
    Environment = "Development"
    ManagedBy   = "Terraform"
  }
}

# Optional: Output the Endpoint Configuration Name
output "endpoint_config_name" {
  value       = aws_sagemaker_endpoint_configuration.example_endpoint_config.name
  description = "The name of the SageMaker endpoint configuration"
}

