# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create an IAM Role for the Lambda function
resource "aws_iam_role" "lambda_exec_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# Attach the basic execution policy to the IAM role (allows logging to CloudWatch)
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Define the source code and package it into a ZIP file
# We map the logic from 'lambda.js' into 'index.js' as requested
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"

  source {
    content  = <<EOF
exports.handler = async (event) => {
    console.log("Event: ", JSON.stringify(event, null, 2));
    const response = {
        statusCode: 200,
        body: JSON.stringify('Hello from Terraform Lambda!'),
    };
    return response;
};
EOF
    filename = "index.js"
  }
}

# Create the Lambda Function
resource "aws_lambda_function" "nodejs_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "my_nodejs_lambda_function"
  role          = aws_iam_role.lambda_exec_role.arn

  # The handler is 'index.handler' because the file is 'index.js' 
  # and the exported function is 'handler'
  handler       = "index.handler"

  # Package hash ensures the function updates when code changes
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "nodejs18.x"

  environment {
    variables = {
      SOURCE_FILE = "lambda.js"
    }
  }

  depends_on = [
    aws_iam_role_policy_attachment.lambda_logs
  ]
}

# Output the Lambda Function ARN
output "lambda_function_arn" {
  value       = aws_lambda_function.nodejs_lambda.arn
  description = "The ARN of the created Lambda function."
}

