  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Local variable for Availability Zones
locals {
  azs = ["us-east-1a", "us-east-1b"]
}

# Create two subnets in different AZs
resource "aws_subnet" "subnets" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = local.azs[count.index]

  tags = {
    Name = "subnet-${local.azs[count.index]}"
  }
}

# Create EC2 Instances
resource "aws_instance" "web_servers" {
  count         = 2
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnets[count.index].id

  tags = {
    Name = "instance-${local.azs[count.index]}"
  }
}

# Create 50 GB EBS Volumes
resource "aws_ebs_volume" "data_volumes" {
  count             = 2
  availability_zone = local.azs[count.index]
  size              = 50

  tags = {
    Name = "ebs-volume-${local.azs[count.index]}"
  }
}

# Attach EBS Volumes to Instances
resource "aws_volume_attachment" "ebs_att" {
  count       = 2
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.data_volumes[count.index].id
  instance_id = aws_instance.web_servers[count.index].id
