# Terraform configuration to deploy Amazon ElastiCache (Redis) 
# as a caching layer to reduce database calls.

provider "aws" {
  region = "us-east-1"
}

# 1. Define Networking (VPC and Subnet)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "cache-vpc"
  }
}

resource "aws_subnet" "cache_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "cache-subnet"
  }
}

# 2. Security Group to allow application access to Redis
resource "aws_security_group" "redis_sg" {
  name        = "redis-access"
  description = "Allow inbound traffic to Redis"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = "cache-subnet-group"
  subnet_ids = [aws_subnet.cache_subnet.id]
}

# 4. Redis Cluster (Single Node for Caching)
resource "aws_elasticache_cluster" "db_cache" {
  cluster_id           = "app-cache-layer"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379
  subnet_group_name    = aws_elasticache_subnet_group.main.name
  security_group_ids   = [aws_security_group.redis_sg.id]

  tags = {
    Environment = "production"
    Purpose     = "Reduce DB Calls"
  }
}

# Output the endpoint for the application to connect to
output "redis_endpoint" {
  value       = aws_elasticache_cluster.db_cache.cache_nodes[0].address
  description = "The DNS name of the cache cluster"
}

response:
To reduce the number of database calls, the most effective architectural pattern is implementing a **Caching Layer**. By using an in-memory data store like **Amazon ElastiCache for Redis**, frequently accessed data is served from memory rather than querying the primary disk-based database. This significantly reduces latency and the overall load (I/O) on the backend database.

### Step-by-Step Approach:
1.  **Networking**: Define a VPC and Subnets where the cache will reside.
2.  **Security**: Configure a Security Group to allow traffic on the default Redis port (6379) from the application tier.
3.  **Subnet Group**: Create an ElastiCache Subnet Group to define which subnets the cluster can use.
4.  **Cache Instance**: Provision the `aws_elasticache_cluster` using the Redis engine.

```hcl
# Terraform configuration to deploy Amazon ElastiCache (Redis) 
# as a caching layer to reduce database calls.

provider "aws" {
  region = "us-east-1"
}

# 1. Define Networking (VPC and Subnet)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "cache-vpc"
  }
}

resource "aws_subnet" "cache_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "cache-subnet"
  }
}

# 2. Security Group to allow application access to Redis
resource "aws_security_group" "redis_sg" {
  name        = "redis-access"
  description = "Allow inbound traffic to Redis"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = "cache-subnet-group"
  subnet_ids = [aws_subnet.cache_subnet.id]
}

# 4. Redis Cluster (Single Node for Caching)
resource "aws_elasticache_cluster" "db_cache" {
  cluster_id           = "app-cache-layer"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379
