To authenticate an Amazon ElastiCache (Redis) user with IAM, we need to perform several steps:
1. Define the `aws_elasticache_user` with the `authentication_mode` set to `iam`.
2. Assign this user to an `aws_elasticache_user_group`.
3. Create an IAM policy that grants the `elasticache:Connect` permission, targeting the specific user resource ARN.
4. Attach the user group to an ElastiCache replication group (ensure the engine version is 7.0 or higher and Transit Encryption is enabled).

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the ElastiCache User with IAM authentication
# Redis engine version 7.0+ is required for IAM authentication.
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-authenticated-user"
  user_name     = "iam_user_01" # This name is used in the connection string
  engine        = "REDIS"
  access_string = "on ~* +@all" # Adjust permissions as per security requirements

  authentication_mode {
    type = "iam"
  }
}

# 2. Create a User Group and associate the IAM user
# User groups must always include the 'default' user.
resource "aws_elasticache_user_group" "example_group" {
  engine        = "REDIS"
  user_group_id = "iam-user-group"
  user_ids      = ["default", aws_elasticache_user.iam_user.user_id]

  # Lifecycle block recommended because user_ids is a set and can trigger updates
  lifecycle {
    ignore_changes = [user_ids]
  }
}

# 3. Define the IAM Policy to allow connection
# The principal (User/Role) using this policy can then authenticate as 'iam_user_01'
resource "aws_iam_policy" "elasticache_iam_auth" {
  name        = "ElastiCacheConnectPolicy"
  path        = "/"
  description = "Allows IAM role/user to connect to ElastiCache using IAM credentials"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "elasticache:Connect"
        Resource = [aws_elasticache_user.iam_user.arn]
      }
    ]
  })
}

# 4. Create an ElastiCache Replication Group configured for IAM Auth
# Transit encryption (TLS) must be enabled to use IAM authentication.
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "iam-auth-cluster"
  description                = "Redis cluster with IAM Authentication"
  node_type                  = "cache.t3.medium"
  num_cache_clusters         = 1
  port                       = 6379
  engine                     = "redis"
  engine_version             = "7.0"
  parameter_group_name       = "default.redis7"

  # Link the User Group created above
  user_group_ids             = [aws_elasticache_user_group.example_group.user_group_id]

  # Security requirements for IAM Auth
  transit_encryption_enabled = true
  at_rest_encryption_enabled  = true

  apply_immediately = true
}

# Example IAM Role to test authentication
resource "aws_iam_role" "app_role" {
  name = "example-app-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

# Attach the connect policy to the role
resource "aws_iam_role_policy_attachment" "attach_connect" {
  role       = aws_iam_role.app_role.name
  policy_arn = aws_iam_policy.elasticache_iam_auth.arn
}

output "elasticache_user_arn" {
  value = aws_elasticache_user.iam_user.arn
}

output "configuration_endpoint" {
  value = aws_elasticache_replication_group.example.configuration_endpoint_address
}
