# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# 2. Get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# 3. Create 3 Subnets (MSK requires one subnet per broker node across different AZs for high availability)
resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# 4. Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for Kafka"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rule for Kafka (Plaintext: 9092, TLS: 9094)
  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Inbound rule for Zookeeper
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. MSK Configuration (Optional but recommended for custom settings)
resource "aws_msk_configuration" "msk_config" {
  kafka_versions = ["3.5.1"]
  name           = "msk-configuration"

  server_properties = <<PROPERTIES
auto.create.topics.enable = true
delete.topic.enable = true
PROPERTIES
}

# 6. MSK Cluster Resource
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster-3-nodes"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnets[0].id,
      aws_subnet.msk_subnets[1].id,
      aws_subnet.msk_subnets[2].id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# 7. CloudWatch Log Group for MSK Logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "msk-cluster-logs"
}

# Outputs
output "zookeeper_connect_string" {
  value = aws_msk_cluster.msk_cluster.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
}

