To create a managed Amazon MSK (Managed Streaming for Apache Kafka) cluster with 3 broker nodes in `us-east-1`, we need to set up the supporting networking infrastructure (VPC, Subnets, and Security Groups) as MSK requires brokers to be distributed across subnets in different Availability Zones.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Get available Availability Zones in the region
data "aws_availability_zones" "available" {
  state = "available"
}

# Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 Subnets (one for each broker node in a different AZ)
resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group for MSK to allow internal traffic
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# KMS Key for encrypting data at rest
resource "aws_kms_key" "msk_kms_key" {
  description = "KMS key for MSK cluster encryption"
}

# Managed MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-3-nodes"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    # MSK requires at least 2 subnets; providing 3 for 3 brokers in 3 AZs
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn

    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Environment = "production"
  }
}

# CloudWatch Log Group for MSK Logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "msk-broker-logs"
}

# Output the Bootstrap Brokers
output "bootstrap_brokers_tls" {
  description = "TLS connection host:port pairs"
  value       = aws_msk_cluster.example.bootstrap_brokers_tls
}
