To create a managed MSK (Amazon Managed Streaming for Apache Kafka) cluster in `us-east-2` with 3 broker nodes, we need to set up a VPC with three subnets across three availability zones, a security group, and the MSK cluster resource itself.

### Thought Process:
1.  **Provider Setup**: Configure the AWS provider for the `us-east-2` region.
2.  **Network Infrastructure**: MSK requires subnets in multiple Availability Zones. We will create a VPC and 3 private subnets (one for each broker) to ensure high availability.
3.  **Security Group**: Define a security group that allows traffic on standard Kafka ports (e.g., 9092 for Plaintext, 9094 for TLS).
4.  **KMS Key**: Create a KMS key for disk encryption at rest, which is a best practice for MSK.
5.  **MSK Cluster**: Define the `aws_msk_cluster` resource.
    *   Set `number_of_broker_nodes` to 3.
    *   Map the 3 subnets to the `broker_node_group_info`.
    *   Choose a standard Kafka version and instance type (e.g., `kafka.m5.large`).

```hcl
# --- Terraform Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-2"
}

# --- Networking ---
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# --- Security Group ---
resource "aws_security_group" "msk_sg" {
  name        = "msk-cluster-sg"
  description = "Allow Kafka traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    description = "Kafka Plaintext"
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  ingress {
    description = "Kafka TLS"
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Encryption Key ---
resource "aws_kms_key" "msk_kms" {
  description = "KMS key for MSK encryption"
}

# --- MSK Cluster ---
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "managed-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

