response:
To create a managed Amazon MSK (Managed Streaming for Kafka) cluster in `us-east-1` with logging enabled to an S3 bucket, we need to set up several resources:
1.  **VPC and Networking**: MSK requires subnets in at least two different Availability Zones.
2.  **S3 Bucket**: To store the Kafka broker logs.
3.  **Security Group**: To allow traffic within the VPC for Kafka brokers.
4.  **MSK Cluster**: The core resource configured with the `logging_info` block pointing to the S3 bucket.

```hcl
# Provider configuration for AWS in us-east-1
provider "aws" {
  region = "us-east-1"
}

# 1. Networking Infrastructure
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-2"
  }
}

# 2. Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow Kafka traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. S3 Bucket for MSK Logging
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket        = "msk-broker-logs-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "aws_s3_bucket_public_access_block" "msk_logs_access" {
  bucket = aws_s3_bucket.msk_logs_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 4. Managed MSK Cluster
resource "aws_msk_cluster" "example_msk" {
  cluster_name           = "msk-logging-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type = "kafka.t3.small"
    client_subnets = [
      aws_subnet.msk_subnet_az1.id,
      aws_subnet.msk_subnet_az2.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 10
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.id
        prefix  = "logs/msk-cluster-"
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# Outputs
output "zookeeper_connect_string" {
  value = aws_msk_cluster.example_msk.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.example_msk.bootstrap_brokers_tls
}

output "s3_logging_bucket" {
  value = aws_s3_bucket.msk_logs_bucket.id
}
