extracted_code:
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure (VPC, Subnets, Security Group)
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "msk-vpc" }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = { Name = "msk-subnet-${count.index}" }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-cluster-sg"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 2. S3 Bucket for Log Storage (Firehose Destination)
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket_prefix = "msk-broker-logs-"
  force_destroy = true
}

# 3. IAM Role and Policy for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "msk_firehose_logging_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_access"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.msk_logs_bucket.arn,
          "${aws_s3_bucket.msk_logs_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 4. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_logs_stream" {
  name        = "terraform-msk-broker-logs"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
  }
}

# 5. MSK Cluster with Firehose Logging
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-logging-demo"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnets[0].id,
      aws_subnet.msk_subnets[1].id,
      aws_subnet.msk_subnets[2].id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  logging_info {
    broker_logs {
      firehose {
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs_stream.name
        enabled         = true
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# Outputs
output "msk_bootstrap_brokers_tls" {
  value       = aws_msk_cluster.example.bootstrap_brokers_tls
  description = "TLS connection host:port pairs"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.msk_logs_bucket.id
}

