To create a serverless Amazon MSK (Managed Streaming for Apache Kafka) cluster, we need to set up the underlying networking infrastructure (VPC, Subnets, and Security Groups) as MSK Serverless requires at least two subnets in different Availability Zones. Additionally, MSK Serverless exclusively uses IAM for client authentication.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# 2. Create Subnets (MSK Serverless requires at least 2 subnets in different AZs)
resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-2"
  }
}

# 3. Create a Security Group for the Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  # Typical port for MSK IAM Authentication is 9098
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Create the MSK Serverless Cluster
resource "aws_msk_serverless_cluster" "msk_serverless" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = [aws_subnet.msk_subnet_az1.id, aws_subnet.msk_subnet_az2.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "Dev"
    Project     = "ServerlessKafka"
  }
}

# Outputs
output "cluster_arn" {
  value       = aws_msk_serverless_cluster.msk_serverless.arn
  description = "The ARN of the MSK Serverless cluster"
}

output "zookeeper_connect_string" {
  value       = "MSK Serverless does not use a Zookeeper connect string; use IAM Auth with the bootstrap brokers."
}
