response:
To create an AWS MSK (Managed Streaming for Kafka) Serverless cluster, we need to set up the underlying networking infrastructure (VPC, Subnets, and Security Groups) and then define the MSK Serverless resource. 

In MSK Serverless, the number of broker nodes is managed automatically by AWS to handle the throughput. However, to ensure high availability and align with the "3 broker nodes" requirement in a serverless context, we will configure the cluster to span **three Availability Zones** by providing three subnets. Note that MSK Serverless only supports **IAM Authentication**.

Here is the complete Terraform configuration:

```hcl
# Configure the Terraform block and AWS Provider
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking Infrastructure ---

# Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Fetch available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create 3 Subnets in different AZs to host the MSK Serverless endpoints
resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group to control traffic to the MSK Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow inbound traffic for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  # MSK Serverless uses IAM authentication on port 9098
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- MSK Serverless Cluster Configuration ---

resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-3-nodes"

  vpc_config {
    subnet_ids         = aws_subnet.msk_subnets[*].id
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# --- Outputs ---

output "cluster_arn" {
  value       = aws_msk_serverless_cluster.example.arn
  description = "The ARN of the MSK Serverless cluster"
}

output "bootstrap_brokers" {
  value       = aws_msk_serverless_cluster.example.cluster_name
  description = "The name of the MSK Serverless cluster"
}
```

