response:
To create a serverless MSK cluster in AWS, we need to set up the underlying networking infrastructure (VPC, subnets, and security groups) because MSK Serverless requires a VPC configuration. Since you requested 3 broker nodes (which translates to 3 Availability Zones for high availability in a serverless context), the configuration below sets up 3 subnets across 3 different AZs in `us-east-1`.

Note: MSK Serverless only supports IAM authentication for clients.

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

# Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Fetch available Availability Zones in us-east-1
data "aws_availability_zones" "available" {
  state = "available"
}

# Create 3 Subnets (one for each "broker" zone)
resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group for the MSK Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow inbound traffic for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka IAM authentication port
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- MSK Serverless Cluster ---

resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = aws_subnet.msk_subnets[*].id
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "production"
    Type        = "Serverless"
  }
}

# Outputs
output "cluster_arn" {
  value = aws_msk_serverless_cluster.example.arn
}

output "bootstrap_brokers" {
  description = "Bootstrap servers for the serverless cluster"
  value       = aws_msk_serverless_cluster.example.cluster_name
}
```

