response:
To create a serverless Amazon MSK (Managed Streaming for Apache Kafka) cluster in the `us-east-2` region, we need to set up the following:
1.  **VPC and Networking**: MSK Serverless requires a VPC with at least two subnets in different Availability Zones.
2.  **Security Groups**: To allow traffic to the MSK cluster (typically on port 9098 for IAM authentication).
3.  **MSK Serverless Cluster**: The core resource, configured with IAM authentication (which is mandatory for serverless MSK).

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-2"
}

# 1. Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# 2. Create two subnets in different Availability Zones
resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-2a"

  tags = {
    Name = "msk-subnet-az1"
  }
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-2b"

  tags = {
    Name = "msk-subnet-az2"
  }
}

# 3. Security Group for MSK (Port 9098 is used for IAM auth in Serverless)
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. MSK Serverless Cluster Configuration
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = [aws_subnet.msk_subnet_az1.id, aws_subnet.msk_subnet_az2.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "Development"
  }
}

# Outputs
output "msk_cluster_arn" {
  value       = aws_msk_serverless_cluster.example.arn
  description = "The ARN of the MSK Serverless cluster"
}

output "bootstrap_brokers" {
  value       = aws_msk_serverless_cluster.example.cluster_name
  description = "The name of the MSK Serverless cluster"
}
```

extracted_code:
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
data "aws_availability_zones" "available" {}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags                 = { Name = "msk-vpc" }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags              = { Name = "msk-subnet-${count.index}" }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  vpc_id      = aws_vpc.msk_vpc.id
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Encryption ---
resource "aws_kms_key" "msk_key" {
  description             = "KMS key for MSK encryption at rest"
  deletion_window_in_days = 7
}

# --- Logging Destinations ---

# 1. CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_cw_logs" {
  name              = "/aws/msk/example-cluster"
  retention_in_days = 7
}

# 2. S3 Bucket for direct MSK logging
resource "aws_s3_bucket" "msk_direct_logs" {
  bucket_prefix = "msk-direct-logs-"
  force_destroy = true
}

# 3. Kinesis Firehose (requires a destination S3 bucket and IAM Role)
resource "aws_s3_bucket" "firehose_dest" {
  bucket_prefix = "msk-firehose-dest-"
  force_destroy = true
}

resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-access"
  role = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = ["s3:AbortMultipartUpload", "s3:GetBucketLocation", "s3:GetObject", "s3:ListBucket", "s3:ListBucketMultipartUploads", "s3:PutObject"]
      Effect = "Allow"
      Resource = [aws_s3_bucket.firehose_dest.arn, "${aws_s3_bucket.firehose_dest.arn}/*"]
    }]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_dest.arn
  }
}

# --- MSK Cluster ---
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-broker-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_cw_logs.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_direct_logs.id
        prefix  = "logs/msk-"
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# --- Outputs ---
output "msk_bootstrap_brokers_tls" {
  value       = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
  description = "TLS connection host:port pairs"
}

output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

