response:
To create an AWS MSK cluster with the specified logging (CloudWatch, S3, and Firehose), encryption, and monitoring requirements, we need to set up the networking infrastructure, the logging destinations, and the MSK cluster resource itself.

The following Terraform configuration includes:
1.  **VPC Infrastructure**: A VPC with three subnets across three Availability Zones to support the 3-node broker requirement.
2.  **Logging Destinations**: A CloudWatch Log Group, an S3 bucket for direct MSK logging, and a Kinesis Firehose delivery stream (which also requires its own S3 bucket and IAM role).
3.  **MSK Cluster**: Configured with 3 broker nodes, encryption at rest using a KMS key, Open Monitoring (Prometheus), and the three specified logging exports.

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
data "aws_availability_zones" "available" {}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags                 = { Name = "msk-vpc" }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags              = { Name = "msk-subnet-${count.index}" }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  vpc_id      = aws_vpc.msk_vpc.id
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Encryption ---
resource "aws_kms_key" "msk_key" {
  description             = "KMS key for MSK encryption at rest"
  deletion_window_in_days = 7
}

# --- Logging Destinations ---

# 1. CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_cw_logs" {
  name              = "/aws/msk/example-cluster"
  retention_in_days = 7
}

# 2. S3 Bucket for direct MSK logging
resource "aws_s3_bucket" "msk_direct_logs" {
  bucket_prefix = "msk-direct-logs-"
  force_destroy = true
}

# 3. Kinesis Firehose (requires a destination S3 bucket and IAM Role)
resource "aws_s3_bucket" "firehose_dest" {
  bucket_prefix = "msk-firehose-dest-"
  force_destroy = true
}

resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-access"
  role = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = ["s3:AbortMultipartUpload", "s3:GetBucketLocation", "s3:GetObject", "s3:ListBucket", "s3:ListBucketMultipartUploads", "s3:PutObject"]
      Effect = "Allow"
      Resource = [aws_s3_bucket.firehose_dest.arn, "${aws_s3_bucket.firehose_dest.arn}/*"]
    }]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_dest.arn
  }
}

# --- MSK Cluster ---
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-broker-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_cw_logs.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_direct_logs.id
        prefix  = "logs/msk-"
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# --- Outputs ---
output "msk_bootstrap_brokers_tls" {
  value       = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
  description = "TLS connection host:port pairs"
}

output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}
```

