      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }
}

# --- S3 Bucket for Plugin ---

resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugins-${data.aws_availability_zones.available.id}"
}

resource "aws_s3_object" "debezium_zip" {
