# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
data "aws_availability_zones" "available" {}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Logging Infrastructure ---

# 1. CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster-logs"
  retention_in_days = 7
}

# 2. S3 Bucket for logs and Plugin
resource "aws_s3_bucket" "msk_storage" {
  bucket_prefix = "msk-infrastructure-storage-"
}

# 3. Kinesis Firehose for logs
resource "aws_iam_role" "firehose_role" {
  name = "msk_firehose_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "terraform-msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_storage.arn
  }
}

# --- MSK Cluster ---
resource "aws_kms_key" "msk_key" {
  description = "KMS Key for MSK encryption at rest"
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-debezium"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_storage.id
        prefix  = "logs/msk-"
      }
    }
  }
}

# --- MSK Connect ---

# Upload the zip file to S3 (assuming file exists locally for this generation)
resource "aws_s3_object" "debezium_plugin_zip" {
  bucket = aws_s3_bucket.msk_storage.id
  key    = "plugins/debezium.zip"
  source = "debezium.zip" # Path to your local debezium.zip
}

# Create MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-source-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_storage.arn
      file_key   = aws_s3_object.debezium_plugin_zip.key
    }
  }
}

# IAM Role for MSK Connect Connector
resource "aws_iam_role" "connector_role" {
  name = "msk_connect_connector_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "kafkaconnect.amazonaws.com" }
    }]
  })
}

# (Add policies for the connector role to access MSK and S3 as needed)
resource "aws_iam_role_policy" "connector_policy" {
  role = aws_iam_role.connector_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# Create MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-mysql-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "change-me"
    "database.port"                  = "3306"
    "database.user"                  = "debezium"
    "database.password"              = "password"
    "database.server.id"             = "184054"
    "database.server.name"           = "dbserver1"
    "database.include.list"          = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
    "database.history.kafka.topic"   = "dbhistory.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.connector_role.arn
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}

