    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "kafkaconnect.amazonaws.com" }
    }]
  })
}

# (Add policies for the connector role to access MSK and S3 as needed)
resource "aws_iam_role_policy" "connector_policy" {
  role = aws_iam_role.connector_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# Create MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-mysql-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "change-me"
    "database.port"                  = "3306"
    "database.user"                  = "debezium"
    "database.password"              = "password"
    "database.server.id"             = "184054"
    "database.server.name"           = "dbserver1"
    "database.include.list"          = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
    "database.history.kafka.topic"   = "dbhistory.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.connector_role.arn
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}
```

