response:
To create a MySQL cluster with 100 GB allocated to each zone, the most robust approach in AWS is to use an **RDS Multi-AZ Deployment**. In this configuration, AWS provisions a primary database instance in one Availability Zone and a synchronous standby instance in a second Availability Zone. By setting the `allocated_storage` to 100 GB and enabling `multi_az`, AWS ensures that 100 GB of storage is provisioned and maintained in each of the two zones.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the MySQL Cluster
resource "aws_vpc" "mysql_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "mysql-cluster-vpc"
  }
}

# 2. Create two Subnets in different Availability Zones (Zones)
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "mysql-subnet-1a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "mysql-subnet-1b"
  }
}

# 3. Create a DB Subnet Group to associate the zones with the RDS instance
resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-main-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "MySQL DB Subnet Group"
  }
}

# 4. Create a Security Group to allow MySQL traffic
resource "aws_security_group" "mysql_sg" {
  name        = "allow_mysql"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.mysql_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Create the MySQL RDS Instance with Multi-AZ (Cluster behavior)
# Setting multi_az = true allocates the storage (100GB) to both the primary and standby zones.
resource "aws_db_instance" "mysql_cluster" {
  identifier           = "my-mysql-cluster"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.medium"
  allocated_storage    = 100
  storage_type         = "gp3"
  db_name              = "maindb"
  username             = "admin"
  password             = "Password123!" # In production, use a secret manager or variable

  # Enabling Multi-AZ provides the high-availability "cluster" across zones
  multi_az             = true

  db_subnet_group_name = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids = [aws_security_group.mysql_sg.id]

  skip_final_snapshot  = true

  tags = {
    Environment = "Dev"
    Project     = "MySQL-MultiAZ"
  }
}

# Output the endpoint for connection
output "mysql_endpoint" {
  value       = aws_db_instance.mysql_cluster.endpoint
  description = "The connection endpoint for the MySQL instance"
}
```

