To create a DynamoDB table using Terraform, we need to define the AWS provider, the table resource itself, and the necessary attributes that will serve as the partition and sort keys. In this example, we'll use `PAY_PER_REQUEST` billing mode (on-demand) to avoid managing throughput units, and define a hash key (`UserId`) and a range key (`GameId`).

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a DynamoDB Table
resource "aws_dynamodb_table" "main_table" {
  name             = "UserGameScores"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "UserId"
  range_key        = "GameId"

  # Attribute definitions (required for keys and indexes)
  # Attribute types: S=String, N=Number, B=Binary
  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "GameId"
    type = "S"
  }

  # Enable Point-In-Time Recovery for backups
  point_in_time_recovery {
    enabled = true
  }

  # Server-side encryption using an AWS managed key by default
  server_side_encryption {
    enabled = true
  }

  tags = {
    Name        = "user-game-scores-table"
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}
