To create a DynamoDB table with Point-in-Time Recovery (PITR) enabled using Terraform, we need to define the `aws_dynamodb_table` resource and specifically include the `point_in_time_recovery` configuration block set to `enabled = true`.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a DynamoDB Table with Point-in-Time Recovery enabled
resource "aws_dynamodb_table" "this" {
  name           = "application-data-table"
  billing_mode   = "PAY_PER_REQUEST" # On-demand scaling
  hash_key       = "UserId"          # Partition key
  range_key      = "Timestamp"       # Sort key

  # Define the attributes used in keys or indexes
  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  # Enable Point-in-Time Recovery (PITR)
  point_in_time_recovery {
    enabled = true
  }

  # Server-side encryption using AWS managed key by default
  server_side_encryption {
    enabled = true
  }

  tags = {
    Name        = "application-data-table"
    Environment = "production"
