response:
To create a DynamoDB Table with replication across multiple regions (Global Tables), we use the `aws_dynamodb_table` resource. For Global Tables (Version 2019.11.21), we must enable `stream_enabled` and set `stream_view_type` to `NEW_AND_OLD_IMAGES`. The `replica` blocks within the resource define the additional regions.

```hcl
# Configure the Terraform providers for the required regions
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Primary region provider
provider "aws" {
  region = "us-west-1"
}

# Secondary region provider (required for Terraform to manage resources in us-west-2)
provider "aws" {
  alias  = "us_west_2"
  region = "us-west-2"
}

# DynamoDB Global Table Resource
resource "aws_dynamodb_table" "global_table" {
  name             = "GlobalApplicationData"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "PK"
  range_key        = "SK"

  # Stream settings are mandatory for Global Tables
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  # Define table schema
  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  # Define the replicas. 
  # Since the main resource is in us-west-1 (via default provider), 
  # we add us-west-2 as a replica.
  replica {
    region_name = "us-west-2"
    # Optional: Enable point-in-time recovery for the replica
    point_in_time_recovery = true
    # Optional: Propagate tags to the replica
    propagate_tags         = true
  }

  # Enable server-side encryption
  server_side_encryption {
    enabled = true
  }

  # Point-in-time recovery for the primary region
  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
    Project     = "GlobalDataStore"
  }
}

# Output the ARN of the table
output "dynamodb_table_arn" {
  value       = aws_dynamodb_table.global_table.arn
  description = "The ARN of the DynamoDB table."
}

# Output the Stream ARN
output "dynamodb_stream_arn" {
  value       = aws_dynamodb_table.global_table.stream_arn
  description = "The Stream ARN of the DynamoDB table."
}
```

