# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the DAX Cluster
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "dax-vpc"
  }
}

# 2. Create a Subnet
resource "aws_subnet" "dax_subnet" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "dax-subnet"
  }
}

# 3. Create a DAX Subnet Group
resource "aws_dax_subnet_group" "main" {
  name       = "dax-subnet-group"
  subnet_ids = [aws_subnet.dax_subnet.id]
}

# 4. Create an IAM Role for DAX
resource "aws_iam_role" "dax_role" {
  name = "DaxServiceRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# 5. Attach policy to allow DAX to access DynamoDB
resource "aws_iam_role_policy" "dax_policy" {
  name = "DaxDynamoDBAccess"
  role = aws_iam_role.dax_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "dynamodb:*"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

# 6. Create a Security Group for the Cluster
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow DAX traffic"
  vpc_id      = aws_vpc.dax_vpc.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.dax_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 7. Create the DAX Cluster
resource "aws_dax_cluster" "main" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.t3.medium"
  replication_factor = 3

  subnet_group_name  = aws_dax_subnet_group.main.name
  security_group_ids = [aws_security_group.dax_sg.id]

  server_side_encryption {
    enabled = true
  }

  maintenance_window = "sun:05:00-sun:06:00"

  tags = {
    Environment = "production"
  }
}

# Output the DAX Cluster Endpoint
output "dax_endpoint" {
  value       = aws_dax_cluster.main.cluster_address
  description = "The configuration endpoint for the DAX cluster"
}

