response:
To create a DynamoDB table with server-side encryption (SSE) enabled, we will define the `aws_dynamodb_table` resource and include the `server_side_encryption` block. 

In this configuration:
1. We define the AWS provider and region.
2. We create the DynamoDB table with a `PAY_PER_REQUEST` billing mode.
3. We define a partition key (Hash Key) named `Id`.
4. We explicitly set `enabled = true` within the `server_side_encryption` block. By default, if `kms_key_arn` is not provided, AWS uses the AWS Owned CMK.

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# DynamoDB Table with Server-Side Encryption
resource "aws_dynamodb_table" "encrypted_table" {
  name             = "secure-data-table"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "Id"

  # Define the attribute for the Hash Key
  attribute {
    name = "Id"
    type = "S"
  }

  # Server-side encryption configuration
  # By default, this enables encryption using an AWS Owned Key (SSE-KMS)
  server_side_encryption {
    enabled     = true
    # To use a specific Customer Managed Key (CMK), provide the kms_key_arn:
    # kms_key_arn = aws_kms_key.my_key.arn
  }

  tags = {
    Name        = "EncryptedTable"
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
