  vpc_id = aws_vpc.main.id
}

response:
To create an AWS VPC with an Egress-Only Internet Gateway, we need to ensure the VPC is configured to support IPv6, as Egress-Only Internet Gateways are specifically designed to allow outbound-only communication for IPv6 traffic while preventing instances from receiving spontaneous inbound connections.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a VPC
# Note: Egress-Only Internet Gateways are for IPv6 traffic, 
# so we must enable IPv6 on the VPC.
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true
  enable_dns_support               = true
  enable_dns_hostnames             = true

  tags = {
    Name = "main-vpc"
  }
}

# Create an Egress-Only Internet Gateway
# This allows outbound IPv6 traffic from the VPC to the internet
# but prevents the internet from initiating a connection to the instances.
resource "aws_egress_only_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-egress-only-igw"
  }
}

# Example Route Table to demonstrate usage
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.main.id
  }

  tags = {
    Name = "private-route-table"
  }
}
```

