response:
To establish a VPC peering connection between two AWS VPCs, we need to follow these steps:
1.  **Define the AWS Provider**: Set up the provider configuration for the target region.
2.  **Create VPC A**: Define the first VPC with a specific CIDR block (e.g., `10.1.0.0/16`).
3.  **Create VPC B**: Define the second VPC with a non-overlapping CIDR block (e.g., `10.2.0.0/16`).
4.  **Create VPC Peering Connection**: Establish a connection resource between VPC A (requester) and VPC B (accepter). Since both are in the same account and region, we can set `auto_accept = true`.
5.  **Configure Routing**: For traffic to flow, we must add routes to the main route tables of both VPCs. VPC A needs a route targeting VPC B's CIDR via the peering connection, and VPC B needs a route targeting VPC A's CIDR via the peering connection.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create VPC A
resource "aws_vpc" "vpc_a" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "VPC-A"
  }
}

# 2. Create VPC B
resource "aws_vpc" "vpc_b" {
  cidr_block           = "10.2.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "VPC-B"
  }
}

# 3. Establish VPC Peering Connection
# Note: auto_accept is set to true as both VPCs are in the same account
resource "aws_vpc_peering_connection" "vpc_a_to_vpc_b" {
  vpc_id        = aws_vpc.vpc_a.id
  peer_vpc_id   = aws_vpc.vpc_b.id
  auto_accept   = true

  tags = {
    Name = "Peering-VPC-A-to-VPC-B"
  }
}

# 4. Create Route in VPC A's Main Route Table to reach VPC B
resource "aws_route" "route_vpc_a_to_vpc_b" {
  route_table_id            = aws_vpc.vpc_a.main_route_table_id
  destination_cidr_block    = aws_vpc.vpc_b.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_a_to_vpc_b.id
}

# 5. Create Route in VPC B's Main Route Table to reach VPC A
resource "aws_route" "route_vpc_b_to_vpc_a" {
  route_table_id            = aws_vpc.vpc_b.main_route_table_id
  destination_cidr_block    = aws_vpc.vpc_a.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_a_to_vpc_b.id
}

# Outputs for verification
output "vpc_a_id" {
  value = aws_vpc.vpc_a.id
}

output "vpc_b_id" {
  value = aws_vpc.vpc_b.id
}

output "peering_connection_id" {
  value = aws_vpc_peering_connection.vpc_a_to_vpc_b.id
}
