response:
To create an AWS infrastructure consisting of a VPC, an Internet Gateway, and a custom route table with a specific route, we follow these steps:

1.  **Define the Provider**: Configure the AWS provider and required version.
2.  **Create the VPC**: Define the primary network container.
3.  **Create the Internet Gateway**: Attach this to the VPC to allow communication between the VPC and the internet.
4.  **Create a Custom Route Table**: Define a routing container associated with the VPC.
5.  **Create a Route**: Add an entry to the route table that directs traffic for a destination CIDR (e.g., `0.0.0.0/0` for all internet traffic) to the Internet Gateway.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Internet Gateway and attach it to the VPC
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 3. Create a custom Route Table
resource "aws_route_table" "custom_rt" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "custom-route-table"
  }
}

# 4. Create a route in the custom route table
# This directs traffic for the specified CIDR block (e.g., 0.0.0.0/0) through the Internet Gateway
resource "aws_route" "internet_access" {
  route_table_id         = aws_route_table.custom_rt.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.igw.id
}
```

