To set up an AWS Neptune cluster with custom parameter groups, we need to define several resources: the networking infrastructure (VPC, Subnets), security groups, the parameter groups themselves (both cluster-level and instance-level), and finally the Neptune cluster and its instances.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the Neptune Cluster
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# 2. Create at least two subnets in different AZs (Neptune requirement)
resource "aws_subnet" "neptune_subnet_a" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "neptune_subnet_b" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 3. Create a DB Subnet Group
resource "aws_neptune_subnet_group" "default" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_a.id, aws_subnet.neptune_subnet_b.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# 4. Create a Security Group to allow access to Neptune (Default port 8182)
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-sg"
  description = "Allow Neptune traffic"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Create a Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_cluster_params" {
  family      = "neptune1.2"
  name        = "custom-cluster-params"
  description = "Custom Neptune cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# 6. Create a Custom Instance Parameter Group
resource "aws_neptune_parameter_group" "custom_instance_params" {
  family      = "neptune1.2"
  name        = "custom-instance-params"
  description = "Custom Neptune instance parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000" # Timeout in milliseconds
  }
}

# 7. Create the Neptune Cluster
resource "aws_neptune_cluster" "default" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  engine_version                      = "1.2.1.0" # Specify your desired engine version
  backup_retention_period             = 5
  preferred_backup_window             = "07:00-09:00"
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = false
  apply_immediately                   = true

  neptune_subnet_group_name           = aws_neptune_subnet_group.default.name
  vpc_security_group_ids              = [aws_security_group.neptune_sg.id]
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_cluster_params.name

  tags = {
    Environment = "Dev"
    Name        = "NeptuneCluster"
  }
}

# 8. Create a Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "instance" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.default.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  apply_immediately  = true

  neptune_parameter_group_name = aws_neptune_parameter_group.custom_instance_params.name

  tags = {
    Name = "NeptuneInstance-1"
  }
}

# Output the endpoint for connectivity
output "neptune_endpoint" {
