  neptune_subnet_group_name = aws_neptune_subnet_group.default.id
}

resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet1" {
  vpc_id     = aws_vpc.example_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.azs.names[0]
}

resource "aws_subnet" "subnet2" {
  vpc_id     = aws_vpc.example_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.azs.names[1]
}
resource "aws_neptune_subnet_group" "default" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
}

response:
To set up an AWS Neptune cluster with a custom parameter group and restricted access to two specific subnets, we need to define the networking layer (VPC and subnets), the security group to control ingress traffic, the Neptune-specific parameter groups, and finally the cluster and its instances.

The following configuration:
1.  Creates a VPC with two subnets in different Availability Zones (required for Neptune).
2.  Defines a **Neptune Cluster Parameter Group** to customize engine behavior.
3.  Defines a **Security Group** that explicitly allows inbound traffic on the default Neptune port (8182) only from the CIDR blocks of the two defined subnets.
4.  Deploys a Neptune Cluster and a Cluster Instance.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# 2. Create two subnets in different AZs
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-b"
  }
}

# 3. Create a Neptune Subnet Group
resource "aws_neptune_subnet_group" "default" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Neptune Subnet Group"
  }
}

# 4. Create a Security Group to restrict access
# Only allows traffic on port 8182 from the two specific subnet CIDRs
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-access-sg"
  description = "Allow access to Neptune from specific subnets"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_a.cidr_block, aws_subnet.subnet_b.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Create a Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_group" {
  family      = "neptune1.2"
  name        = "custom-neptune-cluster-params"
  description = "Custom Neptune cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# 6. Create the Neptune Cluster
resource "aws_neptune_cluster" "default" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_group.name
  neptune_subnet_group_name           = aws_neptune_subnet_group.default.name
  vpc_security_group_ids              = [aws_security_group.neptune_sg.id]
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = true
  apply_immediately                   = true
}

# 7. Create a Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "instance1" {
  count              = 1
  identifier         = "neptune-cluster-demo-instance-${count.index}"
  cluster_identifier = aws_neptune_cluster.default.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  apply_immediately  = true
}

# Output the Neptune Endpoint
output "neptune_endpoint" {
  value       = aws_neptune_cluster.default.endpoint
  description = "The DNS address of the Neptune instance"
}
```

