response:
To set up an AWS Neptune cluster with custom parameter groups, we need to follow these steps:

1.  **Networking**: Neptune must reside in a VPC. We will define a VPC, two subnets in different Availability Zones, and a Neptune Subnet Group.
2.  **Custom Cluster Parameter Group**: This manages settings that apply to the entire cluster (e.g., audit logging).
3.  **Custom Instance Parameter Group**: This manages settings for individual instances (e.g., query timeouts).
4.  **Neptune Cluster**: The primary logical grouping for the database, associated with the custom cluster parameter group.
5.  **Neptune Instance**: The actual compute resource within the cluster, associated with the custom instance parameter group.

Here is the complete Terraform configuration:

```hcl
# Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking Infrastructure ---

# Create a VPC for the Neptune Cluster
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# Create two subnets in different AZs (Neptune requirement)
resource "aws_subnet" "neptune_subnet_a" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "neptune_subnet_b" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Create the Neptune Subnet Group
resource "aws_neptune_subnet_group" "default" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_a.id, aws_subnet.neptune_subnet_b.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# --- Parameter Groups ---

# Custom Cluster Parameter Group (Engine-wide settings)
resource "aws_neptune_cluster_parameter_group" "custom_cluster_pg" {
  family      = "neptune1.2"
  name        = "custom-cluster-pg"
  description = "Custom cluster parameter group for Neptune"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# Custom Instance Parameter Group (Instance-specific settings)
resource "aws_neptune_parameter_group" "custom_instance_pg" {
  family      = "neptune1.2"
  name        = "custom-instance-pg"
  description = "Custom instance parameter group for Neptune"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000" # Timeout in milliseconds
  }
}

# --- Neptune Cluster and Instance ---

# Create the Neptune Cluster
resource "aws_neptune_cluster" "default" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  engine_version                      = "1.2.1.0"
  neptune_subnet_group_name           = aws_neptune_subnet_group.default.name
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_cluster_pg.name
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = false
  storage_encrypted                   = true

  tags = {
    Environment = "Dev"
  }
}

# Create the Neptune Instance within the cluster
resource "aws_neptune_cluster_instance" "instance_1" {
  count              = 1
  identifier         = "neptune-instance-1"
  cluster_identifier = aws_neptune_cluster.default.id
  instance_class     = "db.t3.medium"
  engine             = "neptune"

  # Linking the custom instance parameter group
  neptune_parameter_group_name = aws_neptune_parameter_group.custom_instance_pg.name

  tags = {
    Name = "Neptune Instance 1"
  }
}

# Outputs
output "neptune_endpoint" {
  value       = aws_neptune_cluster.default.endpoint
  description = "The DNS address of the Neptune instance"
}

output "neptune_reader_endpoint" {
  value       = aws_neptune_cluster.default.reader_endpoint
  description = "The reader endpoint for the Neptune cluster"
}
