# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# Create the first Chime Voice Connector with encryption enabled
resource "aws_chime_voice_connector" "vc_primary" {
  name               = "primary-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# Create the second Chime Voice Connector with encryption enabled
resource "aws_chime_voice_connector" "vc_secondary" {
  name               = "secondary-voice-connector"
  require_encryption = true
  aws_region         = "us-west-2"
}

# Group the Voice Connectors together
resource "aws_chime_voice_connector_group" "main_group" {
  name = "main-vc-group"

  # Primary Connector
  connector {
    voice_connector_id = aws_chime_voice_connector.vc_primary.id
    priority           = 1
  }

