  }
}

# 4. Create a Security Group to allow access to Redshift (Port 5439)
resource "aws_security_group" "redshift_access_sg" {
  name        = "redshift-access-sg"
  description = "Allow access to Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

