# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

# Create a VPC for the Redshift Cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create a Subnet
resource "aws_subnet" "redshift_subnet" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet"
  }
}

# Define a Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]

  tags = {
    Environment = "Dev"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow Redshift traffic"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to your IP range
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Redshift Cluster ---

resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8CharactersMin1" # Use variables/secrets in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  cluster_subnet_group_name    = aws_redshift_subnet_group.main.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  skip_final_snapshot          = true
  publicly_accessible          = true
}

# --- Notifications ---

# SNS Topic for Notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-event-notifications"
}

# (Optional) Email Subscription for the SNS Topic
resource "aws_sns_topic_subscription" "email_target" {
  topic_arn = aws_sns_topic.redshift_events.arn
  protocol  = "email"
  endpoint  = "your-email@example.com" # Replace with your email
}

# Redshift Event Subscription
resource "aws_redshift_event_subscription" "example_notifications" {
  name          = "redshift-cluster-event-sub"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  # The source type can be cluster, cluster-parameter-group, cluster-security-group, or cluster-snapshot
  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.example.id]

  # Categories include: availability, backup, configuration, management, monitoring, restoration
  event_categories = [
    "availability",
    "backup",
    "management"
  ]

  severity = "INFO"
  enabled  = true
}

# --- Outputs ---

output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "sns_topic_arn" {
  value = aws_sns_topic.redshift_events.arn
}

