  region = "us-east-1"
}

# 1. Create a Redshift Parameter Group
resource "aws_redshift_parameter_group" "example_params" {
  name   = "example-redshift-params"
  family = "redshift-1.0"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  tags = {
    Environment = "Dev"
  }
}

# 2. Create the Redshift Cluster
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier         = "tf-redshift-cluster"
  database_name              = "dev_db"
