  master_password            = "MustBe8Characters1!" # Use secrets management in production
  node_type                  = "dc2.large"
  cluster_type               = "single-node"
  cluster_parameter_group_name = aws_redshift_parameter_group.example_params.name
  skip_final_snapshot        = true

  tags = {
    Name = "TerraformRedshiftCluster"
  }
}

# 3. Create an SNS Topic for notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-event-notifications"
}

# 4. Create Redshift Event Subscription for the Parameter Group
# This triggers notifications when the parameter group is modified or updated
resource "aws_redshift_event_subscription" "param_group_events" {
  name             = "redshift-parameter-group-event-subscription"
  sns_topic_arn    = aws_sns_topic.redshift_notifications.arn
  source_type      = "cluster-parameter-group"
  source_ids       = [aws_redshift_parameter_group.example_params.id]
