# Terraform Configuration for a Private S3 Bucket

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the S3 Bucket
resource "aws_s3_bucket" "example" {
  bucket = "my-tf-example-bucket-20231027" # Replace with a globally unique name

  tags = {
    Name        = "Example Bucket"
    Environment = "Dev"
    Terraform   = "true"
  }
}

# Manage S3 Bucket Ownership Controls
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.example.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Block all public access to the bucket
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Output the bucket domain name
output "bucket_endpoint" {
  value       = aws_s3_bucket.example.bucket_domain_name
  description = "The domain name of the S3 bucket"
}

response:
To create a standard S3 bucket in AWS using Terraform, we will follow these steps:

1.  **Define the Provider**: Configure the AWS provider and specify the target region.
2.  **Generate a Unique Name**: S3 bucket names must be globally unique. We will use a standard naming convention for this example.
3.  **Define the S3 Bucket Resource**: Create the `aws_s3_bucket` resource.
4.  **Implement Security Best Practices**: Include an ownership control resource and a public access block to ensure the bucket remains private by default, adhering to modern AWS security standards.
5.  **Tagging**: Add metadata tags for easier resource management.

```hcl
# Terraform Configuration for a Private S3 Bucket

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the S3 Bucket
resource "aws_s3_bucket" "example" {
  bucket = "my-tf-example-bucket-20231027" # Replace with a globally unique name

  tags = {
    Name        = "Example Bucket"
    Environment = "Dev"
    Terraform   = "true"
  }
}

# Manage S3 Bucket Ownership Controls
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.example.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Block all public access to the bucket
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Output the bucket domain name
output "bucket_endpoint" {
  value       = aws_s3_bucket.example.bucket_domain_name
  description = "The domain name of the S3 bucket"
}
```

