# Configure the AWS Provider
provider "aws" {
  region = "us-east-1" # You can change this to your preferred region
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "website_images" {
  bucket = "my-unique-website-images-bucket-12345" # Replace with a globally unique name

  tags = {
    Name        = "Website Images"
    Environment = "Production"
  }
}

# 2. Configure Ownership Controls
resource "aws_s3_bucket_ownership_controls" "images_ownership" {
  bucket = aws_s3_bucket.website_images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Disable Block Public Access
# This is required to allow the bucket policy to grant public read access
resource "aws_s3_bucket_public_access_block" "images_public_access" {
  bucket = aws_s3_bucket.website_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Attach a Public Read Policy
# This allows anyone on the internet to view (but not upload/delete) the images
resource "aws_s3_bucket_policy" "public_read_policy" {
  bucket = aws_s3_bucket.website_images.id

  # Ensure public access block is disabled before applying the policy
  depends_on = [aws_s3_bucket_public_access_block.images_public_access]

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_images.arn}/*"
      },
    ]
  })
}

# Output the bucket name and the website URL format
output "bucket_name" {
  value = aws_s3_bucket.website_images.id
}

output "image_url_prefix" {
  value       = "https://${aws_s3_bucket.website_images.bucket_domain_name}/"
  description = "Append your image filename to this URL to view it."
}

response:
To store and serve images for a website on AWS, the most common and cost-effective solution is using an **Amazon S3 (Simple Storage Service)** bucket. 

To ensure the images are viewable on your website, we need to:
1.  **Create the S3 bucket.**
2.  **Configure Ownership Controls** to ensure the bucket owner has full control.
3.  **Disable "Block Public Access" settings**, as website images typically need to be publicly accessible via a URL.
4.  **Attach a Bucket Policy** that allows public "Read" access (`s3:GetObject`) so browsers can fetch and display the images.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1" # You can change this to your preferred region
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "website_images" {
  bucket = "my-unique-website-images-bucket-12345" # Replace with a globally unique name

  tags = {
    Name        = "Website Images"
    Environment = "Production"
  }
}

# 2. Configure Ownership Controls
resource "aws_s3_bucket_ownership_controls" "images_ownership" {
  bucket = aws_s3_bucket.website_images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Disable Block Public Access
# This is required to allow the bucket policy to grant public read access
resource "aws_s3_bucket_public_access_block" "images_public_access" {
  bucket = aws_s3_bucket.website_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Attach a Public Read Policy
# This allows anyone on the internet to view (but not upload/delete) the images
resource "aws_s3_bucket_policy" "public_read_policy" {
  bucket = aws_s3_bucket.website_images.id

  # Ensure public access block is disabled before applying the policy
  depends_on = [aws_s3_bucket_public_access_block.images_public_access]

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_images.arn}/*"
      },
    ]
  })
}

# Output the bucket name and the website URL format
output "bucket_name" {
  value = aws_s3_bucket.website_images.id
}

output "image_url_prefix" {
  value       = "https://${aws_s3_bucket.website_images.bucket_domain_name}/"
  description = "Append your image filename to this URL to view it."
}
```

