  bucket = "my-source-data-bucket-${data.aws_caller_identity.current.account_id}"
}

# 2. Destination S3 Bucket (The bucket to store inventory reports)
resource "aws_s3_bucket" "inventory_dest_bucket" {
  bucket = "my-inventory-reports-bucket-${data.aws_caller_identity.current.account_id}"
}

# 3. Bucket Policy for the destination bucket
# This allows S3 Inventory service to write objects to the destination bucket
resource "aws_s3_bucket_policy" "allow_inventory_writing" {
  bucket = aws_s3_bucket.inventory_dest_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowS3InventoryToWriteReports"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory_dest_bucket.arn}/*"
        Condition = {
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.source_bucket.arn
          }
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

# 4. S3 Bucket Inventory Configuration
resource "aws_s3_bucket_inventory" "weekly_inventory" {
  bucket = aws_s3_bucket.source_bucket.id
  name   = "weekly-inventory-csv"

  # Include only current versions as requested
  included_object_versions = "Current"

  # Schedule the report to run weekly
  schedule {
    frequency = "Weekly"
  }

  # Configure the destination and format (CSV)
  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory_dest_bucket.arn
      prefix     = "reports"
    }
  }

  # Optional: Define which metadata fields to include in the CSV
  optional_fields = [
    "Size",
    "LastModifiedDate",
    "StorageClass",
    "ETag",
    "IsMultipartUpload"
  ]

  # Ensure the policy is applied before the inventory configuration is validated
  depends_on = [aws_s3_bucket_policy.allow_inventory_writing]
}

