  force_destroy = true                  # Allows the bucket to be deleted even if it contains files
}

# Upload the PDF file to the S3 Bucket
resource "aws_s3_object" "pdf_upload" {
  bucket       = aws_s3_bucket.pdf_vault.id
  key          = "test.pdf"          # The name of the file as it will appear in S3
  source       = "assets/test.pdf"   # Path to your local file
  content_type = "application/pdf"   # Sets the correct MIME type for browser viewing

