To store and upload your PDF file to AWS using Terraform, we will follow these steps:

1.  **Define the Provider**: Configure the AWS provider and specify the target region.
2.  **Create an S3 Bucket**: Provision a Simple Storage Service (S3) bucket to act as the storage container for your assets.
3.  **Upload the Object**: Use the `aws_s3_object` resource to reference the local file path `assets/test.pdf` and upload it to the created bucket.
4.  **Handle Updates**: Use the `filemd5()` function to ensure that if the local PDF file is modified, Terraform detects the change and updates the version in S3.

```hcl
# AWS Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change this to your preferred region
}

# Create an S3 Bucket to store the PDF
resource "aws_s3_bucket" "pdf_vault" {
  bucket_prefix = "pdf-assets-storage-" # Creates a unique bucket name starting with this prefix
  force_destroy = true                  # Allows the bucket to be deleted even if it contains files
}

# Upload the PDF file to the S3 Bucket
resource "aws_s3_object" "pdf_upload" {
  bucket       = aws_s3_bucket.pdf_vault.id
  key          = "test.pdf"          # The name of the file as it will appear in S3
  source       = "assets/test.pdf"   # Path to your local file
  content_type = "application/pdf"   # Sets the correct MIME type for browser viewing

  # The etag triggers an update if the file content changes locally
  etag = filemd5("assets/test.pdf")
}

# Output the S3 URI of the uploaded file
output "pdf_s3_uri" {
  value       = "s3://${aws_s3_bucket.pdf_vault.id}/${aws_s3_object.pdf_upload.key}"
  description = "The S3 URI for the uploaded PDF"
}
```

