# Create a Customer Managed KMS Key for encryption
resource "aws_kms_key" "s3_key" {
  description             = "KMS key for S3 bucket encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "s3-encryption-key"
  }
}

# Create an alias for the KMS key to make it easier to identify
resource "aws_kms_alias" "s3_key_alias" {
  name          = "alias/s3-storage-key"
  target_key_id = aws_kms_key.s3_key.key_id
}

# Create the S3 Bucket
resource "aws_s3_bucket" "secure_bucket" {
  bucket = "my-kms-encrypted-storage-bucket-${random_id.suffix.hex}"

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Apply Server-Side Encryption (SSE-KMS) using the defined KMS key
resource "aws_s3_bucket_server_side_encryption_configuration" "secure_bucket_encryption" {
  bucket = aws_s3_bucket.secure_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.s3_key.arn
      sse_algorithm     = "aws:kms"
    }
    bucket_key_enabled = true
  }
}

# Optional: Random ID to ensure bucket name uniqueness
resource "random_id" "suffix" {
  byte_length = 4
}

# Output the Bucket Name and KMS Key ARN
output "bucket_name" {
  value       = aws_s3_bucket.secure_bucket.id
  description = "The name of the S3 bucket"
}

output "kms_key_arn" {
  value       = aws_kms_key.s3_key.arn
  description = "The ARN of the KMS key used for encryption"
}

