# Terraform configuration for an S3 Bucket with CORS rules

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the S3 Bucket
resource "aws_s3_bucket" "example_bucket" {
  bucket = "terraform-ai-cors-example-bucket-unique-id"

  tags = {
    Name        = "CORS Example Bucket"
    Environment = "Dev"
  }
}

# 2. Define the Bucket CORS Configuration
# This resource attaches the CORS rules to the bucket created above
resource "aws_s3_bucket_cors_configuration" "example" {
  bucket = aws_s3_bucket.example_bucket.id

  cors_rule {
    # Allowed headers that the browser is allowed to include in the request
    allowed_headers = ["*"]

    # HTTP methods that are allowed (Required)
    allowed_methods = ["GET", "PUT", "POST", "DELETE"]

    # Origins that are allowed to make the request (Required)
    allowed_origins = ["https://www.example.com", "http://localhost:3000"]

    # Headers in the response that the browser is allowed to access
    expose_headers  = ["ETag", "Content-Type"]

    # The time in seconds that the browser caches the preflight response
    max_age_seconds = 3600
  }
}

# Output the bucket domain name for reference
output "bucket_domain_name" {
  value       = aws_s3_bucket.example_bucket.bucket_domain_name
  description = "The domain name of the created S3 bucket."
}

