To create an S3 bucket configured for static website hosting, we need to define the bucket, manage its public access settings (as AWS blocks public access by default), and then apply a bucket policy that allows public read access to the objects. Finally, we attach the website configuration resource.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "website_bucket" {
  bucket = "my-terraform-static-website-example-12345" # Ensure this is globally unique

  tags = {
    Name        = "Website Bucket"
    Environment = "Dev"
  }
}

# 2. Configure Bucket Ownership Controls (Required for public access settings)
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.website_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Disable "Block Public Access" settings to allow the website to be public
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.website_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Define the Static Website Configuration
resource "aws_s3_bucket_website_configuration" "website_config" {
  bucket = aws_s3_bucket.website_bucket.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# 5. Apply a Bucket Policy to allow public read access to objects
resource "aws_s3_bucket_policy" "allow_public_access" {
  bucket = aws_s3_bucket.website_bucket.id

  # Ensure the public access block is removed before applying the policy
  depends_on = [aws_s3_bucket_public_access_block.example]

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_bucket.arn}/*"
      },
    ]
  })
}

# Output the website endpoint URL
output "website_url" {
  description = "The endpoint for the S3 static website"
  value       = aws_s3_bucket_website_configuration.website_config.website_endpoint
}
```

