response:
To create a static website hosted on AWS S3, we need to define the bucket, configure it for website hosting, disable the default public access blocks, and set a bucket policy to allow public read access to the objects.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "static_website" {
  bucket = "my-tf-static-website-bucket-${random_id.suffix.hex}"

  tags = {
    Name        = "Static Website Bucket"
    Environment = "Dev"
  }
}

# Generate a random suffix for a unique bucket name
resource "random_id" "suffix" {
  byte_length = 4
}

# 2. Configure S3 Bucket Ownership Controls
# This is required to manage public access permissions in modern AWS accounts
resource "aws_s3_bucket_ownership_controls" "website_ownership" {
  bucket = aws_s3_bucket.static_website.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Disable Public Access Block
# By default, S3 blocks all public access. We must disable this for a public website.
resource "aws_s3_bucket_public_access_block" "website_access" {
  bucket = aws_s3_bucket.static_website.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Configure Static Website Settings
resource "aws_s3_bucket_website_configuration" "website_config" {
  bucket = aws_s3_bucket.static_website.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# 5. Set Bucket Policy for Public Read Access
# This allows anyone on the internet to view the website content
resource "aws_s3_bucket_policy" "public_read_access" {
  bucket = aws_s3_bucket.static_website.id

  # Ensure public access block is disabled before applying policy
  depends_on = [aws_s3_bucket_public_access_block.website_access]

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.static_website.arn}/*"
      },
    ]
  })
}

# 6. Upload index.html (Optional helper)
resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.static_website.id
  key          = "index.html"
  content      = "<html><body><h1>Welcome to my Terraform-managed website!</h1></body></html>"
  content_type = "text/html"
}

# Output the website endpoint URL
output "website_url" {
  description = "The URL of the static website"
  value       = aws_s3_bucket_website_configuration.website_config.website_endpoint
}
```

