response:
To create a setup where one S3 bucket (the source) stores its server access logs in another S3 bucket (the destination), we need to define both buckets and configure the logging parameters. 

According to AWS best practices and recent security changes, we must also ensure the destination bucket has the correct ownership controls and ACLs to allow the S3 Log Delivery group to write logs to it.

Here is the complete Terraform configuration:

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Destination Bucket for Access Logs
resource "aws_s3_bucket" "log_bucket" {
  bucket        = "my-app-server-access-logs-dest"
  force_destroy = true
}

# 2. Set Ownership Controls for the Log Bucket
# This is required to allow the use of ACLs for log delivery
resource "aws_s3_bucket_ownership_controls" "log_bucket_ownership" {
  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Grant the Log Delivery group write access to the Log Bucket via ACL
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket_ownership]

  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# 4. Create the Source S3 Bucket
resource "aws_s3_bucket" "source_bucket" {
  bucket        = "my-app-main-data-storage"
  force_destroy = true
}

# 5. Configure Logging on the Source Bucket
# This links the source bucket to the log bucket and specifies a prefix
resource "aws_s3_bucket_logging" "source_bucket_logging" {
  bucket = aws_s3_bucket.source_bucket.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "log/"
}

# Outputs for verification
output "source_bucket_name" {
  value = aws_s3_bucket.source_bucket.id
}

output "log_bucket_name" {
  value = aws_s3_bucket.log_bucket.id
}
```

