# Terraform Configuration for a CS Autograder using AWS CodeBuild

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# --- Variables ---
variable "aws_region" {
  default = "us-east-1"
}

variable "github_repository_url" {
  description = "The URL of the GitHub repository containing the students' code or the grading template."
  type        = string
}

variable "github_token" {
  description = "GitHub Personal Access Token for AWS CodeBuild to access the repository."
  type        = string
  sensitive   = true
}

# --- S3 Bucket for Results ---
resource "aws_s3_bucket" "autograder_results" {
  bucket        = "cs-autograder-results-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# --- IAM Role for CodeBuild ---
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# --- GitHub Source Credential ---
resource "aws_codebuild_source_credential" "github_creds" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# --- CodeBuild Project ---
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for student assignments"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0" # Standard image with Python, Java, Node, etc.
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1

    # Inline Buildspec: This defines what the autograder actually does
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo Installing test dependencies...
            - pip install pytest
        pre_build:
          commands:
            - echo Preparing environment...
        build:
          commands:
            - echo Running Student Tests...
            - pytest --json-report --json-report-file=results.json || true
        post_build:
          commands:
            - echo Uploading results for $CODEBUILD_RESOLVED_SOURCE_VERSION
            - aws s3 cp results.json s3://$RESULT_BUCKET/results-$CODEBUILD_RESOLVED_SOURCE_VERSION.json
      EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-log-group"
      stream_name = "autograder-log-stream"
    }
  }
}

# --- Webhook for Automatic Grading ---
resource "aws_codebuild_webhook" "autograder_webhook" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
    }
  }
}

# --- Outputs ---
output "s3_bucket_name" {
  value = aws_s3_bucket.autograder_results.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "webhook_url" {
  value = aws_codebuild_webhook.autograder_webhook.payload_url
}

