# Terraform Configuration for a CS Autograder Infrastructure

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# --- Variables ---
variable "aws_region" {
  default = "us-east-1"
}

variable "project_name" {
  default = "cs-autograder"
}

variable "github_repo_url" {
  description = "The URL of the student repository or the template repository"
  type        = string
}

# --- S3 Bucket for Grading Results ---
resource "aws_s3_bucket" "autograder_results" {
  bucket        = "${var.project_name}-results-${data.aws_caller_identity.current.account_id}"
  force_destroy = true
}

resource "aws_s3_bucket_public_access_block" "results_privacy" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# --- IAM Role for CodeBuild ---
resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect   = "Allow"
        Action   = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# --- CloudWatch Logs ---
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/${var.project_name}"
  retention_in_days = 14
}

# --- CodeBuild Project ---
resource "aws_codebuild_project" "autograder" {
  name          = var.project_name
  description   = "Autograder for CS class assignments"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.autograder_results.bucket
    packaging = "ZIP"
    name      = "grading-results.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0" # Standard Linux image with Python/Java/Node/Go
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1

    # The buildspec defines the grading commands. 
    # This can be stored in the repo as 'buildspec.yml' or defined inline here.
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo Installing test dependencies...
            - pip install pytest
        pre_build:
          commands:
            - echo Preparing environment for student code...
        build:
          commands:
            - echo Running Autograder...
            - pytest tests/student_tests.py --junitxml=results.xml
        post_build:
          commands:
            - echo Grading complete.
      artifacts:
        files:
          - results.xml
          - '**/test-reports/*'
    EOF
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      stream_name = "autograder-stream"
    }
  }
}

# --- Outputs ---
data "aws_caller_identity" "current" {}

output "results_bucket_name" {
  value = aws_s3_bucket.autograder_results.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

