        }
      }
    ]
  })
}

# IAM Policy for S3 access and Logging
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  name = "autograder-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# 3. CodeBuild Project (The Autograder Engine)
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-project"
  description   = "Autograder for CS class assignments"
  build_timeout = "5" # Minutes
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.autograder_results.bucket
    packaging = "NONE"
    name      = "grading-output"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0" # Standard Linux image with Python, Java, etc.
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # Environment variables for grading scripts
    environment_variable {
      name  = "GRADING_MODE"
      value = "strict"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo.git" # Replace with your repo template
    git_clone_depth = 1

    # The buildspec defines the grading commands. 
    # Usually, this is in the repo, but we can define it inline too.
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
        pre_build:
          commands:
            - echo "Preparing environment..."
        build:
          commands:
            - echo "Running student tests..."
            - python3 -m pytest tests/ > results.txt
        post_build:
          commands:
            - echo "Grading completed on `date`"
      artifacts:
        files:
          - results.txt
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-log-group"
      stream_name = "autograder-stream"
    }
  }

  tags = {
    Environment = "Education"
    Project     = "Autograder"
  }
}

# 4. Optional: GitHub Webhook to trigger autograder on push
# Note: Requires AWS CodeBuild GitHub credentials to be configured in the account
resource "aws_codebuild_webhook" "github_trigger" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
  }
}

output "s3_bucket_name" {
  value       = aws_s3_bucket.autograder_results.id
  description = "The name of the S3 bucket where grading results are stored."
}

output "codebuild_project_name" {
  value       = aws_codebuild_project.autograder.name
  description = "The name of the CodeBuild autograder project."
}

