To create the requested infrastructure, we will define an AWS S3 bucket for artifact storage, an IAM role and policy to allow CodeBuild to access S3 and CloudWatch, and the AWS CodeBuild project with the specific environment and source configurations provided.

Let's think through the steps:
1. **S3 Bucket**: We create a bucket to store the build outputs.
2. **IAM Role**: CodeBuild requires a service role to perform actions like writing logs and uploading artifacts to S3.
3. **CodeBuild Project**: We configure the `artifacts` block to point to the S3 bucket, set the `environment` block with the specified container and compute type, and define the `source` block for GitHub integration.

```hcl
# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Random suffix for unique bucket naming
resource "random_id" "suffix" {
  byte_length = 4
}

# 1. AWS S3 bucket to store code build output
resource "aws_s3_bucket" "build_output" {
  bucket        = "student-build-artifacts-${random_id.suffix.hex}"
  force_destroy = true
}

# 2. IAM Role for CodeBuild service
resource "aws_iam_role" "codebuild_role" {
  name = "student-codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for CodeBuild to access S3 and CloudWatch Logs
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.build_output.arn,
          "${aws_s3_bucket.build_output.arn}/*"
        ]
      }
    ]
  })
}

# 4. AWS CodeBuild project resource
resource "aws_codebuild_project" "student_project" {
  name          = "student-code-build-project"
  description   = "CodeBuild project for student code builds"
  service_role  = aws_iam_role.codebuild_role.arn

  # Artifacts configuration
  artifacts {
    type     = "S3"
    location = aws_s3_bucket.build_output.bucket
  }

  # Environment configuration
  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "alpine"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
  }

  # Source configuration
  source {
    type            = "GITHUB"
    location        = "https://github.com/source-location"
    git_clone_depth = 1
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }
}
