# --- Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking (VPC) ---
# We create a VPC with no route to the internet to ensure total isolation.
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "autograder-vpc" }
}

resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = { Name = "autograder-private-subnet" }
}

# --- VPC Endpoints ---
# Since there is no internet, CodeBuild needs endpoints to reach S3 and CloudWatch.
resource "aws_vpc_endpoint" "s3_gateway" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  route_table_ids = [aws_vpc.autograder_vpc.main_route_table_id]
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.codebuild_sg.id]
  private_dns_enabled = true
}

# --- Security Groups ---
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Allow no outbound internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow internal communication for VPC Endpoints (HTTPS)
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  # Egress is restricted. CodeBuild only needs to talk to VPC endpoints.
  # We do NOT add a 0.0.0.0/0 rule here to ensure student code cannot call out.
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }
}

# --- S3 Storage ---
resource "aws_s3_bucket" "results" {
  bucket_prefix = "cs-autograder-results-"
  force_destroy = true
}

# --- IAM Roles ---
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "codebuild.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.results.arn,
          "${aws_s3_bucket.results.arn}/*"
        ]
      },
      {
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# --- CodeBuild Project ---
resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Securely grades student submissions"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # Environment variables can be used to pass submission IDs
    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo-placeholder.git"
    git_clone_depth = 1
    # Note: CodeBuild pulls the source code using the service network 
    # BEFORE the VPC restriction is applied to the build container.
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      status      = "ENABLED"
    }
  }

  tags = {
    Environment = "Education"
  }
}

# --- Outputs ---
output "result_bucket_name" {
  value = aws_s3_bucket.results.id
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

