response:
To fulfill your request, I will generate a Terraform configuration that includes an S3 bucket for build artifacts, a VPC with the specified CIDR blocks, a restricted Security Group, and a CodeBuild project configured with the environment and source details you provided. 

I have also included the necessary IAM roles and policies that AWS CodeBuild requires to interact with S3 and manage Network Interfaces within your VPC.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. AWS S3 bucket to store code build output
resource "aws_s3_bucket" "build_artifacts" {
  bucket = "student-codebuild-output-bucket-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

# 2. AWS VPC with cidr_block "10.0.0.0/16"
resource "aws_vpc" "main_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "codebuild-vpc"
  }
}

# 3. VPC subnet with cidr_block "10.0.0.0/24"
resource "aws_subnet" "main_subnet" {
  vpc_id     = aws_vpc.main_vpc.id
  cidr_block = "10.0.0.0/24"

  tags = {
    Name = "codebuild-subnet"
  }
}

# 4. AWS Security Group with no ingress and no egress to block internet access
resource "aws_security_group" "restricted_sg" {
  name        = "block-all-traffic-sg"
  description = "Security group with no ingress or egress rules"
  vpc_id      = aws_vpc.main_vpc.id

  # In Terraform, omitting ingress and egress blocks results in no rules, 
  # which effectively blocks all traffic.
}

# 5. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_service_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy to allow CodeBuild to write to S3 and manage VPC ENIs
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_service_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.build_artifacts.arn,
          "${aws_s3_bucket.build_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# 6. AWS CodeBuild project resource
resource "aws_codebuild_project" "student_build" {
  name          = "student-code-build-project"
  description   = "Build project for student code storage"
  service_role  = aws_iam_role.codebuild_service_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.build_artifacts.id
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "alpine"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/source-location"
    git_clone_depth = 1
  }

  vpc_config {
    vpc_id             = aws_vpc.main_vpc.id
    subnets            = [aws_subnet.main_subnet.id]
    security_group_ids = [aws_security_group.restricted_sg.id]
  }

  tags = {
    Environment = "Education"
  }
}
