        ]
      },
      {
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# 3. Lambda Functions (Python)
# --- Upload Logic ---
data "archive_file" "upload_zip" {
  type        = "zip"
  output_path = "upload.zip"
  source {
    content  = <<-EOF
import json
import boto3
import base64
import uuid
import os

s3 = boto3.client('s3')
BUCKET = os.environ['BUCKET_NAME']

def handler(event, context):
    try:
        file_content = base64.b64decode(event['body'])
        file_name = f"{uuid.uuid4()}.jpg"
        s3.put_object(Bucket=BUCKET, Key=file_name, Body=file_content, ContentType='image/jpeg')
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Cat uploaded!', 'file': file_name})
        }
    except Exception as e:
        return {'statusCode': 500, 'body': str(e)}
EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "upload_lambda" {
  filename         = data.archive_file.upload_zip.output_path
  function_name    = "cat-upload-service"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.upload_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_storage.id
    }
  }
}

# --- Randomizer Logic ---
data "archive_file" "random_zip" {
  type        = "zip"
  output_path = "random.zip"
  source {
    content  = <<-EOF
import json
import boto3
import random
import os

s3 = boto3.client('s3')
BUCKET = os.environ['BUCKET_NAME']

def handler(event, context):
    try:
        objects = s3.list_objects_v2(Bucket=BUCKET)
        if 'Contents' not in objects:
            return {'statusCode': 404, 'body': 'No cats found!'}

        random_cat = random.choice(objects['Contents'])['Key']
        url = s3.generate_presigned_url('get_object', Params={'Bucket': BUCKET, 'Key': random_cat}, ExpiresIn=3600)

        return {
            'statusCode': 200,
            'headers': { 'Content-Type': 'application/json' },
            'body': json.dumps({'url': url})
        }
    except Exception as e:
        return {'statusCode': 500, 'body': str(e)}
EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "random_lambda" {
  filename         = data.archive_file.random_zip.output_path
  function_name    = "cat-randomizer-service"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.random_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_storage.id
    }
  }
}

