  bucket = aws_s3_bucket.cat_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. IAM Role for Lambda Functions
resource "aws_iam_role" "lambda_exec_role" {
  name = "cat_service_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "lambda_s3_policy" {
  name = "cat_service_s3_policy"
  role = aws_iam_role.lambda_exec_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetObject", "s3:ListBucket"]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.cat_storage.arn,
          "${aws_s3_bucket.cat_storage.arn}/*"
        ]
      },
      {
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# 3. Lambda Functions (Python)
# --- Upload Logic ---
data "archive_file" "upload_zip" {
  type        = "zip"
  output_path = "upload.zip"
  source {
    content  = <<-EOF
import json
import boto3
import base64
import uuid
import os

s3 = boto3.client('s3')
BUCKET = os.environ['BUCKET_NAME']

def handler(event, context):
    try:
        file_content = base64.b64decode(event['body'])
        file_name = f"{uuid.uuid4()}.jpg"
        s3.put_object(Bucket=BUCKET, Key=file_name, Body=file_content, ContentType='image/jpeg')
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Cat uploaded!', 'file': file_name})
        }
    except Exception as e:
        return {'statusCode': 500, 'body': str(e)}
EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "upload_lambda" {
  filename         = data.archive_file.upload_zip.output_path
  function_name    = "cat-upload-service"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.upload_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_storage.id
    }
  }
}

# --- Randomizer Logic ---
data "archive_file" "random_zip" {
  type        = "zip"
  output_path = "random.zip"
  source {
    content  = <<-EOF
import json
import boto3
import random
import os

s3 = boto3.client('s3')
BUCKET = os.environ['BUCKET_NAME']

def handler(event, context):
    try:
        objects = s3.list_objects_v2(Bucket=BUCKET)
        if 'Contents' not in objects:
            return {'statusCode': 404, 'body': 'No cats found!'}

        random_cat = random.choice(objects['Contents'])['Key']
        url = s3.generate_presigned_url('get_object', Params={'Bucket': BUCKET, 'Key': random_cat}, ExpiresIn=3600)

        return {
            'statusCode': 200,
            'headers': { 'Content-Type': 'application/json' },
            'body': json.dumps({'url': url})
        }
    except Exception as e:
        return {'statusCode': 500, 'body': str(e)}
EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "random_lambda" {
  filename         = data.archive_file.random_zip.output_path
  function_name    = "cat-randomizer-service"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.random_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_storage.id
    }
  }
}

# 4. API Gateway Configuration
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPictureAPI"
  description = "API to upload and fetch random cat pictures"
}

# --- Upload Endpoint ---
resource "aws_api_gateway_resource" "upload_res" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_res.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.upload_res.id
  http_method             = aws_api_gateway_method.upload_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.upload_lambda.invoke_arn
}

# --- Random Endpoint ---
resource "aws_api_gateway_resource" "random_res" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

resource "aws_api_gateway_method" "random_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_res.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.random_res.id
  http_method             = aws_api_gateway_method.random_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.random_lambda.invoke_arn
}

# 5. Lambda Permissions for API Gateway
resource "aws_lambda_permission" "apigw_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

resource "aws_lambda_permission" "apigw_random" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.random_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# 6. Deployment and Stage
resource "aws_api_gateway_deployment" "cat_api_deploy" {
  depends_on = [
    aws_api_gateway_integration.upload_integration,
    aws_api_gateway_integration.random_integration
  ]
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
}

resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api_deploy.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# Outputs
output "api_endpoint" {
  value = "${aws_api_gateway_stage.prod.invoke_url}"
  description = "The URL of the Cat API"
}

output "upload_url" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/upload"
}

output "random_url" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/random"
}
