extracted_code:
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for AWS Backup to the role
resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 2. Get the latest Amazon Linux 2 AMI for EC2
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 3. Create the EC2 Instance
resource "aws_instance" "app_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  tags = {
    Name        = "ProductionServer"
    BackupPolicy = "DailyMidnight" # This tag links it to the Backup Plan
  }
}

# 4. Create an AWS Backup Vault
resource "aws_backup_vault" "ec2_backup_vault" {
  name = "ec2_midnight_backup_vault"
}

# 5. Create the AWS Backup Plan
resource "aws_backup_plan" "daily_midnight_plan" {
  name = "daily_midnight_backup_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_name = aws_backup_vault.ec2_backup_vault.name

    # Schedule: Every day at 00:00 UTC
    # Format: cron(Minutes Hours Day-of-month Month Day-of-week Year)
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# 6. Assign the EC2 Instance to the Backup Plan using Tags
resource "aws_backup_selection" "ec2_backup_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_midnight_selection"
  plan_id      = aws_backup_plan.daily_midnight_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupPolicy"
    value = "DailyMidnight"
  }
}

# Output the Instance ID and Vault Name
output "instance_id" {
  value = aws_instance.app_server.id
}

output "backup_vault_name" {
  value = aws_backup_vault.ec2_backup_vault.name
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_instance" "cloud_desktop" {
  instance_type = "t2.micro"
  ami = data.aws_ami.amzn2.id
}

resource "aws_backup_plan" "cloud_desktop_backup" {
  name = "cloud_desktop_backup_plan"
  rule {
    rule_name         = "cloud_desktop_backup_rule" # required, not specified
    target_vault_name = aws_backup_vault.valut.name # required, not specified
    schedule          = "cron(0 0 * * ? *)"
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

resource "aws_backup_vault" "valut" {
  name = "cloud_desktop_backup_valut"
}

resource "aws_backup_selection" "backup_ec2" {
  iam_role_arn = aws_iam_role.backup.arn

  name    = "backup_ec2"
  plan_id = aws_backup_plan.cloud_desktop_backup.id

  resources = [
    aws_instance.cloud_desktop.arn,
  ]
}

data "aws_iam_policy_document" "backup_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "backup" {
  name               = "backup"
  assume_role_policy = data.aws_iam_policy_document.backup_assume_role.json
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

response:
To accomplish this request, we need to set up several components:
1.  **IAM Role**: A service role that allows AWS Backup to perform backup and restore operations.
2.  **EC2 Instance**: The target instance to be backed up.
3.  **AWS Backup Vault**: A container to store the recovery points (backups).
4.  **AWS Backup Plan**: The definition of the schedule (daily at midnight) and the retention policy.
5.  **AWS Backup Selection**: The logic that assigns the EC2 instance to the backup plan (using tags).

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for AWS Backup to the role
resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 2. Get the latest Amazon Linux 2 AMI for EC2
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 3. Create the EC2 Instance
resource "aws_instance" "app_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  tags = {
    Name        = "ProductionServer"
    BackupPolicy = "DailyMidnight" # This tag links it to the Backup Plan
  }
}

# 4. Create an AWS Backup Vault
resource "aws_backup_vault" "ec2_backup_vault" {
  name = "ec2_midnight_backup_vault"
}

# 5. Create the AWS Backup Plan
resource "aws_backup_plan" "daily_midnight_plan" {
  name = "daily_midnight_backup_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_name = aws_backup_vault.ec2_backup_vault.name

    # Schedule: Every day at 00:00 UTC
    # Format: cron(Minutes Hours Day-of-month Month Day-of-week Year)
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# 6. Assign the EC2 Instance to the Backup Plan using Tags
resource "aws_backup_selection" "ec2_backup_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_midnight_selection"
  plan_id      = aws_backup_plan.daily_midnight_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupPolicy"
    value = "DailyMidnight"
  }
}

# Output the Instance ID and Vault Name
output "instance_id" {
  value = aws_instance.app_server.id
}

output "backup_vault_name" {
  value = aws_backup_vault.ec2_backup_vault.name
}
```

