}

# 2. Data source to get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2023" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-*-x86_64"]
  }
}

# 3. AWS EC2 Instance
resource "aws_instance" "target_server" {
  ami           = data.aws_ami.amazon_linux_2023.id
  instance_type = "t3.micro"
  key_name      = aws_key_pair.web_key.key_name

  tags = {
    Name        = "BackupEnabledServer"
    BackupPolicy = "Daily"
  }
}

# 4. AWS Backup Vault
resource "aws_backup_vault" "daily_backup_vault" {
  name        = "ec2-daily-vault"
  kms_key_arn = null # Uses default AWS Backup encryption key if not specified
}

# 5. AWS Backup Plan
