# Terraform configuration for AWS EC2 and AWS Backup

# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. AWS EC2 Key Pair using the local public key file
resource "aws_key_pair" "deployer" {
  key_name   = "deployer-key"
  public_key = file("./key.pub")
}

# 2. Data source to find the latest Amazon Linux 2023 AMI for x86_64
data "aws_ami" "amazon_linux_2023" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-2023*-x86_64"]
  }
}

# 3. AWS EC2 Instance
resource "aws_instance" "web_server" {
  ami           = data.aws_ami.amazon_linux_2023.id
  instance_type = "t2.micro"
  key_name      = aws_key_pair.deployer.key_name

  tags = {
    Name = "BackupTargetInstance"
  }
}

# 4. AWS Backup Vault
resource "aws_backup_vault" "main_vault" {
  name = "ec2_backup_vault"
}

# 5. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_selection_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      },
    ]
  })
}

# 6. Attach the AWSBackupServiceRolePolicyForBackup policy to the role
resource "aws_iam_role_policy_attachment" "backup_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 7. AWS Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily_ec2_backup_plan"

  rule {
    rule_name         = "midnight_daily_rule"
    target_vault_name = aws_backup_vault.main_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at midnight

    lifecycle {
      delete_after = 7 # Delete after 7 days
    }
  }

  # Advanced backup setting for EC2 as requested
  advanced_backup_setting {
    resource_type = "EC2"
    backup_options = {
      WindowsVSS = "disabled"
    }
  }
}

# 8. AWS Backup Selection
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2_backup_selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  # Link the specific EC2 instance for backup
  resources = [
    aws_instance.web_server.arn
  ]
}

