      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# Attach basic execution policy to the role (allows logging to CloudWatch)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Package the Lambda Function Code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"
  source {
    content  = "exports.handler = async (event) => { console.log('Task executed at 7 UTC'); return { status: 'success' }; };"
    filename = "index.js"
  }
}

# 3. Create the Lambda Function
resource "aws_lambda_function" "scheduled_code" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "daily_7am_utc_task"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "nodejs18.x"
}

# 4. EventBridge Rule (Scheduled to run at 7:00 UTC daily)
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-seven-am-utc-rule"
  description         = "Trigger Lambda function every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 5. EventBridge Target (Pointing the rule to the Lambda)
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "TriggerDailyLambda"
  arn       = aws_lambda_function.scheduled_code.arn
