  memory_size = 128
}

# 4. EventBridge Rule for Schedule (7:00 AM UTC daily)
resource "aws_cloudwatch_event_rule" "every_day_7am" {
  name                = "run-every-day-at-7am-utc"
  description         = "Triggers at 7:00 AM UTC every day"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 5. EventBridge Target - Link Rule to Lambda
