  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "python3.9"
}

# 5. Create the EventBridge Rule (Scheduled at 7:00 UTC Daily)
resource "aws_cloudwatch_event_rule" "daily_rule" {
  name                = "run-lambda-at-7-utc"
  description         = "Triggers Lambda function every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 6. Set the Lambda Function as the Target for the Rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_rule.name
  target_id = "SendToLambda"
  arn       = aws_lambda_function.scheduled_lambda.arn
}

# 7. Add Permission for EventBridge to Invoke the Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_rule.arn
}
