response:
To create an AWS infrastructure that triggers a Lambda function daily at 7 UTC using EventBridge, we follow these steps:

1.  **IAM Role**: Define an IAM role that allows the Lambda function to execute.
2.  **Lambda Function**: Create the function with the specified name, handler, runtime, and local zip file path.
3.  **EventBridge Rule**: Configure a rule named "cron" with the specific cron expression for 7:00 UTC every day.
4.  **EventBridge Target**: Link the rule to the Lambda function.
5.  **Lambda Permission**: Grant EventBridge the necessary permissions to invoke the specific Lambda function.

```hcl
provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "cron-lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# AWS Lambda Function resource
resource "aws_lambda_function" "cron" {
  function_name = "cron-lambda-function"
  filename      = "./supplement/lambda_func.zip"
  handler       = "lambda_func.lambda_handler"
  runtime       = "python3.12"
  role          = aws_iam_role.lambda_exec.arn
}

# AWS EventBridge event rule resource
resource "aws_cloudwatch_event_rule" "cron" {
  name                = "cron"
  description         = "Trigger everyday at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# AWS EventBridge event target linking rule to lambda
resource "aws_cloudwatch_event_target" "cron_target" {
  rule      = aws_cloudwatch_event_rule.cron.name
  target_id = "TriggerCronLambda"
  arn       = aws_lambda_function.cron.arn
}

# AWS Lambda permission to allow EventBridge invocation
resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cron.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.cron.arn
}
```

extracted_code:
# Terraform Configuration for Global Video Streaming Infrastructure

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create S3 Bucket for Video Content
resource "aws_s3_bucket" "video_assets" {
  bucket        = "global-video-streaming-assets-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# 2. Block all public access to the S3 bucket
resource "aws_s3_bucket_public_access_block" "video_assets_block" {
  bucket = aws_s3_bucket.video_assets.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 3. Create CloudFront Origin Access Control (OAC)
# This allows CloudFront to securely communicate with the private S3 bucket
resource "aws_cloudfront_origin_access_control" "default" {
  name                              = "s3-video-oac"
  description                       = "OAC for Video Streaming S3 Bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 4. Create CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_assets.bucket_regional_domain_name
    origin_id                = "S3-Video-Origin"
    origin_access_control_id = aws_cloudfront_origin_access_control.default.id
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"

  # Optimize for global delivery
  price_class = "PriceClass_All"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-Video-Origin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Environment = "Production"
    Service     = "VideoStreaming"
  }
}

# 5. S3 Bucket Policy to allow CloudFront OAC access
resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.video_assets.id
  policy = data.aws_iam_policy_document.s3_policy.json
}

data "aws_iam_policy_document" "s3_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.video_assets.arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.video_distribution.arn]
    }
  }
}

# Outputs
output "s3_bucket_name" {
  value       = aws_s3_bucket.video_assets.id
  description = "The name of the S3 bucket to upload videos to."
}

output "cloudfront_domain_name" {
  value       = aws_cloudfront_distribution.video_distribution.domain_name
  description = "The domain name of the CloudFront distribution for accessing videos."
}

