response:
To create a global video streaming infrastructure, we will use **Amazon S3** as the origin server to store the video files and **Amazon CloudFront** as the Content Delivery Network (CDN) to cache and serve content from edge locations worldwide. 

We will use **Origin Access Control (OAC)**, which is the current AWS best practice for securing S3 origins, ensuring that users can only access the videos via the CloudFront URL and not directly via S3.

```hcl
# Terraform Configuration for Global Video Streaming Infrastructure

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create S3 Bucket for Video Content
resource "aws_s3_bucket" "video_assets" {
  bucket        = "global-video-streaming-assets-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# 2. Block all public access to the S3 bucket
resource "aws_s3_bucket_public_access_block" "video_assets_block" {
  bucket = aws_s3_bucket.video_assets.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 3. Create CloudFront Origin Access Control (OAC)
# This allows CloudFront to securely communicate with the private S3 bucket
resource "aws_cloudfront_origin_access_control" "default" {
  name                              = "s3-video-oac"
  description                       = "OAC for Video Streaming S3 Bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 4. Create CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_assets.bucket_regional_domain_name
    origin_id                = "S3-Video-Origin"
    origin_access_control_id = aws_cloudfront_origin_access_control.default.id
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"

  # Optimize for global delivery
  price_class = "PriceClass_All"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-Video-Origin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Environment = "Production"
    Service     = "VideoStreaming"
  }
}

# 5. S3 Bucket Policy to allow CloudFront OAC access
resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.video_assets.id
  policy = data.aws_iam_policy_document.s3_policy.json
}

data "aws_iam_policy_document" "s3_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.video_assets.arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.video_distribution.arn]
    }
  }
}

# Outputs
output "s3_bucket_name" {
  value       = aws_s3_bucket.video_assets.id
  description = "The name of the S3 bucket to upload videos to."
}

output "cloudfront_domain_name" {
  value       = aws_cloudfront_distribution.video_distribution.domain_name
  description = "The domain name of the CloudFront distribution for accessing videos."
}
```

