}

variable "aws_region" {
  default = "us-east-1"
}

variable "domain_name" {
  description = "The domain name for the streaming site (e.g., video.example.com)"
  type        = string
}

variable "route53_zone_id" {
  description = "The ID of the Route53 hosted zone"
  type        = string
}

# 1. S3 Bucket for Video Content
resource "aws_s3_bucket" "video_assets" {
  bucket = "video-streaming-assets-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

# Block all public access to S3
resource "aws_s3_bucket_public_access_block" "video_assets_block" {
