response:
To build a globally distributed video streaming infrastructure, we will use **Amazon S3** for origin storage, **CloudFront** for global content delivery with **Origin Access Control (OAC)** for security, and **Route 53** for DNS management. 

Here is the complete Terraform configuration:

```hcl
# Terraform Configuration for a Global Video Streaming Site

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Primary provider for resources
provider "aws" {
  region = var.aws_region
}

# CloudFront certificates must be in us-east-1
provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"
}

variable "aws_region" {
  default     = "us-west-2"
  description = "The region to deploy the S3 bucket"
}

variable "domain_name" {
  description = "The domain name for the streaming site (e.g., video.example.com)"
  type        = string
}

# 1. S3 Bucket for Video Content
resource "aws_s3_bucket" "video_origin" {
  bucket = "video-streaming-origin-${var.domain_name}"
}

# Block all public access to S3 (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "video_origin_block" {
  bucket = aws_s3_bucket.video_origin.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "video_oac" {
  name                              = "video-streaming-oac"
  description                       = "OAC for streaming site origin"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 3. Route53 Zone
resource "aws_route53_zone" "main" {
  name = var.domain_name
}

# 4. ACM Certificate for HTTPS
resource "aws_acm_certificate" "cert" {
  provider          = aws.us_east_1
  domain_name       = var.domain_name
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

# DNS Validation Record for ACM
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = aws_route53_zone.main.zone_id
}

resource "aws_acm_certificate_validation" "cert" {
  provider                = aws.us_east_1
  certificate_arn         = aws_acm_certificate.cert.arn
  validation_record_fqdns = [for record in aws_route53_record.cert_validation : record.fqdn]
}

# 5. CloudFront Distribution
resource "aws_cloudfront_distribution" "video_dist" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Video Streaming Distribution"
  default_root_object = "index.html"
  aliases             = [var.domain_name]

  origin {
    domain_name              = aws_s3_bucket.video_origin.bucket_regional_domain_name
    origin_id                = "S3VideoOrigin"
    origin_access_control_id = aws_cloudfront_origin_access_control.video_oac.id
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3VideoOrigin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  # Optimized for streaming
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate_validation.cert.certificate_arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }
}

# 6. S3 Bucket Policy to allow CloudFront Access
resource "aws_s3_bucket_policy" "allow_cloudfront" {
  bucket = aws_s3_bucket.video_origin.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "s3:GetObject"
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.video_origin.arn}/*"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_dist.arn
          }
        }
      }
    ]
  })
}

# 7. Route53 Record pointing to CloudFront
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = var.domain_name
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_dist.domain_name
    zone_id                = aws_cloudfront_distribution.video_dist.hosted_zone_id
    evaluate_target_health = false
  }
}

# Output the DNS Name
output "cloudfront_url" {
  value = aws_cloudfront_distribution.video_dist.domain_name
}
```

