response:
To build a scalable video streaming infrastructure on AWS, we need a high-availability network, an Application Load Balancer (ALB) to distribute incoming traffic, and an Auto Scaling Group (ASG) to manage a fleet of EC2 instances. This configuration ensures that as viewer demand increases, the infrastructure scales horizontally.

Here is the complete Terraform configuration:

```hcl
# --- Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
# Create a VPC for the streaming site
resource "aws_vpc" "streaming_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = { Name = "streaming-vpc" }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.streaming_vpc.id
}

# Fetch Availability Zones
data "aws_availability_zones" "available" {}

# Create Public Subnets (for ALB and EC2)
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.streaming_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
  tags = { Name = "streaming-public-${count.index}" }
}

# Route Table for Internet Access
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.streaming_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public_assoc" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# --- Security Groups ---
# ALB Security Group (Allows HTTP)
resource "aws_security_group" "alb_sg" {
  name        = "streaming-alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Instance Security Group (Allows traffic only from ALB)
resource "aws_security_group" "web_sg" {
  name        = "streaming-web-sg"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Load Balancer ---
resource "aws_lb" "streaming_alb" {
  name               = "streaming-site-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id
}

resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming_vpc.id

  health_check {
    path                = "/"
    healthy_threshold   = 2
    unhealthy_threshold = 10
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# --- Compute (Auto Scaling Group) ---
# Launch Template for Web Servers
resource "aws_launch_template" "streaming_lt" {
  name_prefix   = "streaming-server-"
  image_id      = "ami-0440d3b780d96b29d" # Amazon Linux 2023 AMI (Region Specific)
  instance_type = "t3.micro"

  network_interfaces {
    associate_public_ip_address = true
    security_groups             = [aws_security_group.web_sg.id]
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server: $(hostname -f)</h1>" > /var/www/html/index.html
              EOF
  )

  lifecycle {
    create_before_destroy = true
  }
}

# Auto Scaling Group
resource "aws_autoscaling_group" "streaming_asg" {
  desired_capacity    = 2
  max_size            = 5
  min_size            = 2
  target_group_arns   = [aws_lb_target_group.streaming_tg.arn]
  vpc_zone_identifier = aws_subnet.public[*].id

  launch_template {
    id      = aws_launch_template.streaming_lt.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "streaming-web-server"
    propagate_at_launch = true
  }
}

# --- Outputs ---
output "alb_dns_name" {
  value       = aws_lb.streaming_alb.dns_name
  description = "The DNS name of the load balancer to access the streaming site."
}
```

extracted_code:
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC Module to create the network foundation
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.0.0"

  name = "streaming-site-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24", "10.0.103.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  tags = {
    Environment = "production"
    Application = "video-streaming"
  }
}

# 2. Security Groups
resource "aws_security_group" "alb_sg" {
  name        = "streaming-alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "ec2_sg" {
  name        = "streaming-ec2-sg"
  description = "Allow traffic from ALB"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Application Load Balancer
resource "aws_lb" "streaming_lb" {
  name               = "streaming-site-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets
}

resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# 4. EC2 Launch Template and Auto Scaling Group
resource "aws_launch_template" "streaming_lt" {
  name_prefix   = "streaming-server-"
  image_id      = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 AMI (Region specific)
  instance_type = "t3.medium" # Suitable for mid-range streaming tasks

  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.ec2_sg.id]
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server: $(hostname -f)</h1>" > /var/www/html/index.html
              EOF
  )
}

resource "aws_autoscaling_group" "streaming_asg" {
  desired_capacity    = 3
  max_size            = 6
  min_size            = 2
  vpc_zone_identifier = module.vpc.private_subnets
  target_group_arns   = [aws_lb_target_group.streaming_tg.arn]

  launch_template {
    id      = aws_launch_template.streaming_lt.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "streaming-worker"
    propagate_at_launch = true
  }
}

# 5. Route53 DNS Configuration
resource "aws_route53_zone" "primary" {
  name = "example-streaming-site.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example-streaming-site.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_lb.dns_name
    zone_id                = aws_lb.streaming_lb.zone_id
    evaluate_target_health = true
  }
}

# Outputs
output "load_balancer_dns" {
  value = aws_lb.streaming_lb.dns_name
}

output "route53_nameservers" {
  value = aws_route53_zone.primary.name_servers
}

