  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_instance" "database" {
  identifier             = "dolphinscheduler"
  db_name                = "dolphinscheduler"
  instance_class         = "db.t3.micro"
  allocated_storage      = 5
  engine                 = "postgres"
  engine_version         = "17.1"
  skip_final_snapshot    = true
  db_subnet_group_name   = aws_db_subnet_group.db-subnet-group.id
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.db-sg.id]
  username               = "myusername"
  password               = "mypassword"
}

response:
To set up this infrastructure on AWS, we will follow these steps:

1.  **Networking Layer**: Create a VPC and two public subnets across different Availability Zones (required for the RDS Subnet Group).
2.  **Internet Connectivity**: Deploy an Internet Gateway and a Route Table to ensure the subnets are reachable from the internet.
3.  **Security Groups**: 
    *   Create a Client Security Group (as a placeholder for your application or management IP).
    *   Create a Database Security Group that specifically allows inbound traffic on port 5432 (PostgreSQL) only from the Client Security Group.
4.  **Database Subnet Group**: Group the subnets to define where the RDS instance can be hosted.
5.  **RDS Instance**: Provision a managed PostgreSQL instance using the defined security group and subnet group.

