To set up the requested infrastructure on AWS, we will define a VPC with two public subnets (required for an RDS DB Subnet Group), an Internet Gateway, and a Route Table to ensure connectivity. We will then configure a Security Group that allows inbound traffic on port 5432 (PostgreSQL). Finally, we will provision the PostgreSQL 17.1 instance with the specified storage and identifier.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dolphinscheduler-vpc"
  }
}

# 2. Create Internet Gateway for Public Access
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "dolphinscheduler-igw"
  }
}

# 3. Create Public Subnets (RDS requires at least two subnets in different AZs)
resource "aws_subnet" "public_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-1"
  }
}

resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-2"
  }
}

# 4. Route Table for Public Subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "dolphinscheduler-public-rt"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public_rt.id
}

# 5. DB Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "dolphinscheduler-db-subnet-group"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Name = "dolphinscheduler-db-subnet-group"
  }
}

# 6. Security Group for Database Access
resource "aws_security_group" "db_sg" {
  name        = "dolphinscheduler-db-sg"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to specific IP ranges
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dolphinscheduler-db-sg"
  }
}

# 7. PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  identifier           = "dolphinscheduler"
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro"
  allocated_storage    = 5 # User requested 5GB
  storage_type         = "gp3"

  db_name              = "dolphinscheduler"
