extracted_code:
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Variables ---
variable "vpc_id" {
  description = "The ID of the VPC where the RDS instance will be deployed"
  type        = string
}

variable "private_subnet_ids" {
  description = "A list of private subnet IDs for the RDS subnet group"
  type        = list(string)
}

variable "db_password" {
  description = "The password for the master database user"
  type        = string
  sensitive   = true
}

# --- KMS Key for Encryption at Rest ---
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_key_alias" {
  name          = "alias/rds/postgresql"
  target_key_id = aws_kms_key.rds_key.key_id
}

# --- Security Group ---
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgresql-sg"
  description = "Allow inbound traffic to PostgreSQL"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL Access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Restrict this to your specific application CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgresql-sg"
  }
}

# --- DB Subnet Group ---
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "main-rds-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# --- DB Parameter Group ---
resource "aws_db_parameter_group" "rds_pg" {
  name   = "rds-postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "1" # Force SSL for security
  }
}

# --- RDS PostgreSQL Instance ---
resource "aws_db_instance" "postgresql" {
  identifier           = "secure-postgresql-instance"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.medium"
  allocated_storage    = 20
  max_allocated_storage = 100 # Enables storage autoscaling
  storage_type         = "gp3"

  db_name              = "myappdb"
  username             = "dbadmin"
  password             = var.db_password
  port                 = 5432

  # Security & High Availability
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  parameter_group_name   = aws_db_parameter_group.rds_pg.name
  publicly_accessible    = false

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_key.arn

  # Backup & Maintenance
  backup_retention_period  = 7
  backup_window            = "03:00-04:00"
  maintenance_window       = "Mon:04:00-Mon:05:00"
  delete_automated_backups = true
  skip_final_snapshot      = true # Set to false for production environments
  deletion_protection      = false # Set to true for production environments

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# --- Outputs ---
output "rds_endpoint" {
  value       = aws_db_instance.postgresql.endpoint
  description = "The connection endpoint for the RDS instance"
}

output "rds_kms_key_arn" {
  value = aws_kms_key.rds_key.arn
}

