}

provider "aws" {
  region = var.aws_region
}

# Variables for customization
variable "aws_region" {
  description = "AWS region"
  default     = "us-east-1"
}

variable "vpc_id" {
  description = "The ID of the VPC where the RDS instance will be deployed"
  type        = string
}

variable "private_subnet_ids" {
  description = "A list of private subnet IDs for the RDS subnet group"
  type        = list(string)
}

variable "db_name" {
  description = "The name of the initial database"
  default     = "myappdb"
}

variable "db_username" {
  description = "Master username for the database"
  default     = "dbadmin"
}

variable "db_password" {
  description = "Master password for the database (should be handled via secrets manager in production)"
  type        = string
  sensitive   = true
}

# KMS Key for RDS Encryption at Rest
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_key_alias" {
  name          = "alias/rds/postgres"
  target_key_id = aws_kms_key.rds_key.key_id
}

# DB Subnet Group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# DB Parameter Group for custom PostgreSQL settings
resource "aws_db_parameter_group" "postgres_params" {
  name   = "postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  tags = {
    Name = "PostgreSQL Custom Parameter Group"
  }
}

# Security Group to manage access to the RDS instance
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Adjust to your VPC CIDR or specific application SG
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-security-group"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier = "secure-postgres-instance"

  # Engine specifications
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp3"

  # Database credentials
  db_name  = var.db_name
  username = var.db_username
  password = var.db_password

  # Network and Security
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  parameter_group_name   = aws_db_parameter_group.postgres_params.name
  publicly_accessible    = false

  # High Availability and Backups
  multi_az                = true
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "Mon:04:00-Mon:05:00"

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_key.arn

  # Deletion protection and maintenance
  deletion_protection      = false # Set to true for production
  skip_final_snapshot      = true  # Set to false for production
  copy_tags_to_snapshot    = true
  delete_automated_backups = true

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the RDS Endpoint
output "rds_endpoint" {
  value       = aws_db_instance.postgres.endpoint
  description = "The connection endpoint for the RDS instance"
}

