# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

# Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

# Create two private subnets in different AZs for Multi-AZ support
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-private-b"
  }
}

# DB Subnet Group required for RDS
resource "aws_db_subnet_group" "postgresql" {
  name       = "pg-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# --- Security & Encryption ---

# KMS Key for storage encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS storage encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-encryption-key"
  }
}

# Security Group for the Database
resource "aws_security_group" "rds_sg" {
  name        = "postgresql-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restrict to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# --- Database Configuration ---

# Custom Parameter Group
resource "aws_db_parameter_group" "pg_custom" {
  name   = "custom-pg15-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "client_encoding"
    value = "utf8"
  }
}

# PostgreSQL RDS Instance
resource "aws_db_instance" "postgresql" {
  identifier = "secure-postgresql-instance"

  # Engine Specifications
  engine            = "postgres"
  engine_version    = "15.3"
  instance_class    = "db.t3.medium"
  allocated_storage = 20
  storage_type      = "gp3"

  # High Availability & Connectivity
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.postgresql.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_key.arn

  # Database Credentials (Should ideally be managed via Variables or Secret Manager)
  db_name  = "myappdb"
  username = "dbadmin"
  password = "ReplaceWithASecurePassword123!" # Placeholder

  # Settings & Maintenance
  parameter_group_name = aws_db_parameter_group.pg_custom.name

  # Snapshot Configuration
  skip_final_snapshot       = false
  final_snapshot_identifier = "pgsnapshot"

  # Protection
  deletion_protection = false # Set to true for production

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the endpoint for connection
output "db_instance_endpoint" {
  value       = aws_db_instance.postgresql.endpoint
  description = "The connection endpoint for the PostgreSQL instance"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  final_snapshot_identifier       = "pgsnapshot"
  allocated_storage               = 5
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
To provision a secure, high-availability PostgreSQL instance on AWS with the specified requirements, we need to configure the networking (VPC, Subnets), security (KMS, Security Groups), and the RDS instance itself.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

# Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

# Create two private subnets in different AZs for Multi-AZ support
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-private-b"
  }
}

# DB Subnet Group required for RDS
resource "aws_db_subnet_group" "postgresql" {
  name       = "pg-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# --- Security & Encryption ---

# KMS Key for storage encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS storage encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-encryption-key"
  }
}

# Security Group for the Database
resource "aws_security_group" "rds_sg" {
  name        = "postgresql-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restrict to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# --- Database Configuration ---

# Custom Parameter Group
resource "aws_db_parameter_group" "pg_custom" {
  name   = "custom-pg15-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "client_encoding"
    value = "utf8"
  }
}

# PostgreSQL RDS Instance
resource "aws_db_instance" "postgresql" {
  identifier = "secure-postgresql-instance"

  # Engine Specifications
  engine            = "postgres"
  engine_version    = "15.3"
  instance_class    = "db.t3.medium"
  allocated_storage = 20
  storage_type      = "gp3"

  # High Availability & Connectivity
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.postgresql.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_key.arn

  # Database Credentials (Should ideally be managed via Variables or Secret Manager)
  db_name  = "myappdb"
  username = "dbadmin"
  password = "ReplaceWithASecurePassword123!" # Placeholder

  # Settings & Maintenance
  parameter_group_name = aws_db_parameter_group.pg_custom.name

  # Snapshot Configuration
  skip_final_snapshot       = false
  final_snapshot_identifier = "pgsnapshot"

  # Protection
  deletion_protection = false # Set to true for production

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the endpoint for connection
output "db_instance_endpoint" {
  value       = aws_db_instance.postgresql.endpoint
  description = "The connection endpoint for the PostgreSQL instance"
}
