To set up a PostgreSQL 15 instance on AWS RDS within public subnets for Airbyte testing, we need to configure several components: a VPC with Internet Gateway support, a DB Subnet Group pointing to public subnets, a Security Group allowing PostgreSQL traffic (port 5432), and the RDS instance itself with the specific flags for immediate application and low maintenance.

Here is the complete Terraform configuration:

```hcl
# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# 1. Network Infrastructure (VPC, Subnets, IGW)
resource "aws_vpc" "airbyte_test_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.airbyte_test_vpc.id
}

resource "aws_subnet" "public_a" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "public_b" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_test_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_b.id
  route_table_id = aws_route_table.public_rt.id
}

# 2. RDS Subnet Group
resource "aws_db_subnet_group" "airbyte_db_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = [aws_subnet.public_a.id, aws_subnet.public_b.id]

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

# 3. Security Group (Allows PostgreSQL traffic)
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg"
  description = "Allow inbound traffic for Airbyte tests"
  vpc_id      = aws_vpc.airbyte_test_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Caution: Open to world for testing. Restrict to specific IPs in production.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. PostgreSQL 15 RDS Instance
resource "aws_db_instance" "airbyte_pg" {
  identifier           = "airbyte-connector-test-db"
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t3.micro" # Cost-effective for testing
  allocated_storage    = 20
  storage_type         = "gp3"
  db_name              = "airbyte_test"
  username             = "airbyte_user"
  password             = "ReplaceWithSecurePassword123!" # Use a secret manager in production

  # Network & Accessibility
  db_subnet_group_name   = aws_db_subnet_group.airbyte_db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true

  # Maintenance & Management
  apply_immediately           = true
  skip_final_snapshot         = true
  auto_minor_version_upgrade  = true
  allow_major_version_upgrade = false
  backup_retention_period     = 1 # Low retention for test environments

  # Monitoring
  performance_insights_enabled = false

  tags = {
    Environment = "Testing"
    Project     = "AirbyteConnector"
  }
}

# Outputs
output "rds_endpoint" {
  value = aws_db_instance.airbyte_pg.endpoint
}

output "rds_port" {
  value = aws_db_instance.airbyte_pg.port
}
```

