extracted_code:
# Terraform Configuration for AWS RDS MySQL with Public Access

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the RDS instance
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Create a Security Group to allow public access to MySQL
resource "aws_security_group" "rds_public_sg" {
  name        = "rds_mysql_public_sg"
  description = "Allow inbound traffic to MySQL from the internet"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Open to the world
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-mysql-public-sg"
  }
}

# Create the RDS MySQL Instance
resource "aws_db_instance" "mysql_instance" {
  identifier           = "terraform-mysql-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  db_name              = "mydatabase"
  username             = "admin"
  password             = random_password.db_password.result
  parameter_group_name = "default.mysql8.0"

  # Enabling public access
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.rds_public_sg.id]

  # Recommended for development/testing to avoid deletion hurdles
  skip_final_snapshot = true

  tags = {
    Name = "TerraformMySQLInstance"
  }
}

# Outputs
output "db_endpoint" {
  description = "The connection endpoint for the RDS instance"
  value       = aws_db_instance.mysql_instance.endpoint
}

output "db_password" {
  description = "The randomly generated password for the DB (sensitive)"
  value       = random_password.db_password.result
  sensitive   = true
}

