  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "postgresql-vpc"
  }
}

# 2. Subnets (RDS requires at least two subnets in different Availability Zones)
resource "aws_subnet" "db_subnet_a" {
  vpc_id            = aws_vpc.db_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "db-subnet-a"
  }
}

resource "aws_subnet" "db_subnet_b" {
  vpc_id            = aws_vpc.db_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "db-subnet-b"
  }
}

# 3. DB Subnet Group
resource "aws_db_subnet_group" "pg_subnet_group" {
  name       = "pg-subnet-group"
  subnet_ids = [aws_subnet.db_subnet_a.id, aws_subnet.db_subnet_b.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# 4. Security Group for Database access
resource "aws_security_group" "db_sg" {
  name        = "allow_postgresql"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. PostgreSQL RDS Instance
resource "aws_db_instance" "postgresql_instance" {
  identifier           = "terraform-postgresql-db"
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  db_name              = "mydb"
  username             = "dbadmin"
  password             = "SecurePassword123!" # In production, use a secret manager

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.pg_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = false

  # Backup Configuration
  backup_retention_period = 5
  backup_window           = "03:00-06:00" # UTC Time
  maintenance_window      = "Mon:00:00-Mon:03:00"

  # Final Snapshot & Deletion protection
  skip_final_snapshot     = true # Set to false for production
  deletion_protection     = false

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Output the endpoint for connection
output "db_endpoint" {
