response:
To create an AWS Lightsail instance with automatic snapshots enabled, we need to define the `aws_lightsail_instance` resource and include an `add_on` block. Within the `add_on` block, we set the type to `AutoSnapshot`, specify a snapshot time (in UTC), and set the status to `Enabled`.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a Lightsail Instance with Auto Snapshots enabled
resource "aws_lightsail_instance" "lightsail_with_snapshots" {
  name              = "web-server-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2" # Amazon Linux 2 blueprint
  bundle_id         = "nano_2_0"       # The smallest bundle ($3.50 USD/mo)

  # Configure Automatic Snapshots
  add_on {
    type          = "AutoSnapshot"
    snapshot_time = "03:00" # Snapshot time in UTC (format: HH:00)
    status        = "Enabled"
  }

  tags = {
    Name        = "Production-Web-Server"
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the Public IP of the Lightsail instance
output "lightsail_public_ip" {
  value       = aws_lightsail_instance.lightsail_with_snapshots.public_ip_address
  description = "The public IP address of the Lightsail instance."
}
