response:
To create an Amazon Lightsail instance with a separate, custom SSH key pair using Terraform, we follow these steps:
1.  **Provider Configuration**: Define the AWS provider and the target region.
2.  **SSH Key Generation**: Use the `tls` provider to generate a private/public key pair programmatically, or you can provide an existing public key string. In this example, we generate one for a complete self-contained solution.
3.  **Lightsail Key Pair**: Register the public key with the Lightsail service using the `aws_lightsail_key_pair` resource.
4.  **Lightsail Instance**: Create the instance and explicitly link it to the custom key pair using the `key_pair_name` argument.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Generate a new TLS Private Key
resource "tls_private_key" "lightsail_ssh_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create a custom Lightsail Key Pair using the generated public key
resource "aws_lightsail_key_pair" "custom_key" {
  name       = "lightsail-custom-key"
  public_key = tls_private_key.lightsail_ssh_key.public_key_openssh
}

# Create the Amazon Lightsail Instance
resource "aws_lightsail_instance" "example_instance" {
  name              = "terraform-lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2" # Amazon Linux 2
  bundle_id         = "nano_2_0"       # The smallest instance plan ($3.50 USD/mo)

  # Associate the custom SSH key pair created above
  key_pair_name     = aws_lightsail_key_pair.custom_key.name

  tags = {
    Environment = "Dev"
    Project     = "TerraformAI"
  }
}

# Output the private key (sensitive) to use for SSH
output "private_key_pem" {
  value     = tls_private_key.lightsail_ssh_key.private_key_pem
  sensitive = true
}

# Output the Public IP of the instance
output "instance_public_ip" {
  value = aws_lightsail_instance.example_instance.public_ip_address
}
```

