  region = "us-east-1"
}

# Generate a secure random password for the database master user
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_%@!"
}

# Create the Lightsail Managed Relational Database
resource "aws_lightsail_database" "managed_db" {
  relational_database_name = "my-lightsail-db"
  availability_zone       = "us-east-1a"

  # Blueprint IDs define engine and version: mysql_8_0, postgres_15, etc.
  blueprint_id            = "mysql_8_0"

  # Bundle IDs define the hardware tier: micro_1_0, small_1_0, medium_1_0, etc.
  bundle_id               = "micro_1_0"

  master_database_name    = "application_db"
  master_username         = "db_admin"
  master_password         = random_password.db_password.result

  # Configuration settings
  preferred_backup_window      = "03:00-04:00"
  preferred_maintenance_window = "mon:05:00-mon:06:00"
  publicly_accessible          = false
  apply_immediately            = true
