To create a Lightsail Disk and attach it to a Lightsail Instance, we need to follow these steps:
1.  **Define the Provider**: Set up the AWS provider and specify the region.
2.  **Create the Lightsail Instance**: Provision a virtual private server. We must specify an `availability_zone`, `blueprint_id` (OS), and `bundle_id` (instance size).
3.  **Create the Lightsail Disk**: Provision a block storage disk. Crucially, this must be in the same `availability_zone` as the instance.
4.  **Attach the Disk**: Use the attachment resource to link the disk to the instance using the disk path.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a Lightsail Instance
resource "aws_lightsail_instance" "main_instance" {
  name              = "web-server-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2" # Amazon Linux 2
  bundle_id         = "nano_2_0"       # Cheapest tier
}

# 2. Create a Lightsail Disk
# Note: The disk must be in the same Availability Zone as the instance
resource "aws_lightsail_disk" "additional_storage" {
  name              = "data-disk-01"
  availability_zone = "us-east-1a"
  size_in_gb        = 20
}

# 3. Attach the Disk to the Instance
resource "aws_lightsail_disk_attachment" "main_attachment" {
  disk_name     = aws_lightsail_disk.additional_storage.name
  instance_name = aws_lightsail_instance.main_instance.name
  disk_path     = "/dev/xvdf"
}

# Output the disk name and instance name for confirmation
output "instance_name" {
  value = aws_lightsail_instance.main_instance.name
}

output "disk_name" {
  value = aws_lightsail_disk.additional_storage.name
}
```

