resource "aws_lightsail_distribution" "cdn" {
  name       = "web-distribution"
  bundle_id  = "Small_1_0" # Distribution plan (e.g., 50 GB transfer)
  is_enabled = true

  # Set the Lightsail Instance as the Origin
  origin {
    name          = "primary-origin"
    region_name   = "us-east-1"
    resource_name = aws_lightsail_instance.web_server.name
    protocol_policy = "http-only" # Depends on instance configuration
  }

  # Default Cache Behavior configuration
  default_cache_behavior {
    behavior = "cache" # Options: cache, dont-cache
  }

  # Advanced Cache Settings
  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_headers {
      option = "none"
    }

    forwarded_cookies {
      option = "none"
    }

    forwarded_query_strings {
      option = "false"
    }
  }

