# Terraform configuration for an AWS S3 Glacier Vault

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Fetch current AWS account ID for policy references
data "aws_caller_identity" "current" {}

# 1. Create the S3 Glacier Vault
resource "aws_glacier_vault" "archive_vault" {
  name = "long-term-data-archive-vault"

  # 2. Access Policy
  # This policy allows the account owner full access to the vault.
  # In a production environment, restrict 'Principal' to specific IAM roles.
  access_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowFullAccessToAccountOwner"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action    = "glacier:*"
        Resource  = "arn:aws:glacier:us-east-1:${data.aws_caller_identity.current.account_id}:vaults/long-term-data-archive-vault"
      }
    ]
  })

  # 3. Tags for Resource Management
  tags = {
    Environment = "Production"
    Purpose     = "LongTermStorage"
    ManagedBy   = "Terraform"
  }
}

# 4. Optional: Vault Lock for Compliance
# A Vault Lock allows you to enforce compliance controls, such as WORM.
# Note: Once 'complete_lock' is set to true and confirmed, the policy cannot be changed.
/*
resource "aws_glacier_vault_lock" "archive_lock" {
  complete_lock = false # Set to true only after verifying the policy works as expected
  policy        = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "DenyDeleteIfArchiveAgeLessThanOneYear"
        Effect    = "Deny"
        Principal = "*"
        Action    = "glacier:DeleteArchive"
        Resource  = aws_glacier_vault.archive_vault.arn
        Condition = {
          NumericLessThan = {
            "glacier:ArchiveAgeInDays" = "365"
          }
        }
      }
    ]
  })
  vault_name = aws_glacier_vault.archive_vault.name
}
*/

# Outputs
output "glacier_vault_arn" {
  description = "The ARN of the Glacier Vault"
  value       = aws_glacier_vault.archive_vault.arn
}

output "glacier_vault_uri" {
  description = "The URI of the Glacier Vault"
  value       = aws_glacier_vault.archive_vault.location
}

reference:
provider "aws" {
  region = "us-east-1"  # Replace with your desired AWS region
}

resource "aws_glacier_vault" "example" {
  name = "my-glacier-vault"
}

