To generate an AWS Glacier Vault with a notification service, we need to create three main components: an SNS Topic to receive the alerts, an SNS Topic Policy to allow the Glacier service to publish messages to that topic, and the Glacier Vault itself with the notification configuration.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic for Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications-topic"
}

# 2. Create an IAM Policy Document to allow Glacier to publish to the SNS Topic
data "aws_iam_policy_document" "sns_glacier_policy" {
  statement {
    sid       = "AllowGlacierToPublish"
    actions   = ["sns:Publish"]
    resources = [aws_sns_topic.glacier_notifications.arn]

    principals {
      type        = "Service"
      identifiers = ["glacier.amazonaws.com"]
    }

    # Optional: Restrict to a specific vault for better security
    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = ["arn:aws:glacier:us-east-1:*:vaults/my-archive-vault"]
    }
  }
}

# 3. Apply the policy to the SNS Topic
resource "aws_sns_topic_policy" "default" {
  arn    = aws_sns_topic.glacier_notifications.arn
  policy = data.aws_iam_policy_document.sns_glacier_policy.json
}

# 4. Create the Glacier Vault with notification settings
resource "aws_glacier_vault" "my_vault" {
  name = "my-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Environment = "Production"
    Service     = "Glacier"
  }

  # Ensure the SNS policy is in place before the vault tries to send notifications
  depends_on = [aws_sns_topic_policy.default]
}

# Outputs
output "glacier_vault_arn" {
  value       = aws_glacier_vault.my_vault.arn
  description = "The ARN of the Glacier Vault"
}

output "sns_topic_arn" {
  value       = aws_sns_topic.glacier_notifications.arn
  description = "The ARN of the SNS Topic"
}
```

