To create an AWS S3 Glacier Vault with SNS notification integration, we need to define the SNS topic, set up a policy that allows the Glacier service to publish to that topic, and finally define the Glacier Vault itself with the notification configuration.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic for Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications-topic"
}

# 2. Define an SNS Topic Policy to allow Amazon Glacier to publish messages to the topic
# This is required so Glacier has permission to send alerts to your SNS topic
resource "aws_sns_topic_policy" "glacier_sns_policy" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowGlacierToPublish"
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

# Data source to get the current AWS Account ID for the policy condition
data "aws_caller_identity" "current" {}

# 3. Create the Glacier Vault
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-company-archive-vault"

  # Integration with SNS
  notification {
    events   = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
    sns_topic = aws_sns_topic.glacier_notifications.arn
  }

  tags = {
    Environment = "Production"
    Service     = "Glacier"
  }

  # Ensure the policy is attached before the vault tries to verify the SNS topic
  depends_on = [aws_sns_topic_policy.glacier_sns_policy]
}

# Outputs for reference
output "glacier_vault_arn" {
  value       = aws_glacier_vault.my_archive_vault.arn
  description = "The ARN of the Glacier Vault"
}

output "sns_topic_arn" {
  value       = aws_sns_topic.glacier_notifications.arn
  description = "The ARN of the SNS Topic"
}
```

