}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Glacier Vault
resource "aws_glacier_vault" "my_vault" {
  name = "corporate-compliance-vault"

  tags = {
    Environment = "Production"
    Purpose     = "WORM-Compliance"
  }
}

# 2. Define the Vault Lock Policy
# This policy denies the 'glacier:DeleteArchive' action if the archive is less than 365 days old
data "aws_iam_policy_document" "lock_policy" {
  statement {
    sid    = "DenyDeleteUntilOneYearOld"
    effect = "Deny"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions = [
      "glacier:DeleteArchive",
    ]

    resources = [
      aws_glacier_vault.my_vault.arn,
    ]

    condition {
      test     = "NumericLessThan"
      variable = "glacier:ArchiveAgeInDays"
      values   = ["365"]
    }
  }
}

# 3. Apply the Vault Lock
# complete_lock = true will initiate the lock process.
# Note: Once the lock is completed (usually after a 24-hour window), 
# it cannot be changed or deleted via the API.
resource "aws_glacier_vault_lock" "my_vault_lock" {
  complete_lock = true
  policy        = data.aws_iam_policy_document.lock_policy.json
  vault_name    = aws_glacier_vault.my_vault.name
}

# Output the Vault ARN for reference
output "glacier_vault_arn" {
  value       = aws_glacier_vault.my_vault.arn
  description = "The ARN of the locked Glacier Vault"
}

