To generate this infrastructure, I will define a VPC and two public subnets across different availability zones to meet the high-availability requirements for an AWS Application Load Balancer. I will then configure a security group to allow standard web traffic and deploy the Application Load Balancer with the requested name, public access setting, and deletion protection enabled.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Data source to fetch availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "test-vpc"
  }
}

# Two subnets in different AZs (required for ALB)
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]
  tags = {
    Name = "test-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]
  tags = {
    Name = "test-subnet-2"
  }
}

# Security Group for the ALB
resource "aws_security_group" "lb_sg" {
  name        = "test-lb-sg"
  description = "Allow HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Application Load Balancer
resource "aws_lb" "test_lb" {
  name               = "test-lb-tf"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  enable_deletion_protection = true

  tags = {
    Environment = "test"
  }
}
