# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "internal-lb-vpc"
  }
}

# 2. Create Subnets in different Availability Zones
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "private-subnet-b"
  }
}

# 3. Create the Internal Network Load Balancer with static private IPs
# Note: subnet_mapping is required to specify the private_ipv4_address
resource "aws_lb" "internal_lb" {
  name               = "internal-static-ip-nlb"
  internal           = true
  load_balancer_type = "network"

  subnet_mapping {
    subnet_id            = aws_subnet.subnet_a.id
    private_ipv4_address = "10.0.1.50" # Static IP for AZ-a
  }

  subnet_mapping {
    subnet_id            = aws_subnet.subnet_b.id
    private_ipv4_address = "10.0.2.50" # Static IP for AZ-b
  }

  tags = {
    Environment = "Production"
  }
}

# 4. Create a Target Group (TCP protocol for NLB)
resource "aws_lb_target_group" "app_tg" {
  name        = "app-target-group"
  port        = 80
  protocol    = "TCP"
  vpc_id      = aws_vpc.main.id
  target_type = "instance"

  health_check {
    protocol            = "TCP"
    interval            = 30
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }
}

# 5. Create a Listener to route traffic to the Target Group
resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.internal_lb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

# Output the DNS name and static IPs for verification
output "lb_dns_name" {
  value = aws_lb.internal_lb.dns_name
}

output "lb_static_ips" {
  value = ["10.0.1.50", "10.0.2.50"]
}

