# Terraform Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Network Infrastructure ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags                 = { Name = "alb-to-nlb-vpc" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags              = { Name = "public-1" }
}

resource "aws_subnet" "public_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags              = { Name = "public-2" }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public.id
}

# --- Security Groups ---

resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow HTTP inbound"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Network Load Balancer (Internal) ---

resource "aws_lb" "internal_nlb" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"

  # Note: To target NLB from ALB, we often use static IPs to simplify IP target registration
  subnet_mapping {
    subnet_id            = aws_subnet.public_1.id
    private_ipv4_address = "10.0.1.100"
  }
  subnet_mapping {
    subnet_id            = aws_subnet.public_2.id
    private_ipv4_address = "10.0.2.100"
  }
}

resource "aws_lb_target_group" "nlb_tg" {
  name     = "nlb-backend-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id
  # This target group would point to your actual backend EC2 instances/containers
}

resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.internal_nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# --- Application Load Balancer (Public) ---

resource "aws_lb" "public_alb" {
  name               = "public-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_1.id, aws_subnet.public_2.id]
}

# Target Group for ALB pointing to NLB IP addresses
resource "aws_lb_target_group" "alb_to_nlb_tg" {
  name        = "alb-to-nlb-tg"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip" # ALB must use IP type to target NLB

  health_check {
    protocol = "HTTP"
    path     = "/"
    port     = "80"
  }
}

# Registering the NLB Private IPs as targets for the ALB
resource "aws_lb_target_group_attachment" "nlb_ip_1" {
  target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  target_id        = "10.0.1.100" # IP from NLB Subnet Mapping 1
  port             = 80
}

resource "aws_lb_target_group_attachment" "nlb_ip_2" {
  target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  target_id        = "10.0.2.100" # IP from NLB Subnet Mapping 2
  port             = 80
}

resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.public_alb.arn
