response:
To create a Load Balancer with a redirect action, we will use AWS as the provider. The most common use case is redirecting insecure HTTP traffic (port 80) to secure HTTPS traffic (port 443).

### Logical Steps:
1.  **Provider Configuration**: Initialize the AWS provider.
2.  **Network Infrastructure**: Create a VPC and at least two public subnets in different Availability Zones, as an Application Load Balancer (ALB) requires high availability.
3.  **Security Group**: Define a security group that allows inbound traffic on port 80.
4.  **Application Load Balancer**: Provision the ALB resource.
5.  **Listener with Redirect Action**: Create an ALB Listener on port 80. Instead of forwarding to a target group, we configure the `default_action` with a `type` of `redirect`, specifying the target port (443), protocol (HTTPS), and the redirect status code (typically `HTTP_301`).

```hcl
# --- Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Network Resources ---
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "redirect-demo-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# --- Security Group ---
resource "aws_security_group" "lb_sg" {
  name        = "allow_http"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Application Load Balancer ---
resource "aws_lb" "main_lb" {
  name               = "redirect-example-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Environment = "production"
  }
}

# --- Listener with Redirect Action ---
# This listener captures HTTP (80) traffic and redirects it to HTTPS (443)
resource "aws_lb_listener" "http_to_https_redirect" {
  load_balancer_arn = aws_lb.main_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "redirect"

    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301" # Permanent redirect
    }
  }
}

# --- Output the DNS Name ---
output "lb_dns_name" {
  value       = aws_lb.main_lb.dns_name
  description = "The DNS name of the load balancer"
}
```

