response:
To create an Application Load Balancer (ALB) with a Target Group and link them together, we need to follow these steps:
1. **Network Infrastructure**: Define a VPC and at least two subnets in different Availability Zones (a requirement for AWS ALBs).
2. **Security Groups**: Create a security group to allow inbound traffic on port 80 (HTTP).
3. **Target Group**: Define the target group where traffic will be routed (e.g., to EC2 instances or IP addresses).
4. **Load Balancer**: Create the ALB resource itself.
5. **Listener**: Create an LB Listener that "attaches" the Load Balancer to the Target Group by defining rules for incoming traffic.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "terraform-example-vpc"
  }
}

# 2. Create two Subnets in different Availability Zones (ALB requirement)
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = { Name = "tf-subnet-a" }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = { Name = "tf-subnet-b" }
}

# 3. Create a Security Group for the Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "allow_http_lb"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Create the Target Group
resource "aws_lb_target_group" "app_tg" {
  name     = "app-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    enabled             = true
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 3
    unhealthy_threshold = 2
  }
}

# 5. Create the Application Load Balancer
resource "aws_lb" "app_lb" {
  name               = "main-app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# 6. Create the Listener to attach the LB to the Target Group
resource "aws_lb_listener" "http_listener" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

# Output the DNS name of the Load Balancer
output "lb_dns_name" {
  value       = aws_lb.app_lb.dns_name
  description = "The domain name of the load balancer"
}
```

