To create an AWS RDS database restored from an S3 backup, we use the `s3_import` configuration block within the `aws_db_instance` resource. This process is typically used for MySQL or MariaDB engines.

Here is the step-by-step logic included in the configuration:
1.  **IAM Role**: Create an IAM role that allows the RDS service (`rds.amazonaws.com`) to assume it.
2.  **IAM Policy**: Create a policy that grants the role permissions to list and get objects from the specific S3 bucket where your backup is stored.
3.  **DB Instance**: Define the `aws_db_instance` resource, including the `s3_import` block which specifies the bucket name, the IAM role ARN, and the source engine details.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for RDS to access S3
resource "aws_iam_role" "rds_s3_import_role" {
  name = "rds-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# 2. IAM Policy to grant access to the specific S3 bucket
resource "aws_iam_policy" "rds_s3_import_policy" {
  name        = "rds-s3-import-policy"
  description = "Allows RDS to read backup files from S3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::my-db-backup-bucket",
          "arn:aws:s3:::my-db-backup-bucket/*"
        ]
      }
    ]
  })
}

# 3. Attach the policy to the role
resource "aws_iam_role_policy_attachment" "rds_s3_import_attach" {
  role       = aws_iam_role.rds_s3_import_role.name
  policy_arn = aws_iam_policy.rds_s3_import_policy.arn
}

# 4. RDS Instance restored from S3
# Note: s3_import is only used during the initial creation of the DB instance.
resource "aws_db_instance" "restored_db" {
  allocated_storage    = 20
  db_name              = "restored_database"
  engine               = "mysql"
  engine_version       = "8.0.35"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = "Password123!" # In production, use a secret manager
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true

  # Configuration for restoring from S3
  s3_import {
    source_engine         = "mysql"
    source_engine_version = "8.0"
    bucket_name           = "my-db-backup-bucket"
    bucket_prefix         = "backups/mydb-full-backup" # Path to your backup file/folder
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
  }

  tags = {
    Name = "RestoredMySQLInstance"
  }

  # Ensure IAM roles are attached before RDS tries to access S3
  depends_on = [aws_iam_role_policy_attachment.rds_s3_import_attach]
