# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the EFS
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "efs-vpc"
  }
}

# Create a Subnet
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "efs-subnet"
  }
}

# Security Group to allow NFS traffic (Port 2049)
resource "aws_security_group" "efs_sg" {
  name        = "allow_nfs"
  description = "Allow NFS traffic for EFS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "NFS from VPC"
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# AWS EFS File System with Lifecycle Policy
resource "aws_efs_file_system" "this" {
  creation_token = "my-efs-token"
  encrypted      = true
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"

  # Lifecycle Policy: Move to Infrequent Access (IA) after 30 days of inactivity
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  # Lifecycle Policy: Move to Archive storage after 90 days of inactivity
  lifecycle_policy {
    transition_to_archive = "AFTER_90_DAYS"
  }

  # Lifecycle Policy: Move back to Primary storage if accessed
  lifecycle_policy {
    transition_to_primary_storage_class = "AFTER_1_ACCESS"
  }

  tags = {
    Name = "MyWorkloadEFS"
  }
}

# Mount Target (Attaching the EFS to a specific subnet)
resource "aws_efs_mount_target" "this" {
  file_system_id  = aws_efs_file_system.this.id
  subnet_id       = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

# Output the DNS name of the EFS
output "efs_dns_name" {
  value       = aws_efs_file_system.this.dns_name
  description = "The DNS name of the EFS file system"
}

