}

# 1. Create a VPC and Subnet for the EFS Mount Targets
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "efs-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "efs-subnet-a"
  }
}

# 2. Security Group to allow NFS traffic (Port 2049)
resource "aws_security_group" "efs_sg" {
  name        = "allow_nfs"
  description = "Allow NFS traffic for EFS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "NFS from VPC"
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Create the EFS File System
resource "aws_efs_file_system" "main" {
  creation_token = "my-efs-token"
  encrypted      = true

  tags = {
    Name = "MyProductEFS"
  }
}

# 4. Create Mount Targets (one for each subnet/AZ)
resource "aws_efs_mount_target" "alpha" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

# 5. Define the EFS System Policy
# This policy enforces that all clients must use TLS (Encryption in Transit)
data "aws_iam_policy_document" "efs_policy" {
  statement {
    sid    = "EnforceTLS"
    effect = "Deny"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions = ["*"]

    resources = [aws_efs_file_system.main.arn]

    condition {
      test     = "Bool"
      variable = "aws:SecureTransport"
      values   = ["false"]
    }
  }

  statement {
    sid    = "AllowFullAccess"
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions = [
      "elasticfilesystem:ClientMount",
      "elasticfilesystem:ClientWrite",
      "elasticfilesystem:ClientRootAccess"
    ]

    resources = [aws_efs_file_system.main.arn]
  }
}

# 6. Apply the Policy to the EFS File System
resource "aws_efs_file_system_policy" "policy" {
  file_system_id = aws_efs_file_system.main.id
  policy         = data.aws_iam_policy_document.efs_policy.json
}

# Outputs
output "efs_id" {
  value       = aws_efs_file_system.main.id
  description = "The ID of the EFS File System"
}

output "efs_dns_name" {
  value       = aws_efs_file_system.main.dns_name
  description = "The DNS name of the EFS File System"
}

