response:
To create a VPC with multiple public subnets and internet access in AWS, we will follow these steps:
1.  **Define the Provider**: Set up the AWS provider and region.
2.  **VPC Creation**: Define the primary VPC resource with a specified CIDR block.
3.  **Internet Gateway**: Create an Internet Gateway (IGW) and attach it to the VPC to allow communication with the internet.
4.  **Public Subnets**: Create multiple subnets across different Availability Zones (AZs) and enable `map_public_ip_on_launch` to ensure instances receive public IPs.
5.  **Route Table**: Define a route table containing a route that directs all outbound traffic (0.0.0.0/0) to the Internet Gateway.
6.  **Associations**: Link the created subnets to the public route table.

```hcl
# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 3. Create Multiple Public Subnets
# We define a list of CIDR blocks and AZs to iterate through
variable "public_subnet_cidrs" {
  type    = list(string)
  default = ["10.0.1.0/24", "10.0.2.0/24"]
}

variable "azs" {
  type    = list(string)
  default = ["us-east-1a", "us-east-1b"]
}

resource "aws_subnet" "public_subnets" {
  count                   = length(var.public_subnet_cidrs)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.public_subnet_cidrs[count.index]
  availability_zone       = var.azs[count.index]
  map_public_ip_on_launch = true # Makes the subnet "Public"

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# 4. Create a Public Route Table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# 5. Associate Route Table with Public Subnets
resource "aws_route_table_association" "public_assoc" {
  count          = length(var.public_subnet_cidrs)
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Output the VPC ID and Subnet IDs
output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_ids" {
  value = aws_subnet.public_subnets[*].id
}
```

