response:
To create a VPC in AWS with multiple public subnets, an internet gateway, and a properly configured route table, we will follow these steps:

1.  **Define the VPC**: Establish the primary CIDR block.
2.  **Create the Internet Gateway**: Attach it to the VPC to enable communication with the internet.
3.  **Define Public Subnets**: Create a set of subnets. We will use a `count` or `for_each` loop to handle "multiple" subnets efficiently across different Availability Zones.
4.  **Create a Public Route Table**: Define a route that directs all outbound traffic (`0.0.0.0/0`) to the Internet Gateway.
5.  **Associate Subnets**: Link each public subnet to the public route table to ensure they have internet access.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 3. Create Multiple Public Subnets
# Using count to create 3 subnets in different AZs
variable "public_subnet_cidrs" {
  type    = list(string)
  default = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
}

data "aws_availability_zones" "available" {}

resource "aws_subnet" "public_subnets" {
  count                   = length(var.public_subnet_cidrs)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.public_subnet_cidrs[count.index]
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true # Makes the subnet public

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# 4. Create a Public Route Table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
