response:
To create an AWS VPC with multiple public subnets and internet access, we follow these steps:
1. **Define the Provider**: Configure the AWS provider and region.
2. **Create the VPC**: Establish the primary network container.
3. **Internet Gateway (IGW)**: Create and attach an IGW to allow communication between the VPC and the internet.
4. **Public Subnets**: Create multiple subnets across different Availability Zones (AZs) and enable `map_public_ip_on_launch`.
5. **Route Table**: Create a route table with a default route (`0.0.0.0/0`) pointing to the Internet Gateway.
6. **Associations**: Link the subnets to the route table so they inherit the routing logic.

```hcl
# Terraform Configuration for AWS VPC with Multiple Public Subnets

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 3. Fetch available Availability Zones in the current region
data "aws_availability_zones" "available" {
  state = "available"
}

# 4. Create Multiple Public Subnets
resource "aws_subnet" "public" {
  count                   = 3
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true # This makes it a "Public" subnet

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# 5. Create a Route Table for Internet Access
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# 6. Associate Subnets with the Public Route Table
resource "aws_route_table_association" "public_assoc" {
  count          = length(aws_subnet.public)
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Output the VPC ID and Subnet IDs
output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_ids" {
  value = aws_subnet.public[*].id
}
```

