  type        = string
}

variable "eip_allocation_id" {
  description = "The Allocation ID of the Elastic IP address for the NAT Gateway."
  type        = string
}

variable "nat_gateway_name" {
  description = "The name tag for the NAT Gateway."
  type        = string
  default     = "main-nat-gateway"
}

# NAT Gateway Resource
resource "aws_nat_gateway" "this" {
  # The Allocation ID of the Elastic IP address for the gateway.
  allocation_id = var.eip_allocation_id

  # The Subnet ID of the subnet in which to place the gateway.
  subnet_id     = var.subnet_id

  # Connectivity type for the NAT Gateway. Valid values are 'public' and 'private'.
  # Public NAT Gateways require an EIP.
  connectivity_type = "public"

  tags = {
    Name = var.nat_gateway_name
  }

  # To ensure proper cleanup, it is often recommended to add an explicit dependency 
  # on the Internet Gateway if it were being managed in the same module.
}

# Output the NAT Gateway ID
output "nat_gateway_id" {
  description = "The ID of the NAT Gateway."
  value       = aws_nat_gateway.this.id
}

output "nat_gateway_public_ip" {
  description = "The public IP address of the NAT Gateway."
  value       = aws_nat_gateway.this.public_ip
}

